INSERT INTO learning_path_translations (learning_path_id, lang_code, title, description) VALUES
  ('aaa00000-0000-0000-0000-000000000042', 'hi', 'मत्ती का सुसमाचार', 'मत्ती को आरंभ से अंत तक पढ़ें — प्रत्येक अध्याय पर एक अध्ययन। यीशु से इस्राएल के प्रतिज्ञात राजा के रूप में मिलें: उनकी राजसी वंशावली और जन्म, पहाड़ी उपदेश, राज्य के दृष्टांत, उनके चमत्कार और टकराव, और चरम क्रूस, पुनरुत्थान तथा महान आज्ञा। हर अध्याय पढ़ें और मत्ती को आपको वह राजा दिखाने दें जो सम्पूर्ण पवित्रशास्त्र को पूरा करता है।'),
  ('aaa00000-0000-0000-0000-000000000042', 'ml', 'മത്തായിയുടെ സുവിശേഷം', 'മത്തായിയെ ആരംഭം മുതൽ അവസാനം വരെ പഠിക്കുക — ഓരോ അധ്യായത്തിനും ഒരു പഠനം. യേശുവിനെ ഇസ്രായേലിന്റെ വാഗ്ദത്ത രാജാവായി കണ്ടുമുട്ടുക: അവന്റെ രാജകീയ വംശാവലിയും ജനനവും, ഗിരിപ്രഭാഷണം, രാജ്യത്തിന്റെ ഉപമകൾ, അവന്റെ അത്ഭുതങ്ങളും ഏറ്റുമുട്ടലുകളും, ഒടുവിൽ ക്രൂശും പുനരുത്ഥാനവും മഹാനിയോഗവും. ഓരോ അധ്യായവും വായിച്ച്, എല്ലാ തിരുവെഴുത്തുകളെയും നിവർത്തിക്കുന്ന രാജാവിനെ മത്തായി നിങ്ങൾക്കു കാണിച്ചുതരട്ടെ.'),
  ('aaa00000-0000-0000-0000-000000000043', 'hi', 'मरकुस का सुसमाचार', 'मरकुस के साथ पूरी गति से आगे बढ़ें, जो सबसे छोटा और सबसे अधिक घटनापूर्ण सुसमाचार है — प्रत्येक अध्याय पर एक अध्ययन। यीशु को सेवक के रूप में निरंतर कार्य करते देखें: दुष्टात्माओं को निकालते, बीमारों को चंगा करते, तूफानों को शांत करते, और यरूशलेम की ओर बढ़ते हुए। ''पश्चाताप करो और सुसमाचार पर विश्वास करो'' से लेकर खाली कब्र तक, प्रत्येक अध्याय पढ़ें और परमेश्वर के पुत्र से मिलें, जो बहुतों की छुड़ौती के लिए अपना प्राण देने आया।'),
  ('aaa00000-0000-0000-0000-000000000043', 'ml', 'മര്‍ക്കൊസിന്റെ സുവിശേഷം', 'ഏറ്റവും ചെറുതും ഏറ്റവും സംഭവബഹുലവുമായ സുവിശേഷമായ മര്‍ക്കൊസിലൂടെ പൂര്‍ണ്ണവേഗത്തില്‍ മുന്നേറുക — ഓരോ അധ്യായത്തിനും ഒരു പഠനം. ദുരാത്മാക്കളെ പുറത്താക്കിയും രോഗികളെ സൗഖ്യമാക്കിയും കൊടുങ്കാറ്റുകളെ ശാന്തമാക്കിയും യെരൂശലേമിലേക്കു മുന്നേറിയും നിരന്തരം പ്രവര്‍ത്തിക്കുന്ന ദാസനായ യേശുവിനെ കാണുക. ''മാനസാന്തരപ്പെട്ടു സുവിശേഷത്തില്‍ വിശ്വസിക്കുവിന്‍'' എന്നതുമുതല്‍ ഒഴിഞ്ഞ കല്ലറവരെ, ഓരോ അധ്യായവും വായിച്ച്, അനേകര്‍ക്കു മറുവിലയായി തന്റെ ജീവനെ നല്‍കുവാന്‍ വന്ന ദൈവപുത്രനെ കണ്ടുമുട്ടുക.'),
  ('aaa00000-0000-0000-0000-000000000044', 'hi', 'लूका का सुसमाचार', 'करुणा के सुसमाचार लूका से होकर यात्रा करें — प्रत्येक अध्याय पर एक अध्ययन। सुव्यवस्थित और सावधान विवरण तथा मरियम और जकर्याह के गीतों से लेकर उद्धारकर्ता के जन्म, अनुग्रह के दृष्टान्तों, और इम्माऊस की राह तक, लूका यीशु को खोए हुओं को ढूँढ़ते और उद्धार करते हुए दिखाता है। प्रत्येक अध्याय पढ़ें और उस उद्धारकर्ता से मिलें जिसकी दया दीन, परदेशी और पापी तक पहुँचती है।'),
  ('aaa00000-0000-0000-0000-000000000044', 'ml', 'ലൂക്കൊസിന്റെ സുവിശേഷം', 'കരുണയുടെ സുവിശേഷമായ ലൂക്കൊസിലൂടെ സഞ്ചരിക്കുക — ഓരോ അധ്യായത്തിനും ഒരു പഠനം. ശ്രദ്ധാപൂർവവും ക്രമമായതുമായ വിവരണവും മറിയയുടെയും സെഖര്യാവിന്റെയും കീർത്തനങ്ങളും മുതൽ രക്ഷകന്റെ ജനനം, കൃപയുടെ ഉപമകൾ, എമ്മവുസിലേക്കുള്ള വഴി വരെ, യേശു നഷ്ടപ്പെട്ടവരെ അന്വേഷിക്കുകയും രക്ഷിക്കുകയും ചെയ്യുന്നതായി ലൂക്കൊസ് കാണിക്കുന്നു. ഓരോ അധ്യായവും വായിക്കുക, ദരിദ്രരെയും പുറത്തുള്ളവരെയും പാപിയെയും തന്റെ കരുണ കൊണ്ട് എത്തിപ്പിടിക്കുന്ന രക്ഷകനെ കണ്ടുമുട്ടുക.'),
  ('aaa00000-0000-0000-0000-000000000045', 'hi', 'यूहन्ना का सुसमाचार', 'यूहन्ना के सुसमाचार में मसीह की महिमा को निहारें — प्रति अध्याय एक अध्ययन। "वचन देहधारी हुआ" से लेकर सात चिह्नों, "मैं हूँ" के कथनों, ऊपरी कोठरी, क्रूस और पुनरुत्थान तक, यूहन्ना इसलिए लिखता है कि आप विश्वास करें कि यीशु ही मसीह हैं, परमेश्वर के पुत्र, और उनके नाम में जीवन पाएँ। हर अध्याय को पढ़ें और उस अनन्त पुत्र से मिलें जो पिता को प्रकट करता है।'),
  ('aaa00000-0000-0000-0000-000000000045', 'ml', 'യോഹന്നാന്‍റെ സുവിശേഷം', 'യോഹന്നാന്‍റെ സുവിശേഷത്തില്‍ ക്രിസ്തുവിന്‍റെ മഹത്വം ദര്‍ശിക്കുക — ഓരോ അധ്യായത്തിനും ഒരു പഠനം. "വചനം ജഡമായിത്തീര്‍ന്നു" എന്നതുമുതല്‍ ഏഴ് അടയാളങ്ങള്‍, "ഞാന്‍ ആകുന്നു" എന്ന വചനങ്ങള്‍, മാളികമുറി, ക്രൂശ്, പുനരുത്ഥാനം എന്നിവവരെ, യേശു ദൈവപുത്രനായ ക്രിസ്തു ആകുന്നു എന്നു നിങ്ങള്‍ വിശ്വസിക്കേണ്ടതിനും അവന്‍റെ നാമത്തില്‍ ജീവന്‍ പ്രാപിക്കേണ്ടതിനും യോഹന്നാന്‍ എഴുതുന്നു. ഓരോ അധ്യായവും വായിച്ച് പിതാവിനെ വെളിപ്പെടുത്തുന്ന നിത്യപുത്രനെ കണ്ടുമുട്ടുക.')
INSERT INTO recommended_topics_translations (topic_id, language_code, title, description, category) VALUES
  ('d0100000-e29b-41d4-a716-446655440001', 'hi', 'मत्ती 1: राजा की वंशावली और जन्म', 'मत्ती 1 पढ़ें। मत्ती यीशु की वंशावली को अब्राहम से होते हुए दाऊद तक खोजकर आरंभ करता है, और उन्हें प्रतिज्ञात मसीह तथा दाऊद के सिंहासन का न्यायसंगत उत्तराधिकारी ठहराता है। इस वंशावली में अनुग्रह के आश्चर्यजनक नाम सम्मिलित हैं, फिर स्वर्गदूत पवित्र आत्मा द्वारा कुँवारी से गर्भधारण की घोषणा करता है। यीशु को उद्धारकर्ता नाम दिया गया क्योंकि वह अपने लोगों को उनके पापों से उद्धार देगा, और इम्मानुएल, अर्थात् परमेश्वर हमारे साथ। देहधारण भविष्यद्वाणी को पूरा करता है और हमारी आशा को आधार देता है।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440001', 'ml', 'മത്തായി 1: രാജാവിന്റെ വംശാവലിയും ജനനവും', 'മത്തായി 1 വായിക്കുക. അബ്രാഹാമിൽ തുടങ്ങി ദാവീദ് വഴി യേശുവിന്റെ വംശാവലി കണ്ടെത്തിക്കൊണ്ട് മത്തായി ആരംഭിക്കുന്നു, അവനെ വാഗ്ദത്ത മിശിഹായായും ദാവീദിന്റെ സിംഹാസനത്തിന്റെ ന്യായമായ അവകാശിയായും സ്ഥാപിക്കുന്നു. ഈ വംശാവലിയിൽ കൃപയുടെ അത്ഭുതകരമായ പേരുകൾ ഉൾപ്പെടുന്നു, പിന്നെ പരിശുദ്ധാത്മാവിനാലുള്ള കന്യാഗർഭധാരണത്തെ ദൂതൻ അറിയിക്കുന്നു. യേശു തന്റെ ജനത്തെ അവരുടെ പാപങ്ങളിൽനിന്ന് രക്ഷിക്കും എന്നതിനാൽ അവന് രക്ഷകൻ എന്നും, ദൈവം നമ്മോടുകൂടെ എന്നർഥമുള്ള ഇമ്മാനുവേൽ എന്നും പേർ വിളിക്കപ്പെടുന്നു. അവതാരം പ്രവചനം നിവർത്തിക്കുകയും നമ്മുടെ പ്രത്യാശയ്ക്ക് അടിസ്ഥാനമിടുകയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440002', 'hi', 'मत्ती 2: आराधना, शत्रुता और शरण', 'मत्ती 2 पढ़ें। पूर्व से ज्योतिषी नवजात राजा को ढूँढ़कर उसकी आराधना करते हैं, जबकि हेरोदेस उसकी मृत्यु का षड्यंत्र रचता है, जो मसीह के प्रति दो प्रतिक्रियाओं को प्रकट करता है जो आज भी बनी रहती हैं। परमेश्वर मिस्र की ओर भागने और नासरत लौटने के द्वारा अपने पुत्र की सर्वसामर्थी रक्षा करता है, और हर मोड़ पर पवित्रशास्त्र को पूरा करता है। अन्यजातियों की आराधना सब जातियों तक सुसमाचार के पहुँचने का पूर्वाभास देती है, और परमेश्वर की विश्वासयोग्यता हमें आश्वस्त करती है कि कोई सांसारिक शक्ति उसकी छुटकारे की योजना को विफल नहीं कर सकती।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440002', 'ml', 'മത്തായി 2: ആരാധന, ശത്രുത, അഭയം', 'മത്തായി 2 വായിക്കുക. കിഴക്കുനിന്നുള്ള വിദ്വാന്മാർ നവജാത രാജാവിനെ അന്വേഷിച്ച് അവനെ ആരാധിക്കുന്നു, എന്നാൽ ഹെരോദാവ് അവന്റെ മരണത്തിന് ഗൂഢാലോചന നടത്തുന്നു; ഇത് ഇന്നും നിലനിൽക്കുന്ന ക്രിസ്തുവിനോടുള്ള രണ്ടു പ്രതികരണങ്ങളെ വെളിപ്പെടുത്തുന്നു. ഈജിപ്തിലേക്കുള്ള പലായനത്തിലൂടെയും നസറെത്തിലേക്കുള്ള മടക്കത്തിലൂടെയും ദൈവം പരമാധികാരത്തോടെ തന്റെ പുത്രനെ സംരക്ഷിക്കുന്നു, ഓരോ ഘട്ടത്തിലും തിരുവെഴുത്തു നിവർത്തിക്കുന്നു. വിജാതീയരുടെ ആരാധന സകല ജാതികളിലേക്കും സുവിശേഷം എത്തുന്നതിന്റെ മുന്നോട്ടുള്ള ചിത്രമാണ്; ഒരു ഭൗമികശക്തിക്കും അവന്റെ വീണ്ടെടുപ്പിന്റെ പദ്ധതിയെ തടയാനാവില്ലെന്ന് ദൈവത്തിന്റെ വിശ്വസ്തത നമ്മെ ഉറപ്പിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440003', 'hi', 'मत्ती 3: पश्चाताप और यीशु का बपतिस्मा', 'मत्ती 3 पढ़ें। यूहन्ना बपतिस्मा देनेवाला मार्ग तैयार करता है, इस्राएल को पश्चाताप के लिए बुलाता है और चेतावनी देता है कि सच्चे विश्वास का प्रमाण फल है, न कि वंश। वह स्वयं से हटकर उस अधिक सामर्थी की ओर इशारा करता है जो आत्मा से बपतिस्मा देता है। निष्पाप होते हुए भी, यीशु समस्त धार्मिकता को पूरा करने के लिए बपतिस्मा लेते हैं, और उन पापियों के साथ अपने को पहचानते हैं जिन्हें वह बचाने आए। पिता का स्वर और उतरता हुआ आत्मा त्रिएकता को प्रकट करते हैं, और उनकी सेवकाई की दहलीज़ पर प्रिय पुत्र की पुष्टि करते हैं।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440003', 'ml', 'മത്തായി 3: മാനസാന്തരവും യേശുവിന്റെ സ്നാനവും', 'മത്തായി 3 വായിക്കുക. യോഹന്നാൻ സ്നാപകൻ വഴി ഒരുക്കുന്നു, ഇസ്രായേലിനെ മാനസാന്തരത്തിലേക്ക് വിളിക്കുന്നു, യഥാർഥ വിശ്വാസത്തിന്റെ തെളിവ് പൈതൃകമല്ല, ഫലമാണെന്ന് മുന്നറിയിപ്പു നൽകുന്നു. അവൻ തന്നിൽനിന്നു മാറി, ആത്മാവിനാൽ സ്നാനം നൽകുന്ന ബലവാനായവനിലേക്കു വിരൽചൂണ്ടുന്നു. പാപരഹിതനെങ്കിലും, സകല നീതിയും നിവർത്തിക്കാൻ യേശു സ്നാനമേൽക്കുന്നു, താൻ രക്ഷിക്കാൻ വന്ന പാപികളോട് ഒന്നുചേരുന്നു. പിതാവിന്റെ ശബ്ദവും ഇറങ്ങിവരുന്ന ആത്മാവും ത്രിത്വത്തെ വെളിപ്പെടുത്തുന്നു, അവന്റെ ശുശ്രൂഷയുടെ ഉമ്മറത്ത് പ്രിയപുത്രനെ ഉറപ്പിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440004', 'hi', 'मत्ती 4: परीक्षा, ज्योति और बुलाहट', 'मत्ती 4 पढ़ें। जंगल में यीशु, जो सच्चा इस्राएल हैं, पवित्रशास्त्र को धारण करते हुए शैतान की परीक्षाओं पर विजय पाते हैं, और वहाँ सफल होते हैं जहाँ आदम और इस्राएल असफल रहे। फिर वह राज्य का प्रचार आरंभ करते हैं, पापियों को पश्चाताप के लिए बुलाते हैं क्योंकि राजा आ गया है। मछुओं को अपने पीछे चलने को बुलाकर वह शिक्षा देने, प्रचार करने और चंगा करने की सेवकाई आरंभ करते हैं। उनकी निष्पाप विजय उन्हें हमारे स्थानापन्न होने योग्य ठहराती है और हर आक्रमण के विरुद्ध परमेश्वर के वचन पर निर्भरता का आदर्श प्रस्तुत करती है।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440004', 'ml', 'മത്തായി 4: പരീക്ഷ, വെളിച്ചം, വിളി', 'മത്തായി 4 വായിക്കുക. മരുഭൂമിയിൽ, യഥാർഥ ഇസ്രായേലായ യേശു തിരുവെഴുത്തു പ്രയോഗിച്ച് സാത്താന്റെ പരീക്ഷകളെ ജയിക്കുന്നു, ആദാമും ഇസ്രായേലും പരാജയപ്പെട്ടിടത്ത് വിജയിക്കുന്നു. പിന്നെ രാജാവ് വന്നിരിക്കുന്നതിനാൽ പാപികളെ മാനസാന്തരത്തിലേക്ക് വിളിച്ച് അവൻ രാജ്യം പ്രസംഗിക്കാൻ തുടങ്ങുന്നു. മീൻപിടുത്തക്കാരെ തന്നെ അനുഗമിക്കാൻ വിളിച്ച്, ഉപദേശിക്കുകയും പ്രസംഗിക്കുകയും സൗഖ്യമാക്കുകയും ചെയ്യുന്ന ഒരു ശുശ്രൂഷ അവൻ ആരംഭിക്കുന്നു. അവന്റെ പാപരഹിതമായ വിജയം അവനെ നമ്മുടെ പകരക്കാരനായി യോഗ്യനാക്കുകയും, ഏതു ആക്രമണത്തിനെതിരെയും ദൈവവചനത്തിലുള്ള ആശ്രയത്തിന്റെ മാതൃക നൽകുകയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440005', 'hi', 'मत्ती 5:1-16: धन्यवचन और राज्य की गवाही', 'मत्ती 5:1-16 पढ़ें। यीशु पहाड़ी उपदेश का आरंभ राज्य के नागरिकों के चरित्र का वर्णन करके करते हैं: आत्मा में दीन, शोक करनेवाले, नम्र, धार्मिकता के भूखे, दयालु, मन के शुद्ध, मेल कराने वाले और सताए हुए। ये धन्यवचन हृदय के परिवर्तन का वर्णन करते हैं, न कि कर्मों से अर्जित प्रवेश की शर्तें। फिर वह चेलों को नमक और ज्योति कहते हैं, जिनके भले काम अनुग्रह को प्रकट करते और पिता की महिमा करते हैं, यह दिखाते हुए कि सच्चा विश्वास अनिवार्य रूप से दृश्य, परमेश्वर का सम्मान करने वाला फल लाता है।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440005', 'ml', 'മത്തായി 5:1-16: ഭാഗ്യവചനങ്ങളും രാജ്യത്തിന്റെ സാക്ഷ്യവും', 'മത്തായി 5:1-16 വായിക്കുക. രാജ്യപൗരന്മാരുടെ സ്വഭാവം വർണിച്ചുകൊണ്ട് യേശു ഗിരിപ്രഭാഷണം ആരംഭിക്കുന്നു: ആത്മാവിൽ ദരിദ്രർ, ദുഃഖിക്കുന്നവർ, സൗമ്യർ, നീതിക്കായി വിശക്കുന്നവർ, കരുണയുള്ളവർ, ഹൃദയശുദ്ധിയുള്ളവർ, സമാധാനമുണ്ടാക്കുന്നവർ, പീഡിപ്പിക്കപ്പെടുന്നവർ. ഈ ഭാഗ്യവചനങ്ങൾ പ്രവൃത്തികളാൽ നേടുന്ന പ്രവേശന ഉപാധികളല്ല, ഹൃദയപരിവർത്തനത്തെയാണ് വർണിക്കുന്നത്. പിന്നെ ശിഷ്യന്മാരെ ഉപ്പും വെളിച്ചവും എന്നു വിളിക്കുന്നു; അവരുടെ സൽപ്രവൃത്തികൾ കൃപയെ പ്രദർശിപ്പിക്കുകയും പിതാവിനെ മഹത്വപ്പെടുത്തുകയും ചെയ്യുന്നു, യഥാർഥ വിശ്വാസം അനിവാര്യമായും ദൃശ്യവും ദൈവത്തെ ബഹുമാനിക്കുന്നതുമായ ഫലം പുറപ്പെടുവിക്കുമെന്ന് കാണിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440006', 'hi', 'मत्ती 5:17-48: मसीह व्यवस्था को पूरा करते हैं', 'मत्ती 5:17-48 पढ़ें। यीशु घोषणा करते हैं कि वह व्यवस्था और भविष्यद्वक्ताओं को नष्ट करने नहीं, परन्तु पूरा करने आए, फिर आज्ञाओं के पीछे हृदय की वास्तविक माँगों को प्रकट करते हैं। क्रोध, अभिलाषा, अविश्वासयोग्यता, बदला और घृणा सब परमेश्वर की धार्मिकता का उल्लंघन करते हैं। अपेक्षित सिद्धता हमें मसीह की ओर ले जाती है, जो एकमात्र वह हैं जिन्होंने इसे पूरा किया। मानक को घटाने के बजाय, यीशु उसे और गहरा करते हैं, और उस धार्मिकता के लिए हमारी आवश्यकता को प्रकट करते हैं जिसे केवल वह अनुग्रह के द्वारा प्रदान करते हैं।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440006', 'ml', 'മത്തായി 5:17-48: ക്രിസ്തു ന്യായപ്രമാണം നിവർത്തിക്കുന്നു', 'മത്തായി 5:17-48 വായിക്കുക. താൻ ന്യായപ്രമാണത്തെയും പ്രവാചകന്മാരെയും നീക്കിക്കളയാനല്ല, നിവർത്തിക്കാനാണ് വന്നതെന്ന് യേശു പ്രഖ്യാപിക്കുന്നു, പിന്നെ കല്പനകൾക്കു പിന്നിലെ ഹൃദയത്തിന്റെ യഥാർഥ ആവശ്യങ്ങളെ വെളിപ്പെടുത്തുന്നു. കോപം, മോഹം, അവിശ്വസ്തത, പ്രതികാരം, വിദ്വേഷം — ഇവയെല്ലാം ദൈവത്തിന്റെ നീതിയെ ലംഘിക്കുന്നു. ആവശ്യമായ പൂർണത നമ്മെ ക്രിസ്തുവിലേക്ക് നയിക്കുന്നു, അത് നിവർത്തിച്ച ഏകൻ അവനാണ്. നിലവാരം താഴ്ത്തുന്നതിനു പകരം, യേശു അതിനെ ആഴത്തിലാക്കുന്നു, അവൻ മാത്രം കൃപയാൽ നൽകുന്ന നീതിയോടുള്ള നമ്മുടെ ആവശ്യം വെളിപ്പെടുത്തുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440007', 'hi', 'मत्ती 6: भक्ति, प्रार्थना और भरोसा', 'मत्ती 6 पढ़ें। यीशु मनुष्यों की प्रशंसा के लिए धार्मिकता का अभ्यास करने के विरुद्ध चेतावनी देते हैं, यह सिखाते हुए कि दान, प्रार्थना और उपवास केवल परमेश्वर की दृष्टि के लिए हैं। वह प्रभु की प्रार्थना को परमेश्वर-केंद्रित भक्ति और निर्भरता के नमूने के रूप में देते हैं। चेलों को स्वर्ग में धन संचित करने का आह्वान करते हुए, वह उन्हें उस पिता की ओर इंगित करके चिंता से मुक्त करते हैं जो पक्षियों को खिलाता और सोसनों को पहनाता है। पहले उसके राज्य को ढूँढ़ो, और पिता की विश्वासयोग्य आपूर्ति पर भरोसा रखो।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440007', 'ml', 'മത്തായി 6: ഭക്തി, പ്രാർഥന, ആശ്രയം', 'മത്തായി 6 വായിക്കുക. മനുഷ്യരുടെ പ്രശംസയ്ക്കായി നീതി പ്രവർത്തിക്കുന്നതിനെതിരെ യേശു മുന്നറിയിപ്പു നൽകുന്നു, ദാനവും പ്രാർഥനയും ഉപവാസവും ദൈവത്തിന്റെ കണ്ണുകൾക്കു മാത്രമുള്ളതാണെന്ന് ഉപദേശിക്കുന്നു. ദൈവകേന്ദ്രീകൃതമായ ഭക്തിയുടെയും ആശ്രയത്തിന്റെയും മാതൃകയായി കർത്തൃപ്രാർഥന അവൻ നൽകുന്നു. സ്വർഗത്തിൽ നിക്ഷേപം ശേഖരിക്കാൻ ശിഷ്യന്മാരെ വിളിച്ച്, പക്ഷികളെ പോറ്റുകയും താമരപ്പൂക്കളെ ഉടുപ്പിക്കുകയും ചെയ്യുന്ന പിതാവിലേക്ക് വിരൽചൂണ്ടി അവൻ അവരെ ഉത്കണ്ഠയിൽനിന്നു മോചിപ്പിക്കുന്നു. ആദ്യം അവന്റെ രാജ്യം അന്വേഷിക്കുക, പിതാവിന്റെ വിശ്വസ്തമായ കരുതലിൽ ആശ്രയിക്കുക.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440008', 'hi', 'मत्ती 7: सँकरा मार्ग और सच्चे चेले', 'मत्ती 7 पढ़ें। यीशु पहाड़ी उपदेश का समापन करते हैं, और न्याय करने, निरंतर प्रार्थना और स्वर्णिम नियम पर बात करते हैं। वह सँकरे फाटक, फलों से पहचाने जानेवाले झूठे भविष्यद्वक्ताओं, और इस गंभीर सत्य की चेतावनी देते हैं कि ''हे प्रभु, हे प्रभु'' कहनेवाले सब राज्य में प्रवेश नहीं करते। उनके वचनों को सुनना और मानना ही बुद्धिमान बनानेवाले को मूर्ख बनानेवाले से अलग करता है। भीड़ उनके अधिकार पर चकित होती है, क्योंकि वह उस राजा के समान शिक्षा देते हैं जिसकी आज्ञा मानी जानी चाहिए।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440008', 'ml', 'മത്തായി 7: ഇടുങ്ങിയ വഴിയും യഥാർഥ ശിഷ്യന്മാരും', 'മത്തായി 7 വായിക്കുക. ന്യായവിധി, നിരന്തരമായ പ്രാർഥന, സുവർണനിയമം എന്നിവ പ്രതിപാദിച്ചുകൊണ്ട് യേശു ഗിരിപ്രഭാഷണം സമാപിക്കുന്നു. ഇടുങ്ങിയ വാതിലിനെക്കുറിച്ചും, ഫലത്താൽ അറിയപ്പെടുന്ന കള്ളപ്രവാചകന്മാരെക്കുറിച്ചും, ''കർത്താവേ, കർത്താവേ'' എന്നു പറയുന്ന എല്ലാവരും രാജ്യത്തിൽ പ്രവേശിക്കുകയില്ല എന്ന ഗൗരവമേറിയ സത്യത്തെക്കുറിച്ചും അവൻ മുന്നറിയിപ്പു നൽകുന്നു. അവന്റെ വചനങ്ങൾ കേട്ട് അനുസരിക്കുന്നതാണ് ജ്ഞാനിയായ പണിക്കാരനെ ഭോഷനായവനിൽനിന്നു വേർതിരിക്കുന്നത്. ജനക്കൂട്ടം അവന്റെ അധികാരത്തിൽ വിസ്മയിക്കുന്നു, എന്തെന്നാൽ അനുസരിക്കപ്പെടേണ്ട രാജാവായി അവൻ ഉപദേശിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440009', 'hi', 'मत्ती 8: रोग और प्रकृति पर राजा का अधिकार', 'मत्ती 8 पढ़ें। मत्ती यीशु के अधिकार को प्रकट करने वाले चमत्कारों को एकत्र करता है: कोढ़ी को शुद्ध करना, सूबेदार के दास को वचन से चंगा करना, पतरस की सास को स्वस्थ करना, और यशायाह की भविष्यद्वाणी के अनुसार हमारे रोगों को उठाना। वह तूफान को शांत करते और दुष्टात्माओं को निकालते हैं, और प्रकृति तथा अदृश्य जगत पर अपनी सामर्थ्य सिद्ध करते हैं। यीशु के पीछे चलने के लिए मूल्य गिनना आवश्यक है। ये चिन्ह उनकी पहचान को प्रमाणित करते हैं और टूटे हुओं की ओर ईश्वरीय सामर्थ्य से बहती करुणा को प्रकट करते हैं।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440009', 'ml', 'മത്തായി 8: രോഗത്തിന്മേലും പ്രകൃതിക്കുമേലും രാജാവിന്റെ അധികാരം', 'മത്തായി 8 വായിക്കുക. യേശുവിന്റെ അധികാരം പ്രദർശിപ്പിക്കുന്ന അത്ഭുതങ്ങൾ മത്തായി ഒരുമിച്ചുചേർക്കുന്നു: കുഷ്ഠരോഗിയെ ശുദ്ധമാക്കുന്നു, ശതാധിപന്റെ ദാസനെ വാക്കാൽ സൗഖ്യമാക്കുന്നു, പത്രോസിന്റെ അമ്മായിയമ്മയെ പുനഃസ്ഥാപിക്കുന്നു, യെശയ്യാവു മുൻകൂട്ടിപ്പറഞ്ഞതുപോലെ നമ്മുടെ രോഗങ്ങൾ വഹിക്കുന്നു. അവൻ കൊടുങ്കാറ്റിനെ ശാന്തമാക്കുകയും ഭൂതങ്ങളെ പുറത്താക്കുകയും ചെയ്യുന്നു, പ്രകൃതിക്കുമേലും അദൃശ്യലോകത്തിനുമേലും തന്റെ ശക്തി തെളിയിക്കുന്നു. യേശുവിനെ അനുഗമിക്കാൻ വില കണക്കാക്കണം. ഈ അടയാളങ്ങൾ അവന്റെ വ്യക്തിത്വം സ്ഥിരീകരിക്കുകയും, തകർന്നവരോട് ദൈവികശക്തിയിൽനിന്നൊഴുകുന്ന കരുണ വെളിപ്പെടുത്തുകയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440010', 'hi', 'मत्ती 9: क्षमा करने और पापियों को बुलाने का अधिकार', 'मत्ती 9 पढ़ें। यीशु एक झोले के मारे हुए के पापों को क्षमा करते हैं, और ईश्वरीय अधिकार का दावा करते हैं, फिर अपने अधिकार को सिद्ध करने के लिए उसे चंगा करते हैं। वह मत्ती चुंगी लेनेवाले को बुलाते और पापियों के साथ भोजन करते हैं, यह घोषणा करते हुए कि वह धर्मियों के लिए नहीं, परन्तु पापियों को पश्चाताप के लिए बुलाने आए। बीमारों को चंगा करते और मरे हुओं को जिलाते हुए, वह सताई हुई भीड़ पर करुणा करते और खेत के लिए मजदूरों को माँगते हैं। अनुग्रह अयोग्य और बहिष्कृत को खोजता है।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440010', 'ml', 'മത്തായി 9: ക്ഷമിക്കാനും പാപികളെ വിളിക്കാനുമുള്ള അധികാരം', 'മത്തായി 9 വായിക്കുക. ഒരു പക്ഷവാതക്കാരന്റെ പാപങ്ങൾ ക്ഷമിച്ച് യേശു ദൈവികാവകാശം അവകാശപ്പെടുന്നു, പിന്നെ തന്റെ അധികാരം തെളിയിക്കാൻ അവനെ സൗഖ്യമാക്കുന്നു. ചുങ്കക്കാരനായ മത്തായിയെ വിളിച്ച് പാപികളോടുകൂടെ ഭക്ഷണം കഴിക്കുന്നു, താൻ നീതിമാന്മാർക്കായല്ല, പാപികളെ മാനസാന്തരത്തിലേക്ക് വിളിക്കാനാണ് വന്നതെന്ന് പ്രഖ്യാപിക്കുന്നു. രോഗികളെ സൗഖ്യമാക്കിയും മരിച്ചവരെ ഉയിർപ്പിച്ചും, ഉപദ്രവിക്കപ്പെട്ട ജനക്കൂട്ടത്തോട് അവൻ കരുണ കാണിക്കുകയും കൊയ്ത്തിനു വേലക്കാരെ ആവശ്യപ്പെടുകയും ചെയ്യുന്നു. കൃപ അയോഗ്യരെയും പുറന്തള്ളപ്പെട്ടവരെയും അന്വേഷിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440011', 'hi', 'मत्ती 10: बारहों को भेजना', 'मत्ती 10 पढ़ें। यीशु बारह प्रेरितों को नियुक्त करते हैं, उन्हें अधिकार देते और राज्य का प्रचार करने का निर्देश देते हैं। वह सताव की चेतावनी देते हुए निडर अंगीकार का आग्रह करते हैं, क्योंकि पिता उन्हें गौरैयों से अधिक मूल्यवान समझता है। मसीह के प्रति निष्ठा हर सांसारिक संबंध से बढ़कर है, और जो कोई उसके लिए अपना प्राण खोएगा, वह उसे पाएगा। चेलापन सब कुछ माँगता है फिर भी अनन्त प्रतिफल की प्रतिज्ञा करता है। यह मिशन राजा के अधिकार और अपने सेवकों पर पिता की सर्वसामर्थी देखभाल के अधीन आगे बढ़ता है।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440011', 'ml', 'മത്തായി 10: പന്ത്രണ്ടുപേരെ അയക്കുന്നു', 'മത്തായി 10 വായിക്കുക. യേശു പന്ത്രണ്ട് അപ്പൊസ്തലന്മാരെ നിയോഗിക്കുന്നു, അധികാരം നൽകി രാജ്യം പ്രസംഗിക്കാൻ നിർദേശിക്കുന്നു. പീഡനത്തെക്കുറിച്ച് മുന്നറിയിപ്പു നൽകി, പിതാവ് അവരെ കുരുവികളെക്കാൾ വിലമതിക്കുന്നതിനാൽ ഭയമില്ലാത്ത ഏറ്റുപറച്ചിലിന് അവൻ പ്രേരിപ്പിക്കുന്നു. ക്രിസ്തുവിനോടുള്ള വിശ്വസ്തത ഏതു ഭൗമികബന്ധത്തെയും കവിയുന്നു, അവനുവേണ്ടി ജീവൻ കളയുന്നവൻ അതിനെ കണ്ടെത്തും. ശിഷ്യത്വം എല്ലാം ആവശ്യപ്പെടുന്നു, എങ്കിലും നിത്യപ്രതിഫലം വാഗ്ദാനം ചെയ്യുന്നു. രാജാവിന്റെ അധികാരത്തിന്റെയും തന്റെ ദാസന്മാരോടുള്ള പിതാവിന്റെ പരമാധികാരപരമായ കരുതലിന്റെയും കീഴിൽ ഈ ദൗത്യം മുന്നേറുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440012', 'hi', 'मत्ती 11: यीशु की पहचान और थके हुओं के लिए विश्राम', 'मत्ती 11 पढ़ें। यूहन्ना का प्रश्न यीशु को अपनी मसीही पहचान के प्रमाण के रूप में अपने कामों की ओर इंगित करने के लिए प्रेरित करता है। यीशु उन पश्चातापहीन नगरों को डाँटते हैं जिन्होंने उनके चमत्कार देखकर भी फिरने से इनकार किया। वह आनन्दित होते हैं कि पिता दीनों पर सत्य प्रकट करता है, न कि अपने आप को बुद्धिमान समझनेवालों पर। फिर वह एक कोमल निमंत्रण देते हैं: हे सब थके हुओं, मेरे पास आओ, और अपने प्राणों के लिए विश्राम पाओ। उद्धार का विश्राम केवल मसीह में पाया जाता है।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440012', 'ml', 'മത്തായി 11: യേശുവിന്റെ വ്യക്തിത്വവും ക്ഷീണിതർക്കുള്ള ആശ്വാസവും', 'മത്തായി 11 വായിക്കുക. യോഹന്നാന്റെ ചോദ്യം, തന്റെ വ്യക്തിത്വത്തിന്റെ തെളിവായി തന്റെ മിശിഹൈക പ്രവൃത്തികളിലേക്കു വിരൽചൂണ്ടാൻ യേശുവിനെ പ്രേരിപ്പിക്കുന്നു. അവന്റെ അത്ഭുതങ്ങൾ കണ്ടിട്ടും തിരിയാൻ വിസമ്മതിച്ച മാനസാന്തരമില്ലാത്ത പട്ടണങ്ങളെ യേശു ശാസിക്കുന്നു. സ്വയം ജ്ഞാനികളെന്നു കരുതുന്നവർക്കല്ല, താഴ്മയുള്ളവർക്കു പിതാവ് സത്യം വെളിപ്പെടുത്തുന്നതിൽ അവൻ ആനന്ദിക്കുന്നു. പിന്നെ അവൻ ഹൃദ്യമായ ഒരു ക്ഷണം നൽകുന്നു: ക്ഷീണിതരായ എല്ലാവരുമേ, എന്റെ അടുക്കൽ വരുവിൻ, നിങ്ങളുടെ ആത്മാക്കൾക്ക് ആശ്വാസം കണ്ടെത്തുവിൻ. രക്ഷയുടെ ആശ്വാസം ക്രിസ്തുവിൽ മാത്രമേ കണ്ടെത്താനാകൂ.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440013', 'hi', 'मत्ती 12: विश्रामदिन का प्रभु और बढ़ता विरोध', 'मत्ती 12 पढ़ें। यीशु स्वयं को विश्रामदिन का प्रभु घोषित करते हैं, कानूनवाद से ऊपर दया को प्राथमिकता देते और पवित्र दिन पर चंगा करते हैं। जब फरीसी उनकी सामर्थ्य का श्रेय शैतान को देते हैं, तो वह आत्मा के विरुद्ध अक्षम्य निन्दा की चेतावनी देते हैं, और कठोर अविश्वास को प्रकट करते हैं। शब्द हृदय को प्रकट करते हैं, और योना का चिन्ह उनके आनेवाले पुनरुत्थान की ओर इंगित करता है। सच्चा नातेदारी उनकी है जो पिता की इच्छा पूरी करते हैं, न कि केवल शारीरिक संबंधियों की।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440013', 'ml', 'മത്തായി 12: ശബ്ബത്തിന്റെ കർത്താവും വർധിക്കുന്ന എതിർപ്പും', 'മത്തായി 12 വായിക്കുക. യേശു തന്നെത്തന്നെ ശബ്ബത്തിന്റെ കർത്താവായി പ്രഖ്യാപിക്കുന്നു, നിയമവാദത്തെക്കാൾ കരുണയ്ക്കു മുൻഗണന നൽകി വിശുദ്ധദിനത്തിൽ സൗഖ്യമാക്കുന്നു. പരീശന്മാർ അവന്റെ ശക്തി സാത്താന് ആരോപിക്കുമ്പോൾ, ആത്മാവിനെതിരായ ക്ഷമിക്കാനാവാത്ത ദൂഷണത്തെക്കുറിച്ച് അവൻ മുന്നറിയിപ്പു നൽകുന്നു, കഠിനമായ അവിശ്വാസത്തെ വെളിപ്പെടുത്തുന്നു. വാക്കുകൾ ഹൃദയത്തെ വെളിപ്പെടുത്തുന്നു, യോനായുടെ അടയാളം അവന്റെ വരാനിരിക്കുന്ന പുനരുത്ഥാനത്തിലേക്കു വിരൽചൂണ്ടുന്നു. യഥാർഥ ബന്ധുത്വം ശാരീരിക ബന്ധുക്കൾക്കല്ല, പിതാവിന്റെ ഇഷ്ടം ചെയ്യുന്നവർക്കാണ്.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440014', 'hi', 'मत्ती 13: राज्य के दृष्टांत', 'मत्ती 13 पढ़ें। यीशु दृष्टांतों में शिक्षा देते हैं, ग्रहणशील हृदयों पर राज्य को प्रकट करते जबकि कठोर हृदयों से उसे छिपाते हैं। बोनेवाले का दृष्टांत वचन के प्रति भिन्न-भिन्न प्रतिक्रियाओं को दिखाता है; गेहूँ और जंगली बीज, राई के दाने, और खमीर राज्य की गुप्त वृद्धि और अंतिम विभाजन को चित्रित करते हैं। छिपा हुआ धन और मोती उसके अति मूल्य को दर्शाते हैं, और जाल न्याय की भविष्यद्वाणी करता है। राज्य अप्रत्याशित रूप से आता है, सब कुछ माँगता है, और परमेश्वर के सर्वसामर्थी कार्य से बढ़ता है।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440014', 'ml', 'മത്തായി 13: രാജ്യത്തിന്റെ ഉപമകൾ', 'മത്തായി 13 വായിക്കുക. യേശു ഉപമകളിലൂടെ ഉപദേശിക്കുന്നു, സ്വീകരണശേഷിയുള്ള ഹൃദയങ്ങൾക്ക് രാജ്യം വെളിപ്പെടുത്തുകയും കഠിനഹൃദയരിൽനിന്ന് അത് മറയ്ക്കുകയും ചെയ്യുന്നു. വിതക്കാരന്റെ ഉപമ വചനത്തോടുള്ള വ്യത്യസ്ത പ്രതികരണങ്ങൾ കാണിക്കുന്നു; ഗോതമ്പും കളയും, കടുകുമണിയും, പുളിമാവും രാജ്യത്തിന്റെ ഗൂഢമായ വളർച്ചയും അന്തിമമായ വേർതിരിവും ചിത്രീകരിക്കുന്നു. നിധിയും മുത്തും അതിന്റെ അതിശ്രേഷ്ഠമൂല്യം വരച്ചുകാട്ടുന്നു, വല ന്യായവിധി മുൻകൂട്ടിപ്പറയുന്നു. രാജ്യം അപ്രതീക്ഷിതമായി വരുന്നു, എല്ലാം ആവശ്യപ്പെടുന്നു, ദൈവത്തിന്റെ പരമാധികാരപ്രവൃത്തിയാൽ വളരുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440015', 'hi', 'मत्ती 14: आपूर्ति और तूफान पर सामर्थ्य', 'मत्ती 14 पढ़ें। यूहन्ना बपतिस्मा देनेवाले की हत्या के बाद, यीशु अलग हो जाते हैं फिर भी भीड़ पर करुणा करते हैं, और पाँच रोटियों तथा दो मछलियों से पाँच हजार को खिलाते हैं। वह पानी पर चलकर और डूबते हुए संदेह करनेवाले पतरस को बचाकर ईश्वरीय सामर्थ्य प्रकट करते हैं। चेले उन्हें परमेश्वर का पुत्र मानकर आराधना करते हैं। भीड़ उनके वस्त्र को छूकर चंगी होती है। मसीह स्वयं को सर्व-पर्याप्त भरणपोषण करनेवाला और थामनेवाला सिद्ध करते हैं, जो विश्वास और आराधना के योग्य हैं।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440015', 'ml', 'മത്തായി 14: കരുതലും കൊടുങ്കാറ്റിന്മേലുള്ള ശക്തിയും', 'മത്തായി 14 വായിക്കുക. യോഹന്നാൻ സ്നാപകന്റെ രക്തസാക്ഷിത്വത്തിനുശേഷം യേശു മാറിപ്പോകുന്നു, എങ്കിലും ജനക്കൂട്ടത്തോട് കരുണ തോന്നി, അഞ്ച് അപ്പവും രണ്ടു മീനും കൊണ്ട് അയ്യായിരം പേരെ പോറ്റുന്നു. കടലിന്മേൽ നടന്നും, സംശയിച്ച് മുങ്ങുന്ന പത്രോസിനെ രക്ഷിച്ചും അവൻ ദൈവികശക്തി വെളിപ്പെടുത്തുന്നു. ശിഷ്യന്മാർ അവനെ ദൈവപുത്രനായി ആരാധിക്കുന്നു. ജനക്കൂട്ടം അവന്റെ വസ്ത്രം തൊട്ട് സൗഖ്യമാകുന്നു. വിശ്വാസത്തിനും ആരാധനയ്ക്കും യോഗ്യനായ, സർവസമ്പൂർണനായ കരുതലുകാരനും താങ്ങുകാരനുമായി ക്രിസ്തു തന്നെത്തന്നെ തെളിയിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440016', 'hi', 'मत्ती 15: सच्ची अशुद्धता और दृढ़ विश्वास', 'मत्ती 15 पढ़ें। यीशु फरीसियों का सामना करते हैं कि वे परमेश्वर की आज्ञा से ऊपर मानवीय परम्परा को रखते हैं, यह सिखाते हुए कि अशुद्धता बिना धोए हाथों से नहीं, परन्तु हृदय से बहती है। वह पाप के भीतरी स्रोत को प्रकट करते हैं। एक कनानी स्त्री का दृढ़, नम्र विश्वास उन्हें उसकी बेटी को चंगा करने के लिए प्रेरित करता है, जो अन्यजातियों के लिए अनुग्रह का पूर्वाभास देता है। फिर वह चार हजार को खिलाते हैं, और पुनः करुणा तथा आपूर्ति प्रकट करते हैं। परमेश्वर बाहरी रीति से ऊपर हृदय-विश्वास को महत्त्व देता है और उन सबका स्वागत करता है जो उस पर भरोसा करते हैं।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440016', 'ml', 'മത്തായി 15: യഥാർഥ മാലിന്യവും സ്ഥിരതയുള്ള വിശ്വാസവും', 'മത്തായി 15 വായിക്കുക. ദൈവകല്പനയ്ക്കു മുകളിൽ മാനുഷിക പാരമ്പര്യം ഉയർത്തുന്നതിന് യേശു പരീശന്മാരെ നേരിടുന്നു, മാലിന്യം കഴുകാത്ത കൈകളിൽനിന്നല്ല, ഹൃദയത്തിൽനിന്നാണ് ഒഴുകുന്നതെന്ന് ഉപദേശിക്കുന്നു. പാപത്തിന്റെ ആന്തരിക ഉറവിടം അവൻ വെളിപ്പെടുത്തുന്നു. ഒരു കനാന്യസ്ത്രീയുടെ സ്ഥിരവും താഴ്മയുള്ളതുമായ വിശ്വാസം അവളുടെ മകളെ സൗഖ്യമാക്കാൻ അവനെ പ്രേരിപ്പിക്കുന്നു, ഇത് വിജാതീയർക്കുള്ള കൃപയുടെ മുന്നോട്ടുള്ള ചിത്രമാണ്. പിന്നെ അവൻ നാലായിരം പേരെ പോറ്റി, വീണ്ടും കരുണയും കരുതലും പ്രദർശിപ്പിക്കുന്നു. ദൈവം ബാഹ്യാചാരത്തെക്കാൾ ഹൃദയവിശ്വാസത്തെ വിലമതിക്കുകയും, തന്നിൽ ആശ്രയിക്കുന്ന എല്ലാവരെയും സ്വാഗതം ചെയ്യുകയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440017', 'hi', 'मत्ती 16: पतरस का अंगीकार और अनुसरण की कीमत', 'मत्ती 16 पढ़ें। फरीसियों की चिन्ह की माँग को ठुकराते हुए, यीशु झूठी शिक्षा की चेतावनी देते हैं। कैसरिया फिलिप्पी में, पतरस यीशु को मसीह, जीवते परमेश्वर का पुत्र अंगीकार करता है, यह सत्य पिता ने प्रकट किया। यीशु अपनी कलीसिया बनाने की प्रतिज्ञा करते हैं और फिर अपनी मृत्यु तथा पुनरुत्थान की भविष्यद्वाणी करते हैं। वह क्रूस के प्रति पतरस के विरोध को डाँटते हैं और चेलों को अपने आप का इनकार करने, अपना क्रूस उठाने और उनके पीछे चलने को बुलाते हैं।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440017', 'ml', 'മത്തായി 16: പത്രോസിന്റെ ഏറ്റുപറച്ചിലും അനുഗമിക്കുന്നതിന്റെ വിലയും', 'മത്തായി 16 വായിക്കുക. അടയാളം ആവശ്യപ്പെടുന്ന പരീശന്മാരെ തള്ളിക്കളഞ്ഞ് യേശു കള്ളഉപദേശത്തെക്കുറിച്ച് മുന്നറിയിപ്പു നൽകുന്നു. കൈസര്യഫിലിപ്പിയിൽ പത്രോസ് യേശുവിനെ ക്രിസ്തു, ജീവനുള്ള ദൈവത്തിന്റെ പുത്രൻ എന്ന് ഏറ്റുപറയുന്നു; ഈ സത്യം പിതാവ് വെളിപ്പെടുത്തിയതാണ്. യേശു തന്റെ സഭ പണിയുമെന്ന് വാഗ്ദാനം ചെയ്യുകയും പിന്നെ തന്റെ മരണവും പുനരുത്ഥാനവും മുൻകൂട്ടിപ്പറയുകയും ചെയ്യുന്നു. ക്രൂശിനോടുള്ള പത്രോസിന്റെ എതിർപ്പിനെ അവൻ ശാസിക്കുകയും, തന്നെത്തന്നെ ത്യജിച്ച്, തന്റെ ക്രൂശ് എടുത്ത്, അവനെ അനുഗമിക്കാൻ ശിഷ്യന്മാരെ വിളിക്കുകയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440018', 'hi', 'मत्ती 17: रूपान्तरण और पुत्र की महिमा', 'मत्ती 17 पढ़ें। पहाड़ पर यीशु का रूपान्तरण होता है, उनका मुख चमकता है और मूसा तथा एलिय्याह प्रकट होते हैं, जबकि पिता का स्वर आज्ञा देता है, यह मेरा प्रिय पुत्र है; इसकी सुनो। यह महिमा उनके ईश्वरत्व की पुष्टि करती है और व्यवस्था तथा भविष्यद्वक्ताओं से बढ़कर है। उतरकर, यीशु एक दुष्टात्माग्रस्त बालक को चंगा करते हैं, विश्वास के विषय में सिखाते हैं, और फिर अपनी मृत्यु तथा पुनरुत्थान की भविष्यद्वाणी करते हैं। महिमा में भी, वह हमारे उद्धार के लिए दृढ़ता से क्रूस की ओर बढ़ते हैं।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440018', 'ml', 'മത്തായി 17: രൂപാന്തരവും പുത്രന്റെ മഹത്വവും', 'മത്തായി 17 വായിക്കുക. മലയിൽ യേശു രൂപാന്തരപ്പെടുന്നു, അവന്റെ മുഖം പ്രകാശിക്കുന്നു, മോശയും ഏലിയാവും പ്രത്യക്ഷപ്പെടുന്നു, പിതാവിന്റെ ശബ്ദം കല്പിക്കുന്നു, ഇവൻ എന്റെ പ്രിയപുത്രൻ; ഇവന്റെ വാക്കു കേൾക്കുവിൻ. ഈ മഹത്വം അവന്റെ ദൈവത്വം സ്ഥിരീകരിക്കുകയും ന്യായപ്രമാണത്തെയും പ്രവാചകന്മാരെയും കവിയുകയും ചെയ്യുന്നു. ഇറങ്ങിവന്ന്, യേശു ഭൂതബാധിതനായ ഒരു ബാലനെ സൗഖ്യമാക്കുകയും, വിശ്വാസത്തെക്കുറിച്ച് ഉപദേശിക്കുകയും, വീണ്ടും തന്റെ മരണവും പുനരുത്ഥാനവും മുൻകൂട്ടിപ്പറയുകയും ചെയ്യുന്നു. മഹത്വത്തിലും, നമ്മുടെ രക്ഷയ്ക്കായി അവൻ ഉറപ്പോടെ ക്രൂശിലേക്കു നീങ്ങുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440019', 'hi', 'मत्ती 18: दीनता, क्षमा और कलीसियाई अनुशासन', 'मत्ती 18 पढ़ें। यीशु सिखाते हैं कि राज्य में बड़प्पन के लिए बालक के समान दीनता आवश्यक है और छोटों को ठोकर खिलाने के विरुद्ध कठोर चेतावनी देते हैं। पिता भटकी हुई भेड़ को ढूँढ़ता है, और यीशु पाप करनेवाले भाई को पुनः जीतने तथा कलीसियाई अनुशासन चलाने के चरण बताते हैं। निर्दयी दास का दृष्टांत प्रकट करता है कि जिन्हें विशाल ऋण क्षमा किया गया है उन्हें औरों को हृदय से क्षमा करना चाहिए। प्राप्त किया गया अनुग्रह छुड़ाए हुए समुदाय के भीतर अनुग्रह दिखाने के लिए बाध्य करता है।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440019', 'ml', 'മത്തായി 18: താഴ്മ, ക്ഷമ, സഭാശിക്ഷണം', 'മത്തായി 18 വായിക്കുക. രാജ്യത്തിലെ മഹത്വത്തിന് ശിശുസമാനമായ താഴ്മ ആവശ്യമാണെന്ന് യേശു ഉപദേശിക്കുകയും, ചെറിയവരെ ഇടറിക്കുന്നതിനെതിരെ കഠിനമായി മുന്നറിയിപ്പു നൽകുകയും ചെയ്യുന്നു. പിതാവ് വഴിതെറ്റിയ ആടിനെ അന്വേഷിക്കുന്നു, പാപം ചെയ്യുന്ന സഹോദരനെ വീണ്ടെടുക്കാനും സഭാശിക്ഷണം നടത്താനുമുള്ള ഘട്ടങ്ങൾ യേശു വിവരിക്കുന്നു. ക്ഷമിക്കാത്ത ദാസന്റെ ഉപമ, വലിയ കടം ക്ഷമിക്കപ്പെട്ടവർ മറ്റുള്ളവരോട് ഹൃദയത്തിൽനിന്നു ക്ഷമിക്കണമെന്നു വെളിപ്പെടുത്തുന്നു. ലഭിച്ച കൃപ, വീണ്ടെടുക്കപ്പെട്ട സമൂഹത്തിനുള്ളിൽ കൃപ പ്രകടിപ്പിക്കാൻ പ്രേരിപ്പിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440020', 'hi', 'मत्ती 19: विवाह, धन और राज्य', 'मत्ती 19 पढ़ें। यीशु विवाह के लिए परमेश्वर की रचना को बनाए रखते हैं, जो सृष्टि में जड़ पकड़ी हुई आजीवन, एक-तन संगति है, और तलाक को अनुग्रह तथा सत्य के साथ संबोधित करते हैं। वह बच्चों को आशीष देते हैं, यह सिखाते हुए कि राज्य निर्भर रहनेवालों का है। धनी जवान सरदार दुःखी होकर लौट जाता है, यह प्रकट करते हुए कि धन परमेश्वर का प्रतिद्वंद्वी बन सकता है। उद्धार मनुष्य के लिए असंभव है परन्तु परमेश्वर के साथ संभव है, और जो मसीह के लिए सब कुछ छोड़ देते हैं वे प्रचुर अनन्त प्रतिफल पाते हैं।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440020', 'ml', 'മത്തായി 19: വിവാഹം, സമ്പത്ത്, രാജ്യം', 'മത്തായി 19 വായിക്കുക. സൃഷ്ടിയിൽ വേരൂന്നിയ, ആജീവനാന്തമായ, ഏകദേഹമായ ഐക്യമെന്ന വിവാഹത്തിനായുള്ള ദൈവത്തിന്റെ രൂപകല്പനയെ യേശു ഉയർത്തിപ്പിടിക്കുന്നു, വിവാഹമോചനത്തെ കൃപയോടും സത്യത്തോടുംകൂടെ കൈകാര്യം ചെയ്യുന്നു. ആശ്രയിക്കുന്നവർക്കാണ് രാജ്യം എന്ന് ഉപദേശിച്ച് അവൻ കുട്ടികളെ അനുഗ്രഹിക്കുന്നു. ധനവാനായ യുവപ്രമാണി ദുഃഖത്തോടെ മടങ്ങിപ്പോകുന്നു, സമ്പത്ത് ദൈവത്തിന് എതിരാളിയാകാമെന്ന് വെളിപ്പെടുത്തുന്നു. രക്ഷ മനുഷ്യന് അസാധ്യമാണ്, എന്നാൽ ദൈവത്തിന് സാധ്യമാണ്; ക്രിസ്തുവിനായി എല്ലാം ഉപേക്ഷിക്കുന്നവർ സമൃദ്ധമായ നിത്യപ്രതിഫലം പ്രാപിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440021', 'hi', 'मत्ती 20: अनुग्रह, सेवा और दुःख उठानेवाला सेवक', 'मत्ती 20 पढ़ें। दाख की बारी के मजदूरों का दृष्टांत परमेश्वर की सर्वसामर्थी उदारता को प्रकट करता है, जो योग्यता की परवाह किए बिना समान अनुग्रह देता है, और अधिकार के हर दावे को चुप करता है। यीशु तीसरी बार अपनी मृत्यु की भविष्यद्वाणी करते हैं, फिर बड़प्पन को सेवकाई के रूप में पुनः परिभाषित करते हैं: मनुष्य का पुत्र सेवा करवाने नहीं, परन्तु सेवा करने और बहुतों के छुटकारे के लिए अपना प्राण देने आया। वह दो अंधों को चंगा करते हैं, और उस दया को साकार करते हैं जिसका वह प्रचार करते हैं।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440021', 'ml', 'മത്തായി 20: കൃപ, സേവനം, കഷ്ടം അനുഭവിക്കുന്ന ദാസൻ', 'മത്തായി 20 വായിക്കുക. മുന്തിരിത്തോട്ടത്തിലെ വേലക്കാരുടെ ഉപമ ദൈവത്തിന്റെ പരമാധികാരപരമായ ഔദാര്യം വെളിപ്പെടുത്തുന്നു; യോഗ്യത നോക്കാതെ തുല്യകൃപ നൽകി, അവകാശവാദങ്ങളെല്ലാം നിശ്ശബ്ദമാക്കുന്നു. യേശു മൂന്നാം പ്രാവശ്യം തന്റെ മരണം മുൻകൂട്ടിപ്പറയുന്നു, പിന്നെ മഹത്വത്തെ ദാസ്യമായി പുനർനിർവചിക്കുന്നു: മനുഷ്യപുത്രൻ ശുശ്രൂഷ ഏൽക്കാനല്ല, ശുശ്രൂഷിക്കാനും അനേകർക്കു മറുവിലയായി തന്റെ ജീവൻ നൽകാനുമാണ് വന്നത്. അവൻ രണ്ട് അന്ധരെ സൗഖ്യമാക്കി, താൻ പ്രസംഗിക്കുന്ന കരുണ പ്രവൃത്തിയിൽ കാണിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440022', 'hi', 'मत्ती 21: विजयोल्लास प्रवेश और टकराव', 'मत्ती 21 पढ़ें। यीशु यरूशलेम में उस दीन राजा के रूप में प्रवेश करते हैं जिसकी भविष्यद्वाणी जकर्याह ने की थी, और होशन्ना से उनका स्वागत किया जाता है। वह मंदिर को शुद्ध करके उसे प्रार्थना का घर बनाते हैं, और फलहीन अंजीर के पेड़ को शाप देते हैं, जो बंजर धर्म को चित्रित करता है। महायाजकों का सामना करते हुए, वह दो पुत्रों और दुष्ट किसानों के दृष्टांत सुनाते हैं, और परमेश्वर के पुत्र के उनके इनकार को प्रकट करते हैं। ठुकराया हुआ पत्थर परमेश्वर की छुटकारे की योजना का कोनेवाला पत्थर बन जाता है।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440022', 'ml', 'മത്തായി 21: വിജയകരമായ പ്രവേശനവും ഏറ്റുമുട്ടലും', 'മത്തായി 21 വായിക്കുക. സെഖര്യാവ് മുൻകൂട്ടിപ്പറഞ്ഞ താഴ്മയുള്ള രാജാവായി യേശു യെരൂശലേമിലേക്കു പ്രവേശിക്കുന്നു, ഹോശന്നയോടെ വരവേൽക്കപ്പെടുന്നു. അവൻ ദൈവാലയം ശുദ്ധീകരിച്ച് അതിനെ പ്രാർഥനയുടെ ഭവനമായി പുനഃസ്ഥാപിക്കുകയും, ഫലമില്ലാത്ത അത്തിമരത്തെ ശപിച്ച് ഫലശൂന്യമായ മതത്തെ ചിത്രീകരിക്കുകയും ചെയ്യുന്നു. മഹാപുരോഹിതന്മാരെ നേരിട്ട്, രണ്ടു പുത്രന്മാരുടെയും ദുഷ്ടകൃഷിക്കാരുടെയും ഉപമകൾ പറഞ്ഞ്, ദൈവപുത്രനോടുള്ള അവരുടെ തിരസ്കരണം വെളിപ്പെടുത്തുന്നു. തിരസ്കരിക്കപ്പെട്ട കല്ല് ദൈവത്തിന്റെ വീണ്ടെടുപ്പുപദ്ധതിയുടെ മൂലക്കല്ലായിത്തീരുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440023', 'hi', 'मत्ती 22: विवाह-भोज और आलोचकों को चुप करना', 'मत्ती 22 पढ़ें। विवाह-भोज का दृष्टांत चेतावनी देता है कि बहुत बुलाए जाते हैं परन्तु केवल वे ही प्रवेश करते हैं जो धार्मिकता के वस्त्र पहने हैं, जो परमेश्वर-प्रदत्त उद्धार की आवश्यकता को चित्रित करता है। यीशु कर, पुनरुत्थान और व्यवस्था के विषय में जालों का उत्तर देते हैं, यह घोषणा करते हुए कि सबसे बड़ी आज्ञाएँ परमेश्वर और पड़ोसी से पूरे मन से प्रेम करना हैं। फिर वह यह दिखाकर अपने विरोधियों को चुप करते हैं कि मसीह दाऊद का प्रभु है, और मात्र मानवीय वंश से परे अपनी ईश्वरीय पहचान की पुष्टि करते हैं।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440023', 'ml', 'മത്തായി 22: വിവാഹവിരുന്നും വിമർശകരെ നിശ്ശബ്ദമാക്കലും', 'മത്തായി 22 വായിക്കുക. വിവാഹവിരുന്നിന്റെ ഉപമ, അനേകർ ക്ഷണിക്കപ്പെടുന്നുവെങ്കിലും നീതിയുടെ വസ്ത്രം ധരിച്ചവർ മാത്രമേ പ്രവേശിക്കൂ എന്നു മുന്നറിയിപ്പു നൽകുന്നു, ദൈവം നൽകുന്ന രക്ഷയുടെ ആവശ്യകത ചിത്രീകരിക്കുന്നു. നികുതി, പുനരുത്ഥാനം, ന്യായപ്രമാണം എന്നിവയെക്കുറിച്ചുള്ള കെണികൾക്ക് യേശു ഉത്തരം നൽകി, ഏറ്റവും വലിയ കല്പനകൾ ദൈവത്തെയും അയൽക്കാരനെയും പൂർണഹൃദയത്തോടെ സ്നേഹിക്കുന്നതാണെന്ന് പ്രഖ്യാപിക്കുന്നു. പിന്നെ മിശിഹാ ദാവീദിന്റെ കർത്താവാണെന്നു കാണിച്ച് അവൻ എതിരാളികളെ നിശ്ശബ്ദമാക്കുന്നു, കേവലം മാനുഷിക വംശപാരമ്പര്യത്തിനപ്പുറമുള്ള തന്റെ ദൈവിക വ്യക്തിത്വം സ്ഥിരീകരിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440024', 'hi', 'मत्ती 23: कपटियों पर हाय', 'मत्ती 23 पढ़ें। यीशु शास्त्रियों और फरीसियों पर सात बार हाय कहते हैं, उनके कपट, घमंड और औरों पर बोझ डालने की निन्दा करते हुए, जबकि वे न्याय, दया और विश्वास की उपेक्षा करते हैं। वे बाहर से धर्मी दिखते हैं फिर भी भीतर से भ्रष्ट हैं। उनकी तीखी फटकार पुनर्जन्म के बिना धर्म को प्रकट करती है। फिर भी उनके अंतिम वचन यरूशलेम पर कोमल शोक के साथ विलाप करते हैं, और उसकी संतान को इकट्ठा करने की लालसा करते हैं। सच्ची धार्मिकता भीतरी और आत्मा द्वारा रची हुई है, कभी केवल बाहरी प्रदर्शन नहीं।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440024', 'ml', 'മത്തായി 23: കപടഭക്തർക്കു ഹാ കഷ്ടം', 'മത്തായി 23 വായിക്കുക. ശാസ്ത്രിമാർക്കും പരീശന്മാർക്കും യേശു ഏഴു ഹാ കഷ്ടം പ്രഖ്യാപിക്കുന്നു, അവരുടെ കാപട്യം, അഹങ്കാരം, മറ്റുള്ളവരുടെമേൽ ഭാരം ചുമത്തൽ എന്നിവയെ കുറ്റപ്പെടുത്തുന്നു, അതേസമയം നീതി, കരുണ, വിശ്വാസം എന്നിവ അവർ അവഗണിക്കുന്നു. അവർ പുറമെ നീതിമാന്മാരായി കാണപ്പെടുന്നു, എങ്കിലും ഉള്ളിൽ ദുഷിച്ചവരാണ്. അവന്റെ കഠിനമായ ശാസന പുനർജനനമില്ലാത്ത മതത്തെ വെളിപ്പെടുത്തുന്നു. എങ്കിലും അവന്റെ അന്ത്യവചനങ്ങൾ യെരൂശലേമിനെക്കുറിച്ച് ഹൃദ്യമായ ദുഃഖത്തോടെ വിലപിക്കുന്നു, അവളുടെ മക്കളെ ഒരുമിച്ചുചേർക്കാൻ കൊതിക്കുന്നു. യഥാർഥ നീതി ആന്തരികവും ആത്മാവിനാൽ ഉളവാകുന്നതുമാണ്, ഒരിക്കലും കേവലം ബാഹ്യപ്രകടനമല്ല.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440025', 'hi', 'मत्ती 24: जैतून पर्वत का प्रवचन और मसीह का पुनरागमन', 'मत्ती 24 पढ़ें। यीशु मंदिर के विनाश और अंत से पहले के चिन्हों की भविष्यद्वाणी करते हैं: धोखा, क्लेश, और सब जातियों में सुसमाचार का प्रचार। वह झूठे मसीहों के विरुद्ध चेतावनी देते हैं और आश्वासन देते हैं कि उनका आना स्पष्ट और महिमामय होगा। उस दिन या घड़ी को कोई नहीं जानता, इसलिए चेलों को जागते और विश्वासयोग्य रहना चाहिए। मसीह का निश्चित पुनरागमन विश्वासियों को उनके महिमामय दर्शन की प्रतीक्षा करते हुए तत्परता, धीरज और स्थिर सेवा के लिए बुलाता है।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440025', 'ml', 'മത്തായി 24: ഒലിവുമലപ്രഭാഷണവും ക്രിസ്തുവിന്റെ പുനരാഗമനവും', 'മത്തായി 24 വായിക്കുക. ദൈവാലയത്തിന്റെ നാശവും അന്ത്യത്തിനു മുമ്പുള്ള അടയാളങ്ങളും യേശു മുൻകൂട്ടിപ്പറയുന്നു: വഞ്ചന, കഷ്ടകാലം, സകല ജാതികളിലും സുവിശേഷം പ്രസംഗിക്കൽ. കള്ളമിശിഹാമാർക്കെതിരെ അവൻ മുന്നറിയിപ്പു നൽകുകയും, തന്റെ വരവ് വ്യക്തവും മഹത്വമേറിയതുമായിരിക്കുമെന്ന് ഉറപ്പുനൽകുകയും ചെയ്യുന്നു. ആ ദിവസമോ നാഴികയോ ആരും അറിയുന്നില്ല, അതിനാൽ ശിഷ്യന്മാർ ജാഗരൂകരും വിശ്വസ്തരുമായിരിക്കണം. ക്രിസ്തുവിന്റെ നിശ്ചയമായ പുനരാഗമനം, അവന്റെ മഹത്വമേറിയ പ്രത്യക്ഷതയ്ക്കായി കാത്തിരിക്കുമ്പോൾ ഒരുക്കത്തിലേക്കും സഹിഷ്ണുതയിലേക്കും സ്ഥിരമായ സേവനത്തിലേക്കും വിശ്വാസികളെ വിളിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440026', 'hi', 'मत्ती 25: तत्परता और अंतिम न्याय', 'मत्ती 25 पढ़ें। तीन दृष्टांत तत्परता की बुलाहट पर जोर देते हैं: दस कुँवारियाँ तैयार रहने का आग्रह करती हैं, तोड़े विश्वासयोग्य भण्डारीपन की माँग करते हैं, और भेड़ें तथा बकरियाँ अंतिम न्याय को चित्रित करती हैं। मसीह जातियों को अलग करते हैं, और सच्चा विश्वास उनके लोगों के प्रति दया के कामों में स्वयं को सिद्ध करता है, यद्यपि ऐसे काम अनुग्रह से बहते हैं और कभी उद्धार अर्जित नहीं करते। राजा न्याय करने लौटता है, विश्वासयोग्यता को प्रतिफल देता और खोखले अंगीकार को अनन्त अलगाव में दण्डित करता है।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440026', 'ml', 'മത്തായി 25: ഒരുക്കവും അന്തിമ ന്യായവിധിയും', 'മത്തായി 25 വായിക്കുക. മൂന്ന് ഉപമകൾ ഒരുക്കത്തിന്റെ വിളിയെ ഊന്നിപ്പറയുന്നു: പത്തു കന്യകമാർ ഒരുക്കത്തെ ഉദ്ബോധിപ്പിക്കുന്നു, താലന്തുകൾ വിശ്വസ്തമായ കാര്യസ്ഥത ആവശ്യപ്പെടുന്നു, ചെമ്മരിയാടുകളും കോലാടുകളും അന്തിമ ന്യായവിധി ചിത്രീകരിക്കുന്നു. ക്രിസ്തു ജാതികളെ വേർതിരിക്കുന്നു, യഥാർഥ വിശ്വാസം അവന്റെ ജനത്തോടുള്ള കരുണാപ്രവൃത്തികളിൽ തന്നെത്തന്നെ തെളിയിക്കുന്നു, എങ്കിലും അത്തരം പ്രവൃത്തികൾ കൃപയിൽനിന്ന് ഒഴുകുന്നതാണ്, ഒരിക്കലും രക്ഷ നേടിത്തരുന്നില്ല. രാജാവ് ന്യായം വിധിക്കാൻ മടങ്ങിവരുന്നു, വിശ്വസ്തതയ്ക്കു പ്രതിഫലം നൽകുകയും, ശൂന്യമായ ഏറ്റുപറച്ചിലിനെ നിത്യമായ വേർപാടിലേക്കു ശിക്ഷിക്കുകയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440027', 'hi', 'मत्ती 26: अंतिम भोज और गतसमनी', 'मत्ती 26 पढ़ें। ज्यों-ज्यों क्रूस निकट आता है, एक स्त्री यीशु का अभिषेक करती है और यहूदा उन्हें पकड़वाने का षड्यंत्र रचता है। अंतिम भोज में यीशु अपने लहू में एक नई वाचा स्थापित करते हैं, जो पापों की क्षमा के लिए बहाया गया। गतसमनी में वह व्याकुल प्रार्थना में पिता की इच्छा के अधीन हो जाते हैं। वह पकड़वाए जाते, बंदी बनाए जाते और अन्यायपूर्वक मुकद्दमे में लाए जाते हैं, जबकि पतरस उनका इनकार करता है। निष्पाप उद्धारकर्ता स्वेच्छा से अपनी प्रायश्चित मृत्यु की ओर बढ़ते हैं।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440027', 'ml', 'മത്തായി 26: അന്ത്യഅത്താഴവും ഗെത്ത്ശെമനയും', 'മത്തായി 26 വായിക്കുക. ക്രൂശ് അടുക്കുമ്പോൾ, ഒരു സ്ത്രീ യേശുവിനെ അഭിഷേകം ചെയ്യുകയും യൂദാ അവനെ ഒറ്റിക്കൊടുക്കാൻ ഗൂഢാലോചന നടത്തുകയും ചെയ്യുന്നു. അന്ത്യഅത്താഴത്തിൽ യേശു തന്റെ രക്തത്തിൽ ഒരു പുതിയ ഉടമ്പടി സ്ഥാപിക്കുന്നു, അത് പാപമോചനത്തിനായി ചൊരിയപ്പെട്ടു. ഗെത്ത്ശെമനയിൽ വ്യാകുലമായ പ്രാർഥനയിൽ അവൻ പിതാവിന്റെ ഇഷ്ടത്തിന് കീഴ്പെടുന്നു. അവൻ ഒറ്റിക്കൊടുക്കപ്പെടുകയും, ബന്ധിക്കപ്പെടുകയും, അന്യായമായി വിസ്തരിക്കപ്പെടുകയും ചെയ്യുന്നു, അതേസമയം പത്രോസ് അവനെ തള്ളിപ്പറയുന്നു. പാപരഹിതനായ രക്ഷകൻ തന്റെ പ്രായശ്ചിത്തമരണത്തിലേക്കു സ്വമേധയാ നടന്നടുക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440028', 'hi', 'मत्ती 27: राजा का क्रूसीकरण', 'मत्ती 27 पढ़ें। यीशु पीलातुस के सामने दोषी ठहराए जाते, उपहास किए जाते और अपराधियों के बीच क्रूस पर चढ़ाए जाते हैं, और पापियों के लिए परमेश्वर के क्रोध को सहते हैं। अंधकार धरती को ढाँप लेता है और वह हमारे स्थान में त्यागे जाकर पुकारते हैं, और ईश्वरीय न्याय को संतुष्ट करते हैं। उनकी मृत्यु पर मंदिर का परदा फट जाता है, जो परमेश्वर तक पहुँच खोलता है, और पृथ्वी काँपती है। वह एक उधार ली हुई कब्र में गाड़े जाते हैं, जो बंद की और पहरे में रखी जाती है। उन सबके लिए जो विश्वास करते हैं स्थानापन्न प्रायश्चित पूरा हो जाता है।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440028', 'ml', 'മത്തായി 27: രാജാവിന്റെ ക്രൂശീകരണം', 'മത്തായി 27 വായിക്കുക. യേശു പീലാത്തോസിന്റെ മുമ്പിൽ ശിക്ഷിക്കപ്പെടുകയും, പരിഹസിക്കപ്പെടുകയും, കുറ്റവാളികളുടെ നടുവിൽ ക്രൂശിക്കപ്പെടുകയും, പാപികൾക്കായി ദൈവത്തിന്റെ കോപം വഹിക്കുകയും ചെയ്യുന്നു. അന്ധകാരം ഭൂമിയെ മൂടുന്നു, നമ്മുടെ സ്ഥാനത്ത് ഉപേക്ഷിക്കപ്പെട്ടവനായി അവൻ നിലവിളിക്കുന്നു, ദൈവികനീതിയെ തൃപ്തിപ്പെടുത്തുന്നു. അവന്റെ മരണത്തിൽ ദൈവാലയത്തിന്റെ തിരശ്ശീല കീറുന്നു, ദൈവത്തിലേക്കുള്ള പ്രവേശനം തുറക്കുന്നു, ഭൂമി കുലുങ്ങുന്നു. അവൻ കടം വാങ്ങിയ ഒരു കല്ലറയിൽ അടക്കപ്പെടുന്നു, അത് മുദ്രവെച്ച് കാവൽ ഏർപ്പെടുത്തുന്നു. വിശ്വസിക്കുന്ന എല്ലാവർക്കുമായി പകരംനിൽക്കുന്ന പ്രായശ്ചിത്തം പൂർത്തിയാകുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0100000-e29b-41d4-a716-446655440029', 'hi', 'मत्ती 28: पुनरुत्थान और महान आज्ञा', 'मत्ती 28 पढ़ें। पहले दिन कब्र खाली है, और स्वर्गदूत घोषणा करता है कि यीशु जैसा उसने कहा था वैसा ही जी उठा है, और पाप तथा मृत्यु पर विजय पा ली है। जी उठा हुआ मसीह प्रकट होकर भय को दूर करते और अपने शारीरिक पुनरुत्थान की पुष्टि करते हैं, जो हमारी आशा का कोनेवाला पत्थर है। वह स्वर्ग और पृथ्वी पर सब अधिकार का दावा करते और अपने चेलों को सब जातियों को चेला बनाने का आदेश देते हैं, बपतिस्मा देते और शिक्षा देते हुए, इस प्रतिज्ञा के साथ कि वह सदा उनके साथ बने रहेंगे।', 'मसीह का जीवन'),
  ('d0100000-e29b-41d4-a716-446655440029', 'ml', 'മത്തായി 28: പുനരുത്ഥാനവും മഹാനിയോഗവും', 'മത്തായി 28 വായിക്കുക. ഒന്നാം ദിവസം കല്ലറ ശൂന്യമായി നിൽക്കുന്നു, യേശു താൻ പറഞ്ഞതുപോലെ ഉയിർത്തെഴുന്നേറ്റിരിക്കുന്നുവെന്നും പാപത്തെയും മരണത്തെയും ജയിച്ചിരിക്കുന്നുവെന്നും ദൂതൻ അറിയിക്കുന്നു. ഉയിർത്ത ക്രിസ്തു പ്രത്യക്ഷപ്പെട്ട് ഭയം നീക്കുകയും, നമ്മുടെ പ്രത്യാശയുടെ മൂലക്കല്ലായ തന്റെ ശാരീരിക പുനരുത്ഥാനം സ്ഥിരീകരിക്കുകയും ചെയ്യുന്നു. അവൻ സ്വർഗത്തിലും ഭൂമിയിലുമുള്ള സകല അധികാരവും അവകാശപ്പെടുകയും, സ്നാനം നൽകിയും ഉപദേശിച്ചും സകല ജാതികളെയും ശിഷ്യരാക്കാൻ തന്റെ ശിഷ്യന്മാരോട് നിയോഗിക്കുകയും ചെയ്യുന്നു, താൻ എന്നേക്കും അവരോടുകൂടെ വസിക്കുമെന്ന വാഗ്ദാനത്തോടെ.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440001', 'hi', 'मरकुस 1: यीशु मसीह के सुसमाचार का आरंभ', 'मरकुस 1 पढ़ें। मरकुस पूरी गति से आरंभ करता है: यूहन्ना बपतिस्मा देनेवाला मार्ग तैयार करता है, यीशु बपतिस्मा लेते हैं और पिता द्वारा सम्मानित होते हैं, आत्मा उतरता है, और वे परीक्षा पर विजय पाते हैं। वे अपनी सेवकाई का आरंभ यह प्रचार करते हुए करते हैं, ''पश्चाताप करो और सुसमाचार पर विश्वास करो,'' अपने पहले चेलों को बुलाते हैं, दुष्टात्माओं को निकालते हैं, और बीमारों को चंगा करते हैं। पहले ही पद से यीशु मसीह, परमेश्वर के पुत्र घोषित किए जाते हैं, जिनका अधिकारपूर्ण वचन पश्चाताप और विश्वास की माँग करता है।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440001', 'ml', 'മര്‍ക്കൊസ് 1: യേശുക്രിസ്തുവിന്റെ സുവിശേഷത്തിന്റെ ആരംഭം', 'മര്‍ക്കൊസ് 1 വായിക്കുക. മര്‍ക്കൊസ് പൂര്‍ണ്ണവേഗത്തില്‍ ആരംഭിക്കുന്നു: യോഹന്നാന്‍ സ്നാപകന്‍ വഴിയൊരുക്കുന്നു, യേശു സ്നാനമേല്‍ക്കുകയും പിതാവിനാല്‍ അംഗീകരിക്കപ്പെടുകയും ചെയ്യുന്നു, ആത്മാവ് ഇറങ്ങിവരുന്നു, അവന്‍ പരീക്ഷയെ ജയിക്കുന്നു. ''മാനസാന്തരപ്പെട്ടു സുവിശേഷത്തില്‍ വിശ്വസിക്കുവിന്‍'' എന്നു പ്രസംഗിച്ചുകൊണ്ട് അവന്‍ തന്റെ ശുശ്രൂഷ ആരംഭിക്കുന്നു, ആദ്യ ശിഷ്യന്മാരെ വിളിക്കുന്നു, ദുരാത്മാക്കളെ പുറത്താക്കുന്നു, രോഗികളെ സൗഖ്യമാക്കുന്നു. ആദ്യ വാക്യം മുതല്‍ യേശു ക്രിസ്തു, ദൈവപുത്രന്‍ എന്നു പ്രഖ്യാപിക്കപ്പെടുന്നു; അവന്റെ അധികാരമുള്ള വചനം മാനസാന്തരവും വിശ്വാസവും ആവശ്യപ്പെടുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440002', 'hi', 'मरकुस 2: पापों को क्षमा करने का अधिकार', 'मरकुस 2 पढ़ें। यीशु एक लकवे के मारे हुए को चंगा करते हैं ताकि यह प्रमाणित करें कि पृथ्वी पर पापों को क्षमा करने का अधिकार उनके पास है, इस प्रकार अपनी ईश्वरीय पहचान प्रकट करते हैं। वे लेवी चुंगी लेनेवाले को बुलाते हैं, यह घोषणा करते हुए कि वे धर्मियों के लिए नहीं, परन्तु पापियों को बुलाने आए हैं। उपवास और सब्त के विषय में उठे प्रश्न दिखाते हैं कि पुरानी रीतियाँ उस नई वास्तविकता को नहीं समा सकतीं जो वे लाते हैं। उद्धार उनका वरदान है उनके लिए जो अपनी आवश्यकता को जानते हैं, न कि आत्मनिर्भर लोगों के लिए।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440002', 'ml', 'മര്‍ക്കൊസ് 2: പാപങ്ങള്‍ ക്ഷമിക്കുവാനുള്ള അധികാരം', 'മര്‍ക്കൊസ് 2 വായിക്കുക. ഭൂമിയില്‍ പാപങ്ങള്‍ ക്ഷമിക്കുവാന്‍ തനിക്ക് അധികാരമുണ്ടെന്നു തെളിയിക്കാന്‍ യേശു ഒരു പക്ഷവാതക്കാരനെ സൗഖ്യമാക്കി, തന്റെ ദൈവിക സ്വരൂപം വെളിപ്പെടുത്തുന്നു. ചുങ്കക്കാരനായ ലേവിയെ വിളിച്ച്, താന്‍ നീതിമാന്മാരെയല്ല പാപികളെ വിളിക്കാന്‍ വന്നു എന്നു പ്രഖ്യാപിക്കുന്നു. ഉപവാസത്തെയും ശബ്ബത്തിനെയും കുറിച്ചുള്ള ചോദ്യങ്ങള്‍ കാണിക്കുന്നത്, അവന്‍ കൊണ്ടുവരുന്ന പുതിയ യാഥാര്‍ത്ഥ്യത്തെ പഴയ രൂപങ്ങള്‍ക്ക് ഉള്‍ക്കൊള്ളാനാവില്ല എന്നാണ്. രക്ഷ സ്വയംപര്യാപ്തര്‍ക്കല്ല, തങ്ങളുടെ ആവശ്യം അറിയുന്നവര്‍ക്ക് അവന്‍ നല്‍കുന്ന ദാനമാണ്.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440003', 'hi', 'मरकुस 3: सब्त का प्रभु और उसका नया परिवार', 'मरकुस 3 पढ़ें। यीशु सब्त के दिन चंगा करते हैं, उन कठोर हृदयों को उजागर करते हुए जो दया से अधिक परंपरा को महत्व देते हैं। वे बारहों को नियुक्त करते हैं कि वे उनके साथ रहें और प्रचार करें। शैतान की सहायता से दुष्टात्माओं को निकालने का आरोप लगाए जाने पर, वे पवित्र आत्मा के विरुद्ध निन्दा की चेतावनी देते हैं—जो मसीह के प्रति आत्मा की गवाही का निरंतर, अपश्चातापी अस्वीकार है। वे अपने सच्चे परिवार को उन लोगों के रूप में परिभाषित करते हैं जो परमेश्वर की इच्छा पूरी करते हैं, अपनेपन को रक्त-संबंध के बजाय विश्वास और आज्ञाकारिता के चारों ओर पुनः रचते हुए।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440003', 'ml', 'മര്‍ക്കൊസ് 3: ശബ്ബത്തിന്റെ കര്‍ത്താവും അവന്റെ പുതിയ കുടുംബവും', 'മര്‍ക്കൊസ് 3 വായിക്കുക. കരുണയെക്കാള്‍ പാരമ്പര്യത്തെ വിലമതിക്കുന്ന കഠിനഹൃദയങ്ങളെ വെളിപ്പെടുത്തിക്കൊണ്ട് യേശു ശബ്ബത്തുനാളില്‍ സൗഖ്യമാക്കുന്നു. തന്നോടുകൂടെ ഇരിക്കാനും പ്രസംഗിക്കാനും അവന്‍ പന്ത്രണ്ടുപേരെ നിയമിക്കുന്നു. സാത്താന്റെ സഹായത്താല്‍ ദുരാത്മാക്കളെ പുറത്താക്കുന്നു എന്ന് ആരോപിക്കപ്പെട്ടപ്പോള്‍, പരിശുദ്ധാത്മാവിനെതിരായ ദൂഷണത്തെക്കുറിച്ച് അവന്‍ മുന്നറിയിപ്പു നല്‍കുന്നു—അതായത് ക്രിസ്തുവിനെക്കുറിച്ചുള്ള ആത്മാവിന്റെ സാക്ഷ്യത്തെ നിരന്തരം, അനുതാപമില്ലാതെ തള്ളിക്കളയുന്നത്. ദൈവഹിതം ചെയ്യുന്നവരെ അവന്‍ തന്റെ യഥാര്‍ത്ഥ കുടുംബമായി നിര്‍വചിക്കുന്നു, രക്തബന്ധത്തിനു പകരം വിശ്വാസത്തിന്റെയും അനുസരണത്തിന്റെയും ചുറ്റും ഉള്‍ച്ചേര്‍ച്ചയെ പുനര്‍നിര്‍വചിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440004', 'hi', 'मरकुस 4:1-34: राज्य के दृष्टान्त', 'मरकुस 4:1-34 पढ़ें। यीशु दृष्टान्तों में शिक्षा देते हैं: बोनेवाला वचन बिखेरता है, और चार प्रकार की भूमि प्रकट करती है कि हृदय वचन के प्रति कैसे प्रतिक्रिया करते हैं। दीपक, बढ़ता हुआ बीज, और राई का दाना दिखाते हैं कि परमेश्वर का राज्य चुपचाप परन्तु निश्चित रूप से, मानवीय प्रयास के बजाय उसकी सामर्थ्य से आगे बढ़ता है। ये दृष्टान्त ग्रहणशील हृदयों पर सत्य प्रकट करते हैं और कठोर हृदयों से इसे छिपाते हैं, हमें बुलाते हुए कि हम सुनें, ग्रहण करें, और सच्चे विश्वास में फल लाएँ।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440004', 'ml', 'മര്‍ക്കൊസ് 4:1-34: രാജ്യത്തിന്റെ ഉപമകള്‍', 'മര്‍ക്കൊസ് 4:1-34 വായിക്കുക. യേശു ഉപമകളിലൂടെ ഉപദേശിക്കുന്നു: വിതയ്ക്കുന്നവന്‍ വചനം വിതയ്ക്കുന്നു, നാലുതരം നിലങ്ങള്‍ ഹൃദയങ്ങള്‍ വചനത്തോട് എങ്ങനെ പ്രതികരിക്കുന്നു എന്നു വെളിപ്പെടുത്തുന്നു. വിളക്കും വളരുന്ന വിത്തും കടുകുമണിയും കാണിക്കുന്നത്, ദൈവരാജ്യം മനുഷ്യപ്രയത്നത്താലല്ല, അവന്റെ ശക്തിയാല്‍ നിശ്ശബ്ദമായെങ്കിലും ഉറപ്പായി മുന്നേറുന്നു എന്നാണ്. ഈ ഉപമകള്‍ ഗ്രഹണശേഷിയുള്ളവര്‍ക്കു സത്യം വെളിപ്പെടുത്തുകയും കഠിനഹൃദയര്‍ക്കു അതു മറയ്ക്കുകയും ചെയ്യുന്നു; കേള്‍ക്കാനും സ്വീകരിക്കാനും യഥാര്‍ത്ഥ വിശ്വാസത്തില്‍ ഫലം പുറപ്പെടുവിക്കാനും അവ നമ്മെ വിളിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440005', 'hi', 'मरकुस 4:35-41: यीशु तूफान को शांत करते हैं', 'मरकुस 4:35-41 पढ़ें। जब एक प्रचंड तूफान नाव को डुबाने की धमकी देता है, यीशु सो रहे होते हैं, फिर उठकर हवा और लहरों को डाँटकर पूर्ण शांति में बदल देते हैं। भयभीत चेले पूछते हैं, ''यह कौन है, कि हवा और समुद्र भी इसकी आज्ञा मानते हैं?'' उत्तर स्पष्ट है: वे सृष्टि के प्रभु हैं, वह परमेश्वर जो समुद्रों को आज्ञा देता है। उनका भय दुर्बल विश्वास को उजागर करता है, फिर भी उनकी सामर्थ्य उन पर गहरे भरोसे के लिए आमंत्रित करती है।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440005', 'ml', 'മര്‍ക്കൊസ് 4:35-41: യേശു കൊടുങ്കാറ്റിനെ ശാന്തമാക്കുന്നു', 'മര്‍ക്കൊസ് 4:35-41 വായിക്കുക. ഒരു കൊടുങ്കാറ്റ് വള്ളത്തെ മുക്കിക്കളയാന്‍ ഭീഷണിയാകുമ്പോള്‍, യേശു ഉറങ്ങുകയായിരുന്നു; പിന്നെ എഴുന്നേറ്റ് കാറ്റിനെയും തിരകളെയും ശാസിച്ച് പൂര്‍ണ്ണ ശാന്തതയിലേക്കു മാറ്റുന്നു. ഭയന്നുവിറച്ച ശിഷ്യന്മാര്‍ ചോദിക്കുന്നു, ''ഇവന്‍ ആര്‍, കാറ്റും കടലും ഇവനെ അനുസരിക്കുന്നുവല്ലോ?'' ഉത്തരം വ്യക്തമാണ്: അവന്‍ സൃഷ്ടിയുടെ കര്‍ത്താവ്, കടലുകളോട് കല്‍പിക്കുന്ന ദൈവം. അവരുടെ ഭയം ദുര്‍ബലമായ വിശ്വാസത്തെ വെളിപ്പെടുത്തുന്നു; എങ്കിലും അവന്റെ ശക്തി അവനില്‍ ആഴമേറിയ ആശ്രയത്തിലേക്കു ക്ഷണിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440006', 'hi', 'मरकुस 5:1-20: गिरासेनी दुष्टात्मा-ग्रस्त की मुक्ति', 'मरकुस 5:1-20 पढ़ें। यीशु अन्यजातियों के क्षेत्र में पार जाते हैं और एक मनुष्य का सामना करते हैं जो दुष्टात्माओं की सेना से बँधा हुआ, वश में न आनेवाला और सताया हुआ है। एक ही वचन से वे उसे छुड़ाते हैं, और वह मनुष्य वस्त्र पहने और सचेत मन से पाया जाता है। नगरवासी भयभीत होकर यीशु से चले जाने की विनती करते हैं, परन्तु वे चंगे हुए मनुष्य को घर भेजते हैं कि वह प्रचार करे कि प्रभु ने उसके लिए कैसे बड़े काम किए हैं। बुराई पर मसीह का अधिकार अन्यजातियों तक भी पहुँचता है।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440006', 'ml', 'മര്‍ക്കൊസ് 5:1-20: ഗെരസേന്യ ഭൂതഗ്രസ്തന്റെ വിടുതല്‍', 'മര്‍ക്കൊസ് 5:1-20 വായിക്കുക. യേശു ജാതികളുടെ ദേശത്തേക്കു കടന്ന്, ഒരു ലെഗ്യോന്‍ ഭൂതങ്ങളാല്‍ അടിമയാക്കപ്പെട്ട, ഇണക്കാനാവാത്ത, പീഡിതനായ ഒരു മനുഷ്യനെ നേരിടുന്നു. ഒരു വാക്കാല്‍ അവനെ വിടുവിക്കുന്നു, ആ മനുഷ്യന്‍ വസ്ത്രം ധരിച്ച് സുബോധത്തോടെ കാണപ്പെടുന്നു. പട്ടണക്കാര്‍ ഭയന്ന് യേശുവിനോട് വിട്ടുപോകാന്‍ അപേക്ഷിക്കുന്നു, എന്നാല്‍ കര്‍ത്താവ് തനിക്കായി എത്ര വലിയ കാര്യങ്ങള്‍ ചെയ്തു എന്നു പ്രസിദ്ധമാക്കാന്‍ അവന്‍ സൗഖ്യമായ മനുഷ്യനെ വീട്ടിലേക്കു അയയ്ക്കുന്നു. തിന്മയ്ക്കുമേലുള്ള ക്രിസ്തുവിന്റെ അധികാരം ജാതികളിലേക്കും വ്യാപിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440007', 'hi', 'मरकुस 5:21-43: वह विश्वास जो यीशु को छूता है', 'मरकुस 5:21-43 पढ़ें। दो हताश लोग यीशु से मिलते हैं: एक आराधनालय का सरदार जिसकी बेटी मर रही है, और एक स्त्री जो बारह वर्ष से लहू बहने से पीड़ित है। वह विश्वास से उनके वस्त्र को छूती है और चंगी हो जाती है; वे उससे कहते हैं, ''तेरे विश्वास ने तुझे चंगा किया है।'' यद्यपि लड़की मर जाती है, यीशु उसे जिलाते हैं, रोग और मृत्यु पर भी अपनी सामर्थ्य दिखाते हुए। वे उस विश्वास का आदर करते हैं जो असहायता में उनके पास दौड़ता है, प्रतिष्ठित और बहिष्कृत दोनों से करुणा और सामर्थ्य के साथ मिलते हुए।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440007', 'ml', 'മര്‍ക്കൊസ് 5:21-43: യേശുവിനെ സ്പര്‍ശിക്കുന്ന വിശ്വാസം', 'മര്‍ക്കൊസ് 5:21-43 വായിക്കുക. രണ്ടു നിരാശിതര്‍ യേശുവിനെ കണ്ടുമുട്ടുന്നു: മകള്‍ മരണാസന്നയായ ഒരു പള്ളിപ്രമാണിയും, പന്ത്രണ്ടു വര്‍ഷം രക്തസ്രാവമുള്ള ഒരു സ്ത്രീയും. അവള്‍ വിശ്വാസത്തോടെ അവന്റെ വസ്ത്രം തൊട്ടു സൗഖ്യമാകുന്നു; ''നിന്റെ വിശ്വാസം നിന്നെ രക്ഷിച്ചിരിക്കുന്നു'' എന്ന് അവന്‍ അവളോടു പറയുന്നു. ബാലിക മരിച്ചെങ്കിലും, യേശു അവളെ ഉയിര്‍പ്പിക്കുന്നു, രോഗത്തിന്മേലും മരണത്തിന്മേലും തന്നെ തന്റെ ശക്തി കാണിക്കുന്നു. നിസ്സഹായതയില്‍ തന്റെ അടുക്കല്‍ ഓടിയെത്തുന്ന വിശ്വാസത്തെ അവന്‍ ആദരിക്കുന്നു, പ്രമുഖനെയും പുറന്തള്ളപ്പെട്ടവളെയും കരുണയോടും ശക്തിയോടും കൂടെ കണ്ടുമുട്ടുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440008', 'hi', 'मरकुस 6:1-29: अस्वीकार, मिशन, और एक शहीद', 'मरकुस 6:1-29 पढ़ें। यीशु अपने ही नगर में अपमानित होते हैं, जहाँ अविश्वास उन कामों को सीमित कर देता है जो वे उनके बीच करते हैं। वे बारहों को दो-दो करके भेजते हैं कि वे पश्चाताप का प्रचार करें और चंगा करें, अपनी कलीसिया को मिशन के लिए सुसज्जित करते हुए। फिर मरकुस यूहन्ना बपतिस्मा देनेवाले की मृत्यु का वर्णन करता है, जिसे विश्वासयोग्य गवाही के कारण हेरोदेस ने सिर कटवाकर मार डाला। परमेश्वर के सत्य के प्रति विश्वासयोग्यता अस्वीकार और यहाँ तक कि मृत्यु भी ला सकती है, फिर भी सुसमाचार आगे बढ़ता है और राज्य के संदेशवाहक आज्ञाकारिता में आगे चलते हैं।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440008', 'ml', 'മര്‍ക്കൊസ് 6:1-29: തിരസ്കരണം, ദൗത്യം, ഒരു രക്തസാക്ഷി', 'മര്‍ക്കൊസ് 6:1-29 വായിക്കുക. യേശു സ്വന്തം പട്ടണത്തില്‍ അവമാനിക്കപ്പെടുന്നു, അവിടെ അവിശ്വാസം അവന്‍ അവരുടെ ഇടയില്‍ ചെയ്യുന്ന പ്രവൃത്തികളെ പരിമിതപ്പെടുത്തുന്നു. മാനസാന്തരം പ്രസംഗിക്കാനും സൗഖ്യമാക്കാനും അവന്‍ പന്ത്രണ്ടുപേരെ ഈരണ്ടായി അയയ്ക്കുന്നു, ദൗത്യത്തിനായി തന്റെ സഭയെ ഒരുക്കുന്നു. പിന്നെ മര്‍ക്കൊസ്, വിശ്വസ്ത സാക്ഷ്യത്തിന്റെ പേരില്‍ ഹെരോദാവിനാല്‍ ശിരച്ഛേദം ചെയ്യപ്പെട്ട യോഹന്നാന്‍ സ്നാപകന്റെ മരണം വിവരിക്കുന്നു. ദൈവസത്യത്തോടുള്ള വിശ്വസ്തത തിരസ്കരണവും മരണവുംവരെ കൊണ്ടുവന്നേക്കാം; എങ്കിലും സുവിശേഷം മുന്നേറുന്നു, രാജ്യത്തിന്റെ ദൂതന്മാര്‍ അനുസരണത്തില്‍ മുന്നോട്ടു പോകുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440009', 'hi', 'मरकुस 6:30-56: वह चरवाहा जो खिलाता और जल पर चलता है', 'मरकुस 6:30-56 पढ़ें। बिना चरवाहे की भेड़ों के समान भीड़ पर करुणा से भरकर, यीशु उन्हें शिक्षा देते हैं और पाँच रोटियों और दो मछलियों से पाँच हजार को खिलाते हैं, और बारह टोकरियाँ बच जाती हैं। फिर वे समुद्र पर चलते हैं और हवा को शांत करते हैं, यह कहते हुए, ''मैं हूँ; मत डरो।'' ये चिन्ह उन्हें सच्चे चरवाहे और ईश्वरीय ''मैं हूँ'' के रूप में प्रकट करते हैं, वह जो प्रचुरता से प्रदान करता और अपने लोगों के लिए सृष्टि पर शासन करता है।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440009', 'ml', 'മര്‍ക്കൊസ് 6:30-56: പോറ്റുകയും വെള്ളത്തിന്മേല്‍ നടക്കുകയും ചെയ്യുന്ന ഇടയന്‍', 'മര്‍ക്കൊസ് 6:30-56 വായിക്കുക. ഇടയനില്ലാത്ത ആടുകളെപ്പോലെയുള്ള പുരുഷാരത്തോട് മനസ്സലിഞ്ഞ്, യേശു അവരെ ഉപദേശിക്കുകയും അഞ്ച് അപ്പവും രണ്ടു മീനുംകൊണ്ട് അയ്യായിരംപേരെ പോറ്റുകയും ചെയ്യുന്നു, പന്ത്രണ്ടു കൊട്ട ശേഷിക്കുന്നു. പിന്നെ അവന്‍ കടലിന്മേല്‍ നടന്ന്, ''ഞാന്‍ ആകുന്നു; ഭയപ്പെടേണ്ടാ'' എന്നു പറഞ്ഞ് കാറ്റിനെ ശാന്തമാക്കുന്നു. ഈ അടയാളങ്ങള്‍ അവനെ യഥാര്‍ത്ഥ ഇടയനായും ദൈവിക ''ഞാന്‍ ആകുന്നു'' എന്നവനായും വെളിപ്പെടുത്തുന്നു—സമൃദ്ധമായി നല്‍കുകയും തന്റെ ജനത്തിനായി സൃഷ്ടിയെ ഭരിക്കുകയും ചെയ്യുന്നവന്‍.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440010', 'hi', 'मरकुस 7: शुद्ध हृदय और एक अन्यजाति का विश्वास', 'मरकुस 7 पढ़ें। यीशु फरीसियों को डाँटते हैं कि उन्होंने परमेश्वर की आज्ञा से ऊपर मानवीय परंपरा को रखा, और यह उजागर करते हैं कि अशुद्धता पापमय हृदय से निकलती है, न कि बाहरी रीतियों से। वे सब भोजनों को शुद्ध घोषित करते हैं, सुसमाचार के इस्राएल से परे पहुँचने का पूर्वाभास देते हुए। एक सुरुफिनीकी स्त्री का नम्र, निरंतर विश्वास उसकी बेटी के लिए चंगाई जीतता है, और एक बहरा मनुष्य चंगा किया जाता है। मसीह सच्ची समस्या—भ्रष्ट हृदय—का निदान करते हैं, और हर जाति के विश्वास का स्वागत करते हैं जो उनके पास आती है।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440010', 'ml', 'മര്‍ക്കൊസ് 7: ശുദ്ധഹൃദയങ്ങളും ഒരു ജാതിക്കാരിയുടെ വിശ്വാസവും', 'മര്‍ക്കൊസ് 7 വായിക്കുക. ദൈവകല്‍പനയ്ക്കു മീതെ മനുഷ്യപാരമ്പര്യത്തെ ഉയര്‍ത്തിയതിന് യേശു പരീശന്മാരെ ശാസിക്കുകയും, അശുദ്ധി ബാഹ്യാചാരങ്ങളില്‍നിന്നല്ല പാപമയമായ ഹൃദയത്തില്‍നിന്നു പുറപ്പെടുന്നു എന്നു വെളിപ്പെടുത്തുകയും ചെയ്യുന്നു. എല്ലാ ഭക്ഷണങ്ങളെയും ശുദ്ധമെന്നു പ്രഖ്യാപിച്ച്, സുവിശേഷം യിസ്രായേലിനപ്പുറം എത്തുന്നതിന്റെ മുന്നോടി നല്‍കുന്നു. ഒരു സുറോഫൊയ്നീക്യ സ്ത്രീയുടെ വിനയമുള്ള, സ്ഥിരതയുള്ള വിശ്വാസം മകള്‍ക്കു സൗഖ്യം നേടിക്കൊടുക്കുന്നു, ഒരു ബധിരന്‍ സൗഖ്യമാകുന്നു. ക്രിസ്തു യഥാര്‍ത്ഥ പ്രശ്നം—ദുഷിച്ച ഹൃദയം—കണ്ടെത്തുകയും, തന്റെ അടുക്കല്‍ വരുന്ന ഏതു ജാതിയില്‍നിന്നുമുള്ള വിശ്വാസത്തെ സ്വാഗതം ചെയ്യുകയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440011', 'hi', 'मरकुस 8:1-21: पर्याप्त रोटी और अंधे हृदय', 'मरकुस 8:1-21 पढ़ें। यीशु फिर से एक भूखी भीड़ पर करुणा करते हैं और चार हजार को खिलाते हैं, यहूदी और अन्यजाति दोनों के लिए अपनी पर्याप्तता प्रदर्शित करते हुए। फरीसी एक चिन्ह की माँग करते हैं, विश्वास करने से इनकार करते हुए; यीशु चेलों को उनके कठोर अविश्वास के खमीर से सावधान करते हैं। बारहों भी समझने में चूक जाते हैं कि वे कौन हैं, शारीरिक रोटी पर केंद्रित रहते हुए। यह भाग उजागर करता है कि कितनी सहजता से हृदय मसीह की महिमा से चूक जाता है, और हमें उस आत्मिक दृष्टि के लिए बुलाता है जो उन्हें पहचानती और उन पर भरोसा करती है।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440011', 'ml', 'മര്‍ക്കൊസ് 8:1-21: മതിയായ അപ്പവും അന്ധഹൃദയങ്ങളും', 'മര്‍ക്കൊസ് 8:1-21 വായിക്കുക. യേശു വീണ്ടും വിശന്നിരുന്ന പുരുഷാരത്തോട് മനസ്സലിഞ്ഞ് നാലായിരംപേരെ പോറ്റി, യെഹൂദനും ജാതിക്കാരനും വേണ്ടിയുള്ള തന്റെ പര്യാപ്തത പ്രദര്‍ശിപ്പിക്കുന്നു. പരീശന്മാര്‍ വിശ്വസിക്കാന്‍ കൂട്ടാക്കാതെ ഒരു അടയാളം ആവശ്യപ്പെടുന്നു; അവരുടെ കഠിനമായ അവിശ്വാസത്തിന്റെ പുളിമാവിനെക്കുറിച്ച് യേശു ശിഷ്യന്മാര്‍ക്കു മുന്നറിയിപ്പു നല്‍കുന്നു. പന്ത്രണ്ടുപേര്‍പോലും ഭൗതിക അപ്പത്തില്‍ ശ്രദ്ധയൂന്നി, അവന്‍ ആരെന്നു ഗ്രഹിക്കാതെ പോകുന്നു. ഹൃദയം എത്ര എളുപ്പത്തില്‍ ക്രിസ്തുവിന്റെ മഹത്വം നഷ്ടപ്പെടുത്തുന്നു എന്ന് ഈ ഭാഗം വെളിപ്പെടുത്തുകയും, അവനെ തിരിച്ചറിഞ്ഞ് ആശ്രയിക്കുന്ന ആത്മീയ ദൃഷ്ടിയിലേക്കു നമ്മെ വിളിക്കുകയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440012', 'hi', 'मरकुस 8:22-38: तुम मुझे क्या कहते हो?', 'मरकुस 8:22-38 पढ़ें। दो चरणों में चंगा किया गया एक अंधा मनुष्य चेलों की उभरती हुई दृष्टि को प्रतिबिंबित करता है। कैसरिया फिलिप्पी में पतरस अंगीकार करता है, ''आप मसीह हैं''—सुसमाचार का केंद्रबिंदु। फिर यीशु अपनी पहली दुःखभोग की भविष्यवाणी करते हैं: मनुष्य के पुत्र को अवश्य दुःख उठाना, मरना, और जी उठना है। वे क्रूस के प्रति पतरस के विरोध को डाँटते हैं और उनका अनुसरण करनेवाले सब को बुलाते हैं कि वे अपने आप का इन्कार करें, अपना क्रूस उठाएँ, और अपना प्राण खोकर बचाएँ। सच्ची शिष्यता क्रूस पर चढ़ाए गए मसीह को अपनाती है।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440012', 'ml', 'മര്‍ക്കൊസ് 8:22-38: ഞാന്‍ ആരെന്നു നിങ്ങള്‍ പറയുന്നു?', 'മര്‍ക്കൊസ് 8:22-38 വായിക്കുക. രണ്ടു ഘട്ടങ്ങളിലായി സൗഖ്യമാക്കപ്പെട്ട ഒരു അന്ധന്‍ ശിഷ്യന്മാരുടെ ഉദിച്ചുവരുന്ന ഉള്‍ക്കാഴ്ചയെ പ്രതിഫലിപ്പിക്കുന്നു. കൈസര്യാ ഫിലിപ്പിയില്‍ പത്രൊസ് ഏറ്റുപറയുന്നു, ''നീ ക്രിസ്തു ആകുന്നു''—സുവിശേഷത്തിന്റെ കേന്ദ്രബിന്ദു. പിന്നെ യേശു തന്റെ ആദ്യ കഷ്ടാനുഭവ പ്രവചനം നടത്തുന്നു: മനുഷ്യപുത്രന്‍ കഷ്ടം അനുഭവിക്കുകയും മരിക്കുകയും ഉയിര്‍ത്തെഴുന്നേല്‍ക്കുകയും വേണം. ക്രൂശിനോടുള്ള പത്രൊസിന്റെ എതിര്‍പ്പിനെ അവന്‍ ശാസിക്കുകയും, തന്നെ അനുഗമിക്കുന്ന എല്ലാവരെയും തങ്ങളെത്തന്നെ ത്യജിച്ച്, ക്രൂശ് എടുത്ത്, ജീവനെ നഷ്ടപ്പെടുത്തി രക്ഷിക്കാന്‍ വിളിക്കുകയും ചെയ്യുന്നു. യഥാര്‍ത്ഥ ശിഷ്യത്വം ക്രൂശിക്കപ്പെട്ട ക്രിസ്തുവിനെ ആശ്ലേഷിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440013', 'hi', 'मरकुस 9:1-29: रूपान्तरण और वह विश्वास जो सहायता के लिए पुकारता है', 'मरकुस 9:1-29 पढ़ें। पहाड़ पर यीशु का रूपान्तरण होता है, उनकी महिमा अनावृत होती है, और पिता आज्ञा देते हैं, ''यह मेरा प्रिय पुत्र है; इसकी सुनो।'' मूसा और एलिय्याह गवाही देते हैं कि व्यवस्था और भविष्यवक्ता उसी में पूरे होते हैं। नीचे उतरकर, यीशु एक लड़के को छुड़ाते हैं जिसे उनके चेले मुक्त नहीं कर सके, उसके पिता से यह सच्ची प्रार्थना खींचते हुए, ''मैं विश्वास करता हूँ; मेरे अविश्वास का उपाय कर!'' मसीह की ईश्वरीय महिमा और बुराई पर उनकी सामर्थ्य हमारे दुर्बल फिर भी सच्चे, निर्भर विश्वास से मिलती है।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440013', 'ml', 'മര്‍ക്കൊസ് 9:1-29: രൂപാന്തരവും സഹായത്തിനായി നിലവിളിക്കുന്ന വിശ്വാസവും', 'മര്‍ക്കൊസ് 9:1-29 വായിക്കുക. മലയില്‍ യേശു രൂപാന്തരപ്പെടുന്നു, അവന്റെ മഹത്വം വെളിപ്പെടുന്നു, പിതാവ് കല്‍പിക്കുന്നു, ''ഇവന്‍ എന്റെ പ്രിയപുത്രന്‍; ഇവന്‍ പറയുന്നതു കേള്‍ക്കുവിന്‍.'' ന്യായപ്രമാണവും പ്രവാചകന്മാരും അവനില്‍ നിവൃത്തിയാകുന്നു എന്ന് മോശെയും ഏലിയാവും സാക്ഷ്യപ്പെടുത്തുന്നു. താഴെയിറങ്ങി, ശിഷ്യന്മാര്‍ക്കു വിടുവിക്കാന്‍ കഴിയാത്ത ഒരു ബാലനെ യേശു വിടുവിക്കുന്നു, ആ പിതാവില്‍നിന്ന് ''ഞാന്‍ വിശ്വസിക്കുന്നു; എന്റെ അവിശ്വാസത്തിന് സഹായിക്കണമേ!'' എന്ന ആത്മാര്‍ത്ഥ പ്രാര്‍ത്ഥന വരുത്തുന്നു. ക്രിസ്തുവിന്റെ ദൈവിക മഹത്വവും തിന്മയ്ക്കുമേലുള്ള അവന്റെ ശക്തിയും നമ്മുടെ ദുര്‍ബലമെങ്കിലും ആത്മാര്‍ത്ഥവും ആശ്രയമുള്ളതുമായ വിശ്വാസത്തെ കണ്ടുമുട്ടുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440014', 'hi', 'मरकुस 9:30-50: राज्य में सच्ची महानता', 'मरकुस 9:30-50 पढ़ें। यीशु फिर से अपनी मृत्यु और पुनरुत्थान की भविष्यवाणी करते हैं, परन्तु चेले इस पर वाद-विवाद करते हैं कि कौन सबसे बड़ा है। वे उनके मूल्यों को उलट देते हैं: महानता का अर्थ है सबसे छोटा और सबका सेवक होना, छोटों का स्वागत वैसे करना जैसे कोई उन्हीं का स्वागत करता है। वे अत्यंत गंभीरता से चेतावनी देते हैं कि किसी को ठोकर न खिलाएँ और उस पाप से बचें जो विनाश की ओर ले जाता है, मूलगामी, निर्णायक पवित्रता का आह्वान करते हुए। शिष्यता मसीह के प्रति सच्ची भक्ति से बहनेवाली नम्र सेवा है।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440014', 'ml', 'മര്‍ക്കൊസ് 9:30-50: രാജ്യത്തിലെ യഥാര്‍ത്ഥ മഹത്വം', 'മര്‍ക്കൊസ് 9:30-50 വായിക്കുക. യേശു വീണ്ടും തന്റെ മരണവും പുനരുത്ഥാനവും മുന്‍കൂട്ടി പറയുന്നു, എന്നാല്‍ ആരാണ് വലിയവന്‍ എന്നു ശിഷ്യന്മാര്‍ തര്‍ക്കിക്കുന്നു. അവന്‍ അവരുടെ മൂല്യങ്ങളെ മറിച്ചിടുന്നു: മഹത്വം എന്നാല്‍ എല്ലാവരിലും ഒടുവിലത്തവനും എല്ലാവരുടെയും ദാസനും ആകുക, ചെറിയവരെ തന്നെ സ്വീകരിക്കുന്നതുപോലെ സ്വീകരിക്കുക. മറ്റുള്ളവര്‍ക്ക് ഇടര്‍ച്ച വരുത്തുന്നതിനെതിരെയും നാശത്തിലേക്കു നയിക്കുന്ന പാപത്തിനെതിരെയും അവന്‍ കഠിനമായ ഗൗരവത്തോടെ മുന്നറിയിപ്പു നല്‍കുന്നു, സമൂലവും നിര്‍ണ്ണായകവുമായ വിശുദ്ധിയിലേക്കു ആഹ്വാനം ചെയ്യുന്നു. ശിഷ്യത്വം ക്രിസ്തുവിനോടുള്ള ആത്മാര്‍ത്ഥ ഭക്തിയില്‍നിന്നു പുറപ്പെടുന്ന വിനയമുള്ള ശുശ്രൂഷയാണ്.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440015', 'hi', 'मरकुस 10: अनुसरण का मूल्य और प्रतिफल', 'मरकुस 10 पढ़ें। यीशु विवाह के लिए परमेश्वर की रचना को बनाए रखते हैं, बच्चों को राज्य-ग्रहणकारी विश्वास के आदर्श के रूप में आशीष देते हैं, और धनी मनुष्य को दिखाते हैं कि कोई भी कर्मों से नहीं बचता—''परमेश्वर से सब कुछ हो सकता है।'' वे तीसरी बार अपनी मृत्यु की भविष्यवाणी करते हैं और शिक्षा देते हैं कि महानता सेवकाई है: मनुष्य का पुत्र आया ''कि बहुतों की छुड़ौती के लिए अपना प्राण दे।'' अंधा बरतिमाई विश्वास से दृष्टि पाता है। उद्धार अनुग्रह है, और यीशु का अनुसरण क्रूस की ओर जानेवाला मार्ग है।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440015', 'ml', 'മര്‍ക്കൊസ് 10: അനുഗമനത്തിന്റെ വിലയും പ്രതിഫലവും', 'മര്‍ക്കൊസ് 10 വായിക്കുക. വിവാഹത്തിനായുള്ള ദൈവത്തിന്റെ രൂപകല്‍പന യേശു ഉയര്‍ത്തിപ്പിടിക്കുന്നു, രാജ്യം സ്വീകരിക്കുന്ന വിശ്വാസത്തിന്റെ മാതൃകയായി കുട്ടികളെ അനുഗ്രഹിക്കുന്നു, ഒരുവനും പ്രവൃത്തികളാല്‍ രക്ഷിക്കപ്പെടുന്നില്ലെന്ന്—''ദൈവത്തിന് സകലവും സാധ്യമാകുന്നു'' എന്ന്—ധനവാനു കാണിച്ചുകൊടുക്കുന്നു. അവന്‍ മൂന്നാം പ്രാവശ്യം തന്റെ മരണം മുന്‍കൂട്ടി പറയുകയും, മഹത്വം ദാസത്വമാണെന്നു പഠിപ്പിക്കുകയും ചെയ്യുന്നു: മനുഷ്യപുത്രന്‍ വന്നത് ''അനേകര്‍ക്കു മറുവിലയായി തന്റെ ജീവനെ നല്‍കുവാന്‍'' ആകുന്നു. അന്ധനായ ബര്‍ത്തിമായി വിശ്വാസത്താല്‍ കാഴ്ച പ്രാപിക്കുന്നു. രക്ഷ കൃപയാണ്, യേശുവിനെ അനുഗമിക്കുന്നതോ ക്രൂശിലേക്കുള്ള വഴിയും.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440016', 'hi', 'मरकुस 11: राजा यरूशलेम में प्रवेश करते हैं', 'मरकुस 11 पढ़ें। यीशु यरूशलेम में बहुप्रतीक्षित राजा के रूप में प्रवेश करते हैं, होशाना से स्वागत किए जाते हुए, फिर भी क्रूस की ओर नम्रता से सवार होते हुए। वे एक निष्फल अंजीर के पेड़ को शाप देते हैं, फलहीन धर्म पर न्याय अधिनियमित करते हुए, और मंदिर को शुद्ध करते हैं, उसे सब जातियों के लिए प्रार्थना का घर के रूप में पुनः प्राप्त करते हुए। जब अधिकारी उनके अधिकार को चुनौती देते हैं, वे उन्हें चुप करा देते हैं। यह विजयी प्रवेश उस चरम सप्ताह को गति देता है जिसमें राजा अपने लोगों के लिए अपना प्राण देगा।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440016', 'ml', 'മര്‍ക്കൊസ് 11: രാജാവ് യെരൂശലേമില്‍ പ്രവേശിക്കുന്നു', 'മര്‍ക്കൊസ് 11 വായിക്കുക. ഹോശന്നയോടെ വാഴ്ത്തപ്പെട്ടുകൊണ്ട്, എങ്കിലും ക്രൂശിലേക്കു താഴ്മയോടെ കയറിക്കൊണ്ട്, യേശു ദീര്‍ഘകാലമായി കാത്തിരുന്ന രാജാവായി യെരൂശലേമില്‍ പ്രവേശിക്കുന്നു. ഫലരഹിതമായ മതത്തിന്മേല്‍ ന്യായവിധി നടപ്പാക്കിക്കൊണ്ട് അവന്‍ ഫലമില്ലാത്ത അത്തിവൃക്ഷത്തെ ശപിക്കുകയും, ദൈവാലയത്തെ സകല ജാതികള്‍ക്കും പ്രാര്‍ത്ഥനാലയമായി തിരികെ പ്രാപിച്ച് അതിനെ ശുദ്ധീകരിക്കുകയും ചെയ്യുന്നു. അധികാരികള്‍ അവന്റെ അധികാരത്തെ വെല്ലുവിളിച്ചപ്പോള്‍, അവന്‍ അവരെ നിശ്ശബ്ദരാക്കുന്നു. രാജാവ് തന്റെ ജനത്തിനായി തന്റെ ജീവനെ വെച്ചുകൊടുക്കുന്ന ആ നിര്‍ണ്ണായക വാരത്തിന് ഈ വിജയപ്രവേശം തുടക്കമിടുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440017', 'hi', 'मरकुस 12: पुत्र, सबसे बड़ी आज्ञा, और विधवा का दान', 'मरकुस 12 पढ़ें। किसानों के दृष्टान्त में यीशु अपने आप को ठुकराए हुए पुत्र और कोने के पत्थर के रूप में पहचानते हैं जिसे परमेश्वर निर्दोष ठहराता है। वे कर और पुनरुत्थान के विषय में जाल का उत्तर ईश्वरीय बुद्धि से देते हैं, पूर्वजों के जीवते परमेश्वर की पुष्टि करते हैं, और सबसे बड़ी आज्ञाओं का नाम लेते हैं: परमेश्वर से पूरी तरह प्रेम करना और अपने पड़ोसी से अपने समान। खोखले धर्म को उजागर करते हुए, वे एक गरीब विधवा के पूरे मन के दान की प्रशंसा करते हैं। परमेश्वर हृदय को देखता है और उसके प्रति पूर्ण रूप से अर्पित प्रेम और भरोसे को बहुमूल्य मानता है।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440017', 'ml', 'മര്‍ക്കൊസ് 12: പുത്രനും ഏറ്റവും വലിയ കല്‍പനയും വിധവയുടെ ദാനവും', 'മര്‍ക്കൊസ് 12 വായിക്കുക. കുടിയാന്മാരുടെ ഉപമയില്‍ യേശു തന്നെത്തന്നെ, ദൈവം നീതീകരിക്കുന്ന തിരസ്കരിക്കപ്പെട്ട പുത്രനായും മൂലക്കല്ലായും തിരിച്ചറിയുന്നു. നികുതിയെയും പുനരുത്ഥാനത്തെയും കുറിച്ചുള്ള കെണികള്‍ക്ക് അവന്‍ ദൈവിക ജ്ഞാനത്തോടെ ഉത്തരം നല്‍കുന്നു, പിതാക്കന്മാരുടെ ജീവനുള്ള ദൈവത്തെ സ്ഥിരീകരിക്കുന്നു, ഏറ്റവും വലിയ കല്‍പനകള്‍ പറയുന്നു: പൂര്‍ണ്ണഹൃദയത്തോടെ ദൈവത്തെയും കൂട്ടുകാരനെ തന്നെപ്പോലെയും സ്നേഹിക്കുക. പൊള്ളയായ മതത്തെ വെളിപ്പെടുത്തി, ഒരു ദരിദ്ര വിധവയുടെ പൂര്‍ണ്ണഹൃദയ ദാനത്തെ അവന്‍ പ്രശംസിക്കുന്നു. ദൈവം ഹൃദയം കാണുന്നു, അവനു പൂര്‍ണ്ണമായി അര്‍പ്പിക്കുന്ന സ്നേഹവും ആശ്രയവും വിലയേറിയതായി കരുതുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440018', 'hi', 'मरकुस 13: मनुष्य के पुत्र के लिए जागते रहना', 'मरकुस 13 पढ़ें। मंदिर के विनाश की भविष्यवाणी करते हुए, यीशु अपने चेलों को अंत से पहले के क्लेश, धोखे, और सताव के लिए तैयार करते हैं। वे वादा करते हैं कि सुसमाचार पहले सब जातियों में प्रचार किया जाना चाहिए और मनुष्य का पुत्र अपने चुने हुओं को इकट्ठा करने के लिए महिमा में लौटेगा। उस दिन या घड़ी को कोई नहीं जानता, इसलिए वे बार-बार आज्ञा देते हैं, ''जागते रहो।'' विश्वासी विश्वासयोग्य, सचेत प्रत्याशा में जीते हैं, मसीह के निश्चित वचन पर भरोसा करते और उसके फिर आने तक धीरज धरते हुए।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440018', 'ml', 'മര്‍ക്കൊസ് 13: മനുഷ്യപുത്രനായി ഉണര്‍ന്നിരിക്കുക', 'മര്‍ക്കൊസ് 13 വായിക്കുക. ദൈവാലയത്തിന്റെ നാശം മുന്‍കൂട്ടി പറഞ്ഞുകൊണ്ട്, അന്ത്യത്തിനുമുമ്പുള്ള കഷ്ടത, വഞ്ചന, പീഡനം എന്നിവയ്ക്കായി യേശു തന്റെ ശിഷ്യന്മാരെ ഒരുക്കുന്നു. സുവിശേഷം ആദ്യം സകല ജാതികളോടും പ്രസംഗിക്കപ്പെടണമെന്നും മനുഷ്യപുത്രന്‍ തന്റെ തെരഞ്ഞെടുക്കപ്പെട്ടവരെ ചേര്‍ക്കാന്‍ മഹത്വത്തില്‍ മടങ്ങിവരുമെന്നും അവന്‍ വാഗ്ദാനം ചെയ്യുന്നു. ആ ദിവസമോ നാഴികയോ ആരും അറിയുന്നില്ല, അതിനാല്‍ ''ഉണര്‍ന്നിരിക്കുവിന്‍'' എന്ന് അവന്‍ ആവര്‍ത്തിച്ചു കല്‍പിക്കുന്നു. വിശ്വാസികള്‍ വിശ്വസ്തവും സ്വസ്ഥവുമായ പ്രതീക്ഷയില്‍ ജീവിക്കുന്നു, ക്രിസ്തുവിന്റെ ഉറപ്പുള്ള വചനത്തില്‍ ആശ്രയിച്ച് അവന്‍ വീണ്ടും വരുവോളം സഹിച്ചുനില്‍ക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440019', 'hi', 'मरकुस 14:1-31: दफनाने के लिए अभिषेक और नई वाचा', 'मरकुस 14:1-31 पढ़ें। जब यीशु के विरुद्ध षड्यंत्र रचे जाते हैं और यहूदा उन्हें पकड़वाने को सहमत होता है, एक स्त्री असाधारण भक्ति में उन्हें दफनाने के लिए अभिषेक करती है। फसह के भोजन पर यीशु प्रभु-भोज की स्थापना करते हैं, रोटी और कटोरा अपनी देह और लहू के रूप में देते हुए जो ''बहुतों के लिए बहाया जाता है''—उनकी बलिदानमय मृत्यु में मुहर लगाई गई नई वाचा। वे चेलों के भाग जाने और पतरस के इन्कार की भविष्यवाणी करते हैं। क्रूस कोई दुर्घटना नहीं परन्तु उद्धार का नियत साधन है जिसे वे स्वेच्छा से अपनाते हैं।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440019', 'ml', 'മര്‍ക്കൊസ് 14:1-31: അടക്കത്തിനായുള്ള അഭിഷേകവും പുതിയ ഉടമ്പടിയും', 'മര്‍ക്കൊസ് 14:1-31 വായിക്കുക. യേശുവിനെതിരായ ഗൂഢാലോചനകള്‍ രൂപപ്പെടുകയും യൂദാ അവനെ കാണിച്ചുകൊടുക്കാന്‍ സമ്മതിക്കുകയും ചെയ്യുമ്പോള്‍, ഒരു സ്ത്രീ അത്യന്ത ഭക്തിയില്‍ അവനെ അടക്കത്തിനായി അഭിഷേകം ചെയ്യുന്നു. പെസഹ ഭക്ഷണത്തില്‍ യേശു കര്‍ത്തൃമേശ സ്ഥാപിക്കുന്നു, അപ്പവും പാനപാത്രവും ''അനേകര്‍ക്കുവേണ്ടി ചൊരിയുന്ന'' തന്റെ ശരീരവും രക്തവുമായി നല്‍കുന്നു—അവന്റെ ബലിമരണത്തില്‍ മുദ്രയിട്ട പുതിയ ഉടമ്പടി. ശിഷ്യന്മാരുടെ ഉപേക്ഷയും പത്രൊസിന്റെ തള്ളിപ്പറയലും അവന്‍ മുന്‍കൂട്ടി പറയുന്നു. ക്രൂശ് ഒരു അപകടമല്ല, അവന്‍ സ്വമനസ്സാലെ ആശ്ലേഷിക്കുന്ന വീണ്ടെടുപ്പിന്റെ നിയോഗിതമായ മാര്‍ഗ്ഗമാണ്.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440020', 'hi', 'मरकुस 14:32-72: गतसमनी, विश्वासघात, और इन्कार', 'मरकुस 14:32-72 पढ़ें। गतसमनी में यीशु, व्यथा में, पिता की इच्छा के सामने समर्पण करते हैं: ''मेरी नहीं, परन्तु तेरी इच्छा पूरी हो।'' यहूदा द्वारा उन्हें पकड़वाया जाता है, बंदी बनाया जाता है, और उनके चेलों द्वारा त्यागा जाता है। महासभा के सामने वे सत्य अंगीकार करने के लिए दोषी ठहराए जाते हैं—वे मसीह हैं, उस धन्य के पुत्र। इसी बीच पतरस तीन बार उनका इन्कार करता है और फूट-फूट कर रोता है। निष्पाप उद्धारकर्ता स्वेच्छापूर्ण आज्ञाकारिता में क्रूस की ओर बढ़ते हैं, मानवीय असफलता और ईश्वरीय उद्देश्य को वहन करते हुए।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440020', 'ml', 'മര്‍ക്കൊസ് 14:32-72: ഗെത്ത്ശെമന, ഒറ്റിക്കൊടുക്കല്‍, തള്ളിപ്പറയല്‍', 'മര്‍ക്കൊസ് 14:32-72 വായിക്കുക. ഗെത്ത്ശെമനയില്‍ വ്യാകുലപ്പെട്ട യേശു പിതാവിന്റെ ഹിതത്തിനു കീഴ്പ്പെടുന്നു: ''ഞാന്‍ ഇച്ഛിക്കുന്നതല്ല, നീ ഇച്ഛിക്കുന്നതു ആകട്ടെ.'' യൂദായാല്‍ ഒറ്റിക്കൊടുക്കപ്പെട്ട്, ബന്ധിക്കപ്പെട്ട്, ശിഷ്യന്മാരാല്‍ ഉപേക്ഷിക്കപ്പെടുന്നു. ന്യായാധിപസംഘത്തിനു മുമ്പാകെ സത്യം—താന്‍ ക്രിസ്തു, വാഴ്ത്തപ്പെട്ടവന്റെ പുത്രന്‍ എന്ന്—ഏറ്റുപറഞ്ഞതിന് അവന്‍ കുറ്റംവിധിക്കപ്പെടുന്നു. അതേസമയം പത്രൊസ് മൂന്നു പ്രാവശ്യം അവനെ തള്ളിപ്പറഞ്ഞ് കൈപ്പോടെ കരയുന്നു. നിഷ്കളങ്കനായ രക്ഷകന്‍, മാനുഷിക പരാജയവും ദൈവിക ഉദ്ദേശ്യവും വഹിച്ചുകൊണ്ട്, സ്വമേധയാ അനുസരണത്തില്‍ ക്രൂശിലേക്കു നീങ്ങുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440021', 'hi', 'मरकुस 15: राजा का क्रूसारोहण', 'मरकुस 15 पढ़ें। निर्दोष होने पर भी पीलातुस द्वारा दोषी ठहराए गए, यीशु का उपहास किया जाता है, कोड़े मारे जाते हैं, और दो अपराधियों के बीच क्रूस पर चढ़ाया जाता है। अंधकार में वे पुकारते हैं, ''मेरे परमेश्वर, मेरे परमेश्वर, तूने मुझे क्यों छोड़ दिया?''—हमारे स्थानापन्न के रूप में हमारे पाप के योग्य क्रोध को वहन करते हुए। वे प्राण त्याग देते हैं, मंदिर का पर्दा दो भागों में फट जाता है, परमेश्वर तक मार्ग खोलते हुए, और एक सूबेदार अंगीकार करता है, ''सचमुच यह मनुष्य परमेश्वर का पुत्र था।'' यहाँ निष्पाप मसीह ईश्वरीय न्याय को संतुष्ट करते हैं और सब विश्वास करनेवालों के लिए छुटकारा सुनिश्चित करते हैं।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440021', 'ml', 'മര്‍ക്കൊസ് 15: രാജാവിന്റെ ക്രൂശീകരണം', 'മര്‍ക്കൊസ് 15 വായിക്കുക. നിരപരാധിയായിട്ടും പീലാത്തൊസിനാല്‍ കുറ്റംവിധിക്കപ്പെട്ട യേശു പരിഹസിക്കപ്പെട്ട്, ചമ്മട്ടികൊണ്ട് അടിക്കപ്പെട്ട്, രണ്ടു കുറ്റവാളികളുടെ നടുവില്‍ ക്രൂശിക്കപ്പെടുന്നു. ഇരുട്ടില്‍ അവന്‍ നിലവിളിക്കുന്നു, ''എന്റെ ദൈവമേ, എന്റെ ദൈവമേ, നീ എന്നെ കൈവിട്ടതെന്ത്?''—നമ്മുടെ പകരക്കാരനായി നമ്മുടെ പാപം അര്‍ഹിച്ച കോപം വഹിച്ചുകൊണ്ട്. അവന്‍ മരിക്കുന്നു, ദൈവാലയത്തിന്റെ തിരശ്ശീല രണ്ടായി കീറുന്നു, ദൈവത്തിലേക്കുള്ള വഴി തുറക്കുന്നു, ഒരു ശതാധിപന്‍ ഏറ്റുപറയുന്നു, ''ഈ മനുഷ്യന്‍ സത്യമായി ദൈവപുത്രന്‍ ആയിരുന്നു.'' ഇവിടെ നിഷ്കളങ്കനായ ക്രിസ്തു ദൈവിക നീതിയെ തൃപ്തിപ്പെടുത്തുകയും വിശ്വസിക്കുന്ന എല്ലാവര്‍ക്കും വീണ്ടെടുപ്പ് ഉറപ്പാക്കുകയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0200000-e29b-41d4-a716-446655440022', 'hi', 'मरकुस 16: वह जी उठा है', 'मरकुस 16 पढ़ें। सप्ताह के पहले दिन, स्त्रियाँ पत्थर को लुढ़का हुआ पाती हैं और एक स्वर्गदूत घोषणा करता है, ''वह जी उठा है; वह यहाँ नहीं है।'' यीशु का शारीरिक पुनरुत्थान पिता द्वारा अपने पुत्र की निर्दोषता की पुष्टि और हमारी आशा तथा धर्मीकरण की नींव है। (सबसे प्राचीन हस्तलिपियाँ पद 8 पर समाप्त होती हैं; पद 9-20, यद्यपि कलीसिया द्वारा लंबे समय से स्वीकार किए गए, पाठगत रूप से विवादित हैं और सुसमाचार में कुछ भी आवश्यक नहीं जोड़ते।) जी उठे मसीह अपने लोगों को उनका प्रचार करने के लिए नियुक्त करते हैं।', 'मसीह का जीवन'),
  ('d0200000-e29b-41d4-a716-446655440022', 'ml', 'മര്‍ക്കൊസ് 16: അവന്‍ ഉയിര്‍ത്തെഴുന്നേറ്റിരിക്കുന്നു', 'മര്‍ക്കൊസ് 16 വായിക്കുക. ആഴ്ചയുടെ ഒന്നാം നാളില്‍, സ്ത്രീകള്‍ കല്ല് ഉരുട്ടിമാറ്റിയതായി കാണുന്നു, ഒരു ദൂതന്‍ പ്രഖ്യാപിക്കുന്നു, ''അവന്‍ ഉയിര്‍ത്തെഴുന്നേറ്റു; അവന്‍ ഇവിടെ ഇല്ല.'' യേശുവിന്റെ ശാരീരിക പുനരുത്ഥാനം പിതാവ് തന്റെ പുത്രനെ നീതീകരിക്കുന്നതും നമ്മുടെ പ്രത്യാശയുടെയും നീതീകരണത്തിന്റെയും അടിസ്ഥാനവുമാണ്. (ഏറ്റവും പുരാതന കയ്യെഴുത്തുപ്രതികള്‍ 8-ാം വാക്യത്തില്‍ അവസാനിക്കുന്നു; 9-20 വാക്യങ്ങള്‍, സഭ ദീര്‍ഘകാലം സ്വീകരിച്ചിട്ടുണ്ടെങ്കിലും, പാഠപരമായി തര്‍ക്കവിഷയമാണ്, സുവിശേഷത്തിന് അവശ്യമായതൊന്നും കൂട്ടിച്ചേര്‍ക്കുന്നില്ല.) ഉയിര്‍ത്തെഴുന്നേറ്റ ക്രിസ്തു തന്നെ പ്രസിദ്ധമാക്കാന്‍ തന്റെ ജനത്തെ നിയോഗിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440001', 'hi', 'लूका 1:1-25: एक सुव्यवस्थित विवरण और यूहन्ना की प्रतिज्ञा', 'लूका 1:1-25 पढ़ें। लूका थियुफिलुस को संबोधित करते हुए अपने सुसमाचार को सावधान, प्रत्यक्षदर्शी जाँच पर आधारित करता है, ताकि हम इन बातों की निश्चितता जान सकें। स्वर्गदूत गब्रिएल याजक जकर्याह को बताता है कि उसकी बाँझ पत्नी इलीशिबा यूहन्ना को जन्म देगी, जो अग्रदूत होगा और अनेकों को प्रभु की ओर फेरेगा। संदेह करने पर जकर्याह गूँगा कर दिया जाता है। परमेश्वर अपनी वाचा की प्रतिज्ञाएँ निभाता है, साधारण विश्वासयोग्य जनों के द्वारा कार्य करता है, और मसीह के लिए मार्ग तैयार करता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440001', 'ml', 'ലൂക്കൊസ് 1:1-25: ക്രമമായ ഒരു വിവരണവും യോഹന്നാന്റെ വാഗ്ദത്തവും', 'ലൂക്കൊസ് 1:1-25 വായിക്കുക. ഈ കാര്യങ്ങളുടെ നിശ്ചയം നാം അറിയേണ്ടതിന് ലൂക്കൊസ് തെയോഫിലോസിനെ അഭിസംബോധന ചെയ്ത്, ശ്രദ്ധാപൂർവവും ദൃക്സാക്ഷിത്വത്തിലധിഷ്ഠിതവുമായ അന്വേഷണത്തിൽ തന്റെ സുവിശേഷം അടിസ്ഥാനപ്പെടുത്തുന്നു. തന്റെ വന്ധ്യയായ ഭാര്യ എലിസബെത്ത് യോഹന്നാനെ പ്രസവിക്കുമെന്ന്, അനേകരെ കർത്താവിങ്കലേക്കു തിരിക്കുന്ന മുന്നോടിയായ അവനെക്കുറിച്ച്, ഗബ്രിയേൽ ദൂതൻ പുരോഹിതനായ സെഖര്യാവിനെ അറിയിക്കുന്നു. സംശയിച്ചതിനാൽ സെഖര്യാവ് ഊമനായിത്തീരുന്നു. ദൈവം തന്റെ ഉടമ്പടി വാഗ്ദത്തങ്ങൾ പാലിക്കുന്നു, സാധാരണ വിശ്വസ്ത ജനങ്ങളിലൂടെ പ്രവർത്തിക്കുന്നു, മശിഹായ്ക്കു വഴിയൊരുക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440002', 'hi', 'लूका 1:26-56: स्वर्गदूत का संदेश और मरियम का स्तुतिगान', 'लूका 1:26-56 पढ़ें। गब्रिएल कुँवारी मरियम को बताता है कि वह पवित्र आत्मा से यीशु को गर्भ में धारण करेगी, जो परमप्रधान का पुत्र है और जिसके राज्य का अन्त कभी न होगा। मरियम दीन विश्वास में समर्पण करती है, इलीशिबा से भेंट करती है, और स्तुतिगान (मैग्निफिकैट) में फूट पड़ती है। उसका गीत परमेश्वर को अपने उद्धारकर्ता के रूप में बढ़ाता है, उसकी दया, पवित्रता, और दीनों को ऊँचा उठाने के सामर्थ्य का गुणगान करता है। यह देहधारण, कुँवारी से गर्भधारण, और उद्धार को परमेश्वर की अनुग्रहपूर्ण पहल के रूप में पुष्ट करता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440002', 'ml', 'ലൂക്കൊസ് 1:26-56: ദൂതന്റെ അറിയിപ്പും മറിയയുടെ സ്തുതിഗീതവും', 'ലൂക്കൊസ് 1:26-56 വായിക്കുക. പരിശുദ്ധാത്മാവിനാൽ താൻ യേശുവിനെ ഗർഭം ധരിക്കുമെന്നും, അവൻ അത്യുന്നതന്റെ പുത്രനും അവന്റെ രാജ്യത്തിന് അവസാനമില്ലാത്തവനും ആകുമെന്നും ഗബ്രിയേൽ കന്യകയായ മറിയയെ അറിയിക്കുന്നു. മറിയ വിനീത വിശ്വാസത്തിൽ കീഴ്പെടുന്നു, എലിസബെത്തിനെ സന്ദർശിക്കുന്നു, സ്തുതിഗീതത്തിൽ (മാഗ്നിഫിക്കാത്ത്) പൊട്ടിത്തെറിക്കുന്നു. അവളുടെ കീർത്തനം ദൈവത്തെ തന്റെ രക്ഷകനായി മഹത്വപ്പെടുത്തുന്നു, അവന്റെ കരുണയും വിശുദ്ധിയും താഴ്മയുള്ളവരെ ഉയർത്തുന്ന ശക്തിയും വാഴ്ത്തുന്നു. ഇത് അവതാരത്തെയും കന്യാജനനത്തെയും, രക്ഷ ദൈവത്തിന്റെ കൃപാപൂർണമായ മുൻകൈ ആണെന്നതിനെയും ഉറപ്പിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440003', 'hi', 'लूका 1:57-80: यूहन्ना का जन्म और जकर्याह का गीत', 'लूका 1:57-80 पढ़ें। यूहन्ना का जन्म होता है, और जब जकर्याह स्वर्गदूत के वचन की पुष्टि करता है तब उसकी जीभ खुल जाती है। पवित्र आत्मा से भरकर वह बेनेडिक्टस की भविष्यवाणी करता है, परमेश्वर की स्तुति करता है कि उसने दाऊद के घराने में उद्धार का सींग खड़ा किया और उस कोमल दया के लिए जो अंधकार में बैठनेवालों के लिए ज्योति लाती है। यूहन्ना प्रभु के आगे-आगे चलकर उसका मार्ग तैयार करेगा। परमेश्वर अपनी वाचा को स्मरण करता है और मसीह में अपनी उद्धार की प्रतिज्ञाएँ पूरी करता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440003', 'ml', 'ലൂക്കൊസ് 1:57-80: യോഹന്നാന്റെ ജനനവും സെഖര്യാവിന്റെ കീർത്തനവും', 'ലൂക്കൊസ് 1:57-80 വായിക്കുക. യോഹന്നാൻ ജനിക്കുന്നു, ദൂതന്റെ വാക്ക് സ്ഥിരീകരിക്കുമ്പോൾ സെഖര്യാവിന്റെ നാവ് അഴിയുന്നു. പരിശുദ്ധാത്മാവ് നിറഞ്ഞ് അവൻ ബെനഡിക്റ്റസ് പ്രവചിക്കുന്നു, ദാവീദിന്റെ ഭവനത്തിൽ ഒരു രക്ഷയുടെ കൊമ്പ് ഉയർത്തിയതിനും അന്ധകാരത്തിലിരിക്കുന്നവർക്കു വെളിച്ചം നൽകുന്ന ആർദ്രമായ കരുണയ്ക്കും ദൈവത്തെ വാഴ്ത്തുന്നു. കർത്താവിന്റെ മുമ്പേ നടന്ന് അവന്റെ വഴിയൊരുക്കാൻ യോഹന്നാൻ പോകും. ദൈവം തന്റെ ഉടമ്പടി ഓർക്കുകയും ക്രിസ്തുവിൽ തന്റെ വീണ്ടെടുപ്പിന്റെ വാഗ്ദത്തങ്ങൾ നിറവേറ്റുകയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440004', 'hi', 'लूका 2: उद्धारकर्ता का जन्म', 'लूका 2 पढ़ें। यीशु बेतलेहेम में जन्म लेता है, चरनी में रखा जाता है, और स्वर्गदूत चरवाहों के सामने उसे उद्धारकर्ता, मसीह प्रभु के रूप में घोषित करते हैं। उसके समर्पण के समय शिमौन और हन्ना उसे परमेश्वर का उद्धार पहचानते हैं, जो सब लोगों के लिए तैयार किया गया। बालक के रूप में मन्दिर में, यीशु अपने पिता के घर के प्रति सचेत होने का प्रमाण देता है। देहधारी पुत्र सच्ची दीनता में मानव इतिहास में प्रवेश करता है, भविष्यवाणी को पूरा करता है और उन पर शान्ति लाता है जिन पर परमेश्वर की कृपा है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440004', 'ml', 'ലൂക്കൊസ് 2: രക്ഷകന്റെ ജനനം', 'ലൂക്കൊസ് 2 വായിക്കുക. യേശു ബേത്ലഹേമിൽ ജനിക്കുന്നു, പുൽത്തൊട്ടിയിൽ കിടത്തപ്പെടുന്നു, ഇടയന്മാരോട് ദൂതന്മാർ അവനെ ഒരു രക്ഷകൻ, കർത്താവായ ക്രിസ്തു എന്നു അറിയിക്കുന്നു. അവന്റെ സമർപ്പണവേളയിൽ ശിമെയോനും ഹന്നയും അവനെ സകല ജനങ്ങൾക്കുമായി ഒരുക്കിയ ദൈവത്തിന്റെ രക്ഷയായി തിരിച്ചറിയുന്നു. ബാലനായി ദൈവാലയത്തിൽ വെച്ച്, യേശു തന്റെ പിതാവിന്റെ ഭവനത്തെക്കുറിച്ചുള്ള ബോധം പ്രകടമാക്കുന്നു. അവതരിച്ച പുത്രൻ യഥാർഥ താഴ്മയിൽ മനുഷ്യചരിത്രത്തിലേക്കു പ്രവേശിക്കുന്നു, പ്രവചനം നിറവേറ്റുകയും ദൈവപ്രസാദമുള്ളവർക്കു സമാധാനം കൊണ്ടുവരികയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440005', 'hi', 'लूका 3: यूहन्ना का प्रचार और यीशु का बपतिस्मा', 'लूका 3 पढ़ें। यूहन्ना पापों की क्षमा के लिए पश्चाताप का बपतिस्मा प्रचार करता है, पश्चाताप के योग्य फल फलाने का आह्वान करता है, और उस अधिक सामर्थी की ओर संकेत करता है जो आत्मा से बपतिस्मा देगा। यीशु बपतिस्मा लेता है, आत्मा उतरता है, और पिता उसे प्रिय पुत्र घोषित करता है। वंशावली यीशु को आदम तक पीछे ले जाती है, उसे समस्त मानवजाति का उद्धारकर्ता ठहराती है। मात्र वंश-परम्परा नहीं, बल्कि पश्चाताप और विश्वास उन्हें चिह्नित करते हैं जो राज्य के लिए तैयार हैं।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440005', 'ml', 'ലൂക്കൊസ് 3: യോഹന്നാന്റെ പ്രസംഗവും യേശുവിന്റെ സ്നാനവും', 'ലൂക്കൊസ് 3 വായിക്കുക. പാപമോചനത്തിനായുള്ള മാനസാന്തരത്തിന്റെ സ്നാനം യോഹന്നാൻ പ്രസംഗിക്കുന്നു, മാനസാന്തരത്തിനു യോഗ്യമായ ഫലം പുറപ്പെടുവിക്കാൻ ആഹ്വാനം ചെയ്യുന്നു, ആത്മാവിനാൽ സ്നാനം കഴിപ്പിക്കുന്ന അധികം ശക്തനായവനിലേക്കു ചൂണ്ടുന്നു. യേശു സ്നാനമേൽക്കുന്നു, ആത്മാവ് ഇറങ്ങുന്നു, പിതാവ് അവനെ പ്രിയപുത്രൻ എന്നു പ്രഖ്യാപിക്കുന്നു. വംശാവലി യേശുവിനെ ആദാമിലേക്കു പിന്നോട്ടു കണ്ടെത്തുന്നു, അവനെ സർവമനുഷ്യരുടെയും രക്ഷകനായി അടയാളപ്പെടുത്തുന്നു. കേവലം പാരമ്പര്യമല്ല, മാനസാന്തരവും വിശ്വാസവുമാണ് രാജ്യത്തിനൊരുങ്ങിയവരെ അടയാളപ്പെടുത്തുന്നത്.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440006', 'hi', 'लूका 4: परीक्षा और यीशु की सेवकाई का आरम्भ', 'लूका 4 पढ़ें। आत्मा की अगुवाई में यीशु केवल पवित्रशास्त्र के द्वारा शैतान की परीक्षाओं पर विजय पाता है, जहाँ इस्राएल विफल हुआ था वहाँ सफल होता है। नासरत में वह यशायाह को पढ़ता है और स्वयं में उसकी पूर्ति की घोषणा करता है, दीनों को सुसमाचार और बन्दियों को छुटकारे की घोषणा करता है। अपने ही नगर द्वारा अस्वीकार किए जाने पर, वह अधिकार के साथ उपदेश देता है और दुष्टात्माओं को निकालता है। मसीह की उद्धार की सेवकाई आरम्भ होती है, जो लिखे वचन पर आधारित और बुराई पर सामर्थ्य से पुष्ट है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440006', 'ml', 'ലൂക്കൊസ് 4: പരീക്ഷയും യേശുവിന്റെ ശുശ്രൂഷയുടെ ആരംഭവും', 'ലൂക്കൊസ് 4 വായിക്കുക. ആത്മാവിനാൽ നയിക്കപ്പെട്ട്, യിസ്രായേൽ പരാജയപ്പെട്ടിടത്ത് വിജയിച്ചുകൊണ്ട്, യേശു തിരുവെഴുത്തു മാത്രം ഉപയോഗിച്ച് സാത്താന്റെ പരീക്ഷകളെ ജയിക്കുന്നു. നസറെത്തിൽ അവൻ യെശയ്യാവ് വായിച്ച് അതിന്റെ നിവൃത്തി തന്നിൽ പ്രഖ്യാപിക്കുന്നു, ദരിദ്രരോട് സുവിശേഷവും ബന്ധിതർക്കു വിടുതലും അറിയിക്കുന്നു. സ്വന്തം പട്ടണത്താൽ തിരസ്കരിക്കപ്പെട്ടിട്ടും അവൻ അധികാരത്തോടെ ഉപദേശിക്കുകയും ഭൂതങ്ങളെ പുറത്താക്കുകയും ചെയ്യുന്നു. എഴുതപ്പെട്ട വചനത്തിൽ അധിഷ്ഠിതവും തിന്മയുടെമേലുള്ള ശക്തിയാൽ സ്ഥിരീകരിക്കപ്പെട്ടതുമായ മശിഹായുടെ രക്ഷാദൗത്യം ആരംഭിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440007', 'hi', 'लूका 5: चेलों का बुलावा और क्षमा करने का अधिकार', 'लूका 5 पढ़ें। मछलियों के चमत्कारिक पकड़ के बाद, पतरस अपने पाप के बोध में यीशु के सामने गिर पड़ता है, और मनुष्यों को पकड़ने के लिए बुलाया जाता है। यीशु एक कोढ़ी को शुद्ध करता है, फिर एक लकवे के मारे को क्षमा करके चंगा करता है, यह प्रमाणित करते हुए कि मनुष्य के पुत्र को पृथ्वी पर पाप क्षमा करने का अधिकार है। वह लेवी नामक चुंगी लेनेवाले को बुलाता है, यह घोषित करते हुए कि वह धर्मियों को नहीं, बल्कि पापियों को पश्चाताप के लिए बुलाने आया है। उद्धार उनके लिए है जो अनुग्रह की अपनी आवश्यकता को जानते हैं।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440007', 'ml', 'ലൂക്കൊസ് 5: ശിഷ്യന്മാരുടെ വിളിയും ക്ഷമിക്കാനുള്ള അധികാരവും', 'ലൂക്കൊസ് 5 വായിക്കുക. അത്ഭുതകരമായ മീൻപിടിത്തത്തിനുശേഷം, പത്രൊസ് തന്റെ പാപബോധത്തിൽ യേശുവിന്റെ മുമ്പിൽ വീഴുന്നു, മനുഷ്യരെ പിടിക്കാൻ വിളിക്കപ്പെടുന്നു. യേശു ഒരു കുഷ്ഠരോഗിയെ ശുദ്ധമാക്കുന്നു, പിന്നെ ഒരു തളർവാതക്കാരനെ ക്ഷമിച്ച് സൗഖ്യമാക്കുന്നു, മനുഷ്യപുത്രന് ഭൂമിയിൽ പാപങ്ങൾ ക്ഷമിക്കാൻ അധികാരമുണ്ടെന്ന് തെളിയിക്കുന്നു. അവൻ ലേവി എന്ന ചുങ്കക്കാരനെ വിളിക്കുന്നു, താൻ നീതിമാന്മാരെയല്ല, പാപികളെ മാനസാന്തരത്തിലേക്കു വിളിക്കാൻ വന്നുവെന്ന് പ്രഖ്യാപിക്കുന്നു. കൃപയ്ക്കായുള്ള തങ്ങളുടെ ആവശ്യം അറിയുന്നവർക്കാണ് രക്ഷ.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440008', 'hi', 'लूका 6: सब्त का प्रभु और मैदान पर का उपदेश', 'लूका 6 पढ़ें। यीशु सब्त पर अपनी प्रभुता का दावा करता है और चंगा करता है, व्यवस्थावाद को उजागर करता है। वह बारह प्रेरितों को चुनता है, फिर मैदान पर उपदेश देता है: आशीषें और हाय, शत्रुओं के लिए मूलभूत प्रेम, दया, और कपटी न्याय करने के विरुद्ध चेतावनी। पेड़ अपने फल से पहचाना जाता है, और बुद्धिमान वह है जो उसके वचनों को सुनकर मानता है। सच्चा चेलापन बाहरी अनुरूपता से नहीं, बल्कि रूपान्तरित हृदय से बहता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440008', 'ml', 'ലൂക്കൊസ് 6: ശബ്ബത്തിന്റെ കർത്താവും സമഭൂമിയിലെ പ്രസംഗവും', 'ലൂക്കൊസ് 6 വായിക്കുക. യേശു ശബ്ബത്തിന്മേലുള്ള തന്റെ കർത്തൃത്വം ഉറപ്പിക്കുകയും സൗഖ്യമാക്കുകയും ചെയ്ത് ന്യായപ്രമാണവാദത്തെ വെളിപ്പെടുത്തുന്നു. അവൻ പന്ത്രണ്ട് അപ്പൊസ്തലന്മാരെ തിരഞ്ഞെടുക്കുന്നു, പിന്നെ സമഭൂമിയിലെ പ്രസംഗം നൽകുന്നു: അനുഗ്രഹങ്ങളും കഷ്ടങ്ങളും, ശത്രുക്കളോടുള്ള മൗലികമായ സ്നേഹം, കരുണ, കപടമായ വിധിക്കെതിരെയുള്ള മുന്നറിയിപ്പുകൾ. വൃക്ഷം അതിന്റെ ഫലത്താൽ അറിയപ്പെടുന്നു, അവന്റെ വാക്കുകൾ കേട്ട് അനുസരിക്കുന്നവനാണ് ജ്ഞാനിയായി പണിയുന്നവൻ. യഥാർഥ ശിഷ്യത്വം ബാഹ്യമായ അനുരൂപതയിൽനിന്നല്ല, രൂപാന്തരപ്പെട്ട ഹൃദയത്തിൽനിന്നാണ് ഒഴുകുന്നത്.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440009', 'hi', 'लूका 7: विश्वास, करुणा, और क्षमा', 'लूका 7 पढ़ें। यीशु सूबेदार के बड़े विश्वास की सराहना करता है, नाईन में विधवा के बेटे को जिलाता है, और बन्दी यूहन्ना को आश्वस्त करता है कि मसीही चिह्न उसकी पहचान की पुष्टि करते हैं। एक पापिनी स्त्री आँसुओं से उसके पाँव का अभिषेक करती है, और यीशु उसके विश्वास के कारण उसके अनेक पाप क्षमा होने की घोषणा करता है, उसके प्रेम की तुलना फरीसी की उदासीनता से करता है। मसीह की करुणा परदेशी और टूटे हुए तक पहुँचती है, और क्षमा विश्वास के द्वारा मिलती है, जो कृतज्ञ प्रेम उत्पन्न करती है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440009', 'ml', 'ലൂക്കൊസ് 7: വിശ്വാസവും കരുണയും ക്ഷമയും', 'ലൂക്കൊസ് 7 വായിക്കുക. യേശു ശതാധിപന്റെ വലിയ വിശ്വാസത്തെ പ്രശംസിക്കുന്നു, നയിനിലെ വിധവയുടെ മകനെ ഉയിർപ്പിക്കുന്നു, മശിഹൈക അടയാളങ്ങൾ തന്റെ വ്യക്തിത്വം സ്ഥിരീകരിക്കുന്നുവെന്ന് തടവിലുള്ള യോഹന്നാന് ഉറപ്പുനൽകുന്നു. ഒരു പാപിയായ സ്ത്രീ കണ്ണുനീരാൽ അവന്റെ കാൽ അഭിഷേകം ചെയ്യുന്നു, അവളുടെ വിശ്വാസം നിമിത്തം അവളുടെ അനേകം പാപങ്ങൾ ക്ഷമിക്കപ്പെട്ടിരിക്കുന്നുവെന്ന് യേശു പ്രഖ്യാപിക്കുന്നു, അവളുടെ സ്നേഹത്തെ പരീശന്റെ തണുപ്പുമായി താരതമ്യപ്പെടുത്തുന്നു. ക്രിസ്തുവിന്റെ കരുണ പുറത്തുള്ളവനെയും തകർന്നവനെയും എത്തിപ്പിടിക്കുന്നു, ക്ഷമ വിശ്വാസത്താൽ ലഭിക്കുന്നു, അത് കൃതജ്ഞതയുള്ള സ്നേഹം ഉളവാക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440010', 'hi', 'लूका 8: दृष्टान्त और प्रकृति, दुष्टात्माओं और मृत्यु पर सामर्थ्य', 'लूका 8 पढ़ें। यीशु बीज बोनेवाले का दृष्टान्त सिखाता है, यह समझाते हुए कि वचन ईमानदार, धीरजवन्त हृदयों में फल लाता है। वह आँधी को शान्त करता है, गिरासेनी के दुष्टात्मा-ग्रस्त को छुड़ाता है, विश्वास के द्वारा लहू बहनेवाली स्त्री को चंगा करता है, और याईर की बेटी को जिलाता है। उसका अधिकार प्रकृति, दुष्टात्माओं, रोग, और मृत्यु पर फैला है। जब वचन ग्रहण किया और माना जाता है तब राज्य आगे बढ़ता है, और यीशु संप्रभु प्रभु के रूप में प्रकट होता है जो भरोसे के योग्य है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440010', 'ml', 'ലൂക്കൊസ് 8: ഉപമകളും പ്രകൃതിയുടെയും ഭൂതങ്ങളുടെയും മരണത്തിന്റെയും മേലുള്ള ശക്തിയും', 'ലൂക്കൊസ് 8 വായിക്കുക. യേശു വിതയ്ക്കുന്നവന്റെ ഉപമ പഠിപ്പിക്കുന്നു, ആത്മാർഥവും സഹനശീലവുമായ ഹൃദയങ്ങളിൽ വചനം ഫലം പുറപ്പെടുവിക്കുന്നുവെന്ന് വിശദമാക്കുന്നു. അവൻ കൊടുങ്കാറ്റിനെ ശാന്തമാക്കുന്നു, ഗരസേന്യദേശത്തെ ഭൂതഗ്രസ്തനെ വിടുവിക്കുന്നു, വിശ്വാസത്താൽ രക്തസ്രവമുള്ള സ്ത്രീയെ സൗഖ്യമാക്കുന്നു, യായീറോസിന്റെ മകളെ ഉയിർപ്പിക്കുന്നു. അവന്റെ അധികാരം പ്രകൃതിയുടെയും ദുരാത്മാക്കളുടെയും രോഗത്തിന്റെയും മരണത്തിന്റെയും മേൽ വ്യാപിക്കുന്നു. വചനം സ്വീകരിക്കുകയും അനുസരിക്കുകയും ചെയ്യുമ്പോൾ രാജ്യം മുന്നേറുന്നു, യേശു ആശ്രയത്തിനു യോഗ്യനായ പരമാധികാര കർത്താവായി വെളിപ്പെടുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440011', 'hi', 'लूका 9:1-50: पतरस की अंगीकारोक्ति और रूपान्तरण', 'लूका 9:1-50 पढ़ें। यीशु बारहों को भेजता है, पाँच हज़ार को खिलाता है, और पूछता है कि भीड़ उसे कौन कहती है। पतरस उसे परमेश्वर का मसीह अंगीकार करता है, और यीशु अपनी मृत्यु की भविष्यवाणी करता है तथा चेलों को क्रूस उठाने के लिए बुलाता है। पहाड़ पर वह महिमा में रूपान्तरित होता है, और पिता आज्ञा देता है, उसकी सुनो। यह मोड़बिन्दु मसीह की दिव्य महिमा तथा उसकी प्रायश्चित्त-मृत्यु और आत्म-त्यागी चेलेपन की अनिवार्यता को प्रकट करता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440011', 'ml', 'ലൂക്കൊസ് 9:1-50: പത്രൊസിന്റെ ഏറ്റുപറച്ചിലും രൂപാന്തരവും', 'ലൂക്കൊസ് 9:1-50 വായിക്കുക. യേശു പന്ത്രണ്ടുപേരെ അയയ്ക്കുന്നു, അയ്യായിരം പേരെ പോഷിപ്പിക്കുന്നു, ജനക്കൂട്ടം തന്നെ ആരെന്നു പറയുന്നുവെന്ന് ചോദിക്കുന്നു. പത്രൊസ് അവനെ ദൈവത്തിന്റെ ക്രിസ്തു എന്ന് ഏറ്റുപറയുന്നു, യേശു തന്റെ മരണം മുൻകൂട്ടി പറയുകയും ശിഷ്യന്മാരെ ക്രൂശ് എടുക്കാൻ വിളിക്കുകയും ചെയ്യുന്നു. മലയിൽ അവൻ മഹത്വത്തിൽ രൂപാന്തരപ്പെടുന്നു, പിതാവ് കല്പിക്കുന്നു, അവന്റെ വാക്കു കേൾക്കുവിൻ. ഈ വഴിത്തിരിവ് ക്രിസ്തുവിന്റെ ദിവ്യമഹത്വവും അവന്റെ പ്രായശ്ചിത്ത മരണത്തിന്റെയും ആത്മത്യാഗപരമായ ശിഷ്യത്വത്തിന്റെയും അനിവാര്യതയും വെളിപ്പെടുത്തുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440012', 'hi', 'लूका 9:51-62: दृढ़ता से यरूशलेम की ओर', 'लूका 9:51-62 पढ़ें। यीशु यरूशलेम जाने को अपना मुख दृढ़ करता है, यह जानते हुए कि क्रूस उसकी प्रतीक्षा में है। एक सामरी गाँव उसे अस्वीकार करता है, परन्तु वह चेलों की प्रतिशोध की इच्छा को डाँटता है। तीन भावी अनुयायी चेलेपन की कीमत सीखते हैं: न कोई आरामदायक घोंसला है, न विलम्बित आज्ञाकारिता, और न हल पर हाथ रखने के बाद पीछे मुड़कर देखना। मसीह का अनुसरण अविभाजित, पूरे मन की प्रतिबद्धता की माँग करता है जो सब सांसारिक संबंधों से बढ़कर उसे प्रिय जानती है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440012', 'ml', 'ലൂക്കൊസ് 9:51-62: ഉറപ്പോടെ യെരൂശലേമിലേക്ക്', 'ലൂക്കൊസ് 9:51-62 വായിക്കുക. ക്രൂശ് കാത്തിരിക്കുന്നുവെന്നറിഞ്ഞുകൊണ്ട് യേശു യെരൂശലേമിലേക്കു പോകാൻ മുഖം ഉറപ്പിക്കുന്നു. ഒരു ശമര്യഗ്രാമം അവനെ തിരസ്കരിക്കുന്നു, എന്നാൽ ശിഷ്യന്മാരുടെ പ്രതികാരാഗ്രഹത്തെ അവൻ ശാസിക്കുന്നു. ഭാവിയിലെ മൂന്ന് അനുയായികൾ ശിഷ്യത്വത്തിന്റെ വില പഠിക്കുന്നു: സുഖകരമായ ഒരു കൂടില്ല, വൈകിയ അനുസരണമില്ല, കലപ്പയിൽ കൈവെച്ചശേഷം പിന്നോട്ടു നോക്കലുമില്ല. ക്രിസ്തുവിനെ അനുഗമിക്കുന്നത് സകല ഭൗമിക ബന്ധങ്ങളെക്കാളും അവനെ വിലമതിക്കുന്ന അവിഭക്തവും പൂർണഹൃദയവുമായ സമർപ്പണം ആവശ്യപ്പെടുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440013', 'hi', 'लूका 10: सेवकाई, भला सामरी, और एक ही आवश्यक बात', 'लूका 10 पढ़ें। यीशु बहत्तर को राज्य का प्रचार करने भेजता है, यह आनन्द मनाते हुए कि उनके नाम स्वर्ग में लिखे हैं। वह दीनों पर सत्य प्रकट करने के लिए पिता की स्तुति करता है। भले सामरी का दृष्टान्त पड़ोसी-प्रेम को बाधाओं के पार सक्रिय दया के रूप में पुनः परिभाषित करता है। बैतनिय्याह में मार्था चिन्तित है जबकि मरियम यीशु के चरणों में उत्तम भाग को चुनती है। सच्चा चेलापन सबसे पहले मसीह को सुनने में टिका है, जहाँ से प्रेम और सेवा उचित रीति से बहते हैं।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440013', 'ml', 'ലൂക്കൊസ് 10: ദൗത്യം, നല്ല ശമര്യൻ, ഏക ആവശ്യമായ കാര്യം', 'ലൂക്കൊസ് 10 വായിക്കുക. യേശു എഴുപത്തിരണ്ടു പേരെ രാജ്യം ഘോഷിക്കാൻ അയയ്ക്കുന്നു, അവരുടെ പേരുകൾ സ്വർഗത്തിൽ എഴുതപ്പെട്ടിരിക്കുന്നുവെന്ന് സന്തോഷിക്കുന്നു. താഴ്മയുള്ളവർക്കു സത്യം വെളിപ്പെടുത്തിയതിന് അവൻ പിതാവിനെ സ്തുതിക്കുന്നു. നല്ല ശമര്യന്റെ ഉപമ അയൽക്കാരസ്നേഹത്തെ തടസ്സങ്ങൾക്കപ്പുറമുള്ള സജീവമായ കരുണയായി പുനർനിർവചിക്കുന്നു. ബേഥാന്യയിൽ മാർത്ത ഉത്കണ്ഠപ്പെടുമ്പോൾ മറിയ യേശുവിന്റെ കാൽക്കൽ ഉത്തമമായ ഭാഗം തിരഞ്ഞെടുക്കുന്നു. യഥാർഥ ശിഷ്യത്വം ആദ്യം ക്രിസ്തുവിനെ കേൾക്കുന്നതിൽ വിശ്രമിക്കുന്നു, അവിടെനിന്നാണ് സ്നേഹവും ശുശ്രൂഷയും ശരിയായി ഒഴുകുന്നത്.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440014', 'hi', 'लूका 11: प्रार्थना और कपट का सामना', 'लूका 11 पढ़ें। यीशु चेलों को प्रार्थना करना सिखाता है, उन्हें उस भले पिता से दृढ़, भरोसेमन्द होकर माँगने का आग्रह करता है जो पवित्र आत्मा देता है। वह इस आरोप का उत्तर देता है कि वह शैतान के द्वारा दुष्टात्माओं को निकालता है, यह चेतावनी देते हुए कि फूटा हुआ राज्य गिर जाता है और तटस्थता असम्भव है। वह उन फरीसियों और व्यवस्थापकों पर हाय कहता है जो बाहरी शुद्धता और परम्परा को महत्व देते हैं जबकि न्याय और परमेश्वर के प्रेम की उपेक्षा करते हैं। परमेश्वर धार्मिक ढोंग नहीं, बल्कि सच्चे हृदय चाहता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440014', 'ml', 'ലൂക്കൊസ് 11: പ്രാർഥനയും കാപട്യത്തെ നേരിടലും', 'ലൂക്കൊസ് 11 വായിക്കുക. യേശു ശിഷ്യന്മാരെ പ്രാർഥിക്കാൻ പഠിപ്പിക്കുന്നു, പരിശുദ്ധാത്മാവിനെ നൽകുന്ന നല്ല പിതാവിനോട് സ്ഥിരതയോടും ആത്മവിശ്വാസത്തോടും യാചിക്കാൻ പ്രേരിപ്പിക്കുന്നു. താൻ സാത്താനാൽ ഭൂതങ്ങളെ പുറത്താക്കുന്നുവെന്ന ആരോപണത്തിന് അവൻ ഉത്തരം നൽകുന്നു, ഭിന്നിച്ച രാജ്യം വീഴുമെന്നും നിഷ്പക്ഷത അസാധ്യമാണെന്നും മുന്നറിയിപ്പു നൽകുന്നു. നീതിയും ദൈവസ്നേഹവും അവഗണിച്ച് ബാഹ്യശുദ്ധിയും പാരമ്പര്യവും വിലമതിക്കുന്ന പരീശന്മാർക്കും ന്യായശാസ്ത്രിമാർക്കും അവൻ കഷ്ടം പ്രഖ്യാപിക്കുന്നു. ദൈവം മതപരമായ കാപട്യമല്ല, ആത്മാർഥമായ ഹൃദയങ്ങളാണ് ആഗ്രഹിക്കുന്നത്.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440015', 'hi', 'लूका 12: परमेश्वर का भय मानो, राज्य को खोजो, तैयार रहो', 'लूका 12 पढ़ें। यीशु कपट और मनुष्य के भय के विरुद्ध चेतावनी देता है, चेलों को उस परमेश्वर का भय मानने के लिए बुलाता है जो उन्हें अति मूल्यवान जानता है। मूर्ख धनवान धन इकट्ठा करता है पर परमेश्वर की दृष्टि में धनी नहीं है। चेले चिन्ता से मुक्त किए जाते हैं ताकि राज्य को खोजें, पिता की देखभाल पर भरोसा करते हुए। यीशु उसके लौटने के लिए जागते रहने और विश्वासयोग्य भण्डारीपन का आग्रह करता है। अनन्त वास्तविकताएँ सांसारिक प्राथमिकताओं को नियंत्रित करें, क्योंकि हर कोई लौटनेवाले प्रभु को लेखा देता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440015', 'ml', 'ലൂക്കൊസ് 12: ദൈവത്തെ ഭയപ്പെടുക, രാജ്യം അന്വേഷിക്കുക, ഒരുങ്ങിയിരിക്കുക', 'ലൂക്കൊസ് 12 വായിക്കുക. കാപട്യത്തിനും മനുഷ്യഭയത്തിനുമെതിരെ യേശു മുന്നറിയിപ്പു നൽകുന്നു, തങ്ങളെ വിലയേറിയവരായി കാണുന്ന ദൈവത്തെ ഭയപ്പെടാൻ ശിഷ്യന്മാരെ വിളിക്കുന്നു. ഭോഷനായ ധനവാൻ നിക്ഷേപം ശേഖരിക്കുന്നു, എന്നാൽ ദൈവത്തിങ്കൽ ധനവാനല്ല. ശിഷ്യന്മാർ ഉത്കണ്ഠയിൽനിന്നു സ്വതന്ത്രരാക്കപ്പെടുന്നു, പിതാവിന്റെ പരിപാലനത്തിൽ ആശ്രയിച്ച് രാജ്യം അന്വേഷിക്കാൻ. തന്റെ മടങ്ങിവരവിനായി ജാഗ്രതയും വിശ്വസ്തമായ കാര്യസ്ഥതയും യേശു പ്രേരിപ്പിക്കുന്നു. നിത്യയാഥാർഥ്യങ്ങൾ ഭൗമിക മുൻഗണനകളെ നിയന്ത്രിക്കണം, കാരണം ഏവനും മടങ്ങിവരുന്ന കർത്താവിനോട് കണക്കു ബോധിപ്പിക്കണം.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440016', 'hi', 'लूका 13: पश्चाताप करो और सकेत द्वार से प्रवेश करो', 'लूका 13 पढ़ें। यीशु सबको पश्चाताप करने के लिए बुलाता है, यह चेतावनी देते हुए कि पश्चाताप के बिना लोग नाश होते हैं, फिर भी धीरजवन्त माली परमेश्वर की दया को चित्रित करता है। वह सब्त के दिन एक कुबड़ी स्त्री को चंगा करता है, कठोर हृदयों को उजागर करता है, और राज्य की उपमा राई के दाने और खमीर से देता है। वह सकेत द्वार से प्रवेश करने का प्रयत्न करने का आग्रह करता है, क्योंकि अनेक बाहर रखे जाएँगे। वह यरूशलेम के अविश्वास पर विलाप करता है। उद्धार के लिए सच्चा पश्चाताप और विश्वास आवश्यक है, मान ली गई विशेषाधिकार नहीं।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440016', 'ml', 'ലൂക്കൊസ് 13: മാനസാന്തരപ്പെട്ട് ഇടുങ്ങിയ വാതിലിലൂടെ പ്രവേശിക്കുക', 'ലൂക്കൊസ് 13 വായിക്കുക. എല്ലാവരെയും മാനസാന്തരപ്പെടാൻ യേശു വിളിക്കുന്നു, മാനസാന്തരമില്ലാതെ ജനം നശിക്കുമെന്ന് മുന്നറിയിപ്പു നൽകുന്നു, എങ്കിലും ക്ഷമയുള്ള തോട്ടക്കാരൻ ദൈവത്തിന്റെ കരുണ ചിത്രീകരിക്കുന്നു. അവൻ ശബ്ബത്തിൽ കൂനുള്ള ഒരു സ്ത്രീയെ സൗഖ്യമാക്കുന്നു, കഠിനഹൃദയങ്ങളെ വെളിപ്പെടുത്തുന്നു, രാജ്യത്തെ കടുകുമണിയോടും പുളിമാവിനോടും ഉപമിക്കുന്നു. ഇടുങ്ങിയ വാതിലിലൂടെ കടക്കാൻ പ്രയത്നിക്കണമെന്ന് അവൻ പ്രേരിപ്പിക്കുന്നു, കാരണം അനേകർ പുറത്താക്കപ്പെടും. യെരൂശലേമിന്റെ അവിശ്വാസത്തെക്കുറിച്ച് അവൻ വിലപിക്കുന്നു. രക്ഷയ്ക്ക് യഥാർഥ മാനസാന്തരവും വിശ്വാസവും ആവശ്യമാണ്, അനുമാനിക്കപ്പെട്ട പ്രത്യേകാവകാശമല്ല.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440017', 'hi', 'लूका 14: दीनता, बड़ी जेवनार, और चेलेपन की कीमत', 'लूका 14 पढ़ें। सब्त के दिन चंगा करते हुए, यीशु दीनता सिखाता है, अतिथियों को सबसे नीची जगह लेने और मेज़बानों को उन्हें बुलाने का आग्रह करता है जो बदला नहीं चुका सकते। बड़ी जेवनार का दृष्टान्त दिखाता है कि परमेश्वर दीनों और बहिष्कृतों को बुलाता है जबकि संतुष्ट लोग इनकार करते हैं। यीशु चेतावनी देता है कि चेलापन सब कुछ माँगता है; मनुष्य को कीमत आँकनी चाहिए और उसका अनुसरण करने के लिए सब कुछ समर्पित करना चाहिए। अनुग्रह मुफ्त में दिया जाता है, फिर भी यह मसीह के प्रति आनन्दित निष्ठा में सम्पूर्ण जीवन का दावा करता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440017', 'ml', 'ലൂക്കൊസ് 14: താഴ്മ, വലിയ വിരുന്ന്, ശിഷ്യത്വത്തിന്റെ വില', 'ലൂക്കൊസ് 14 വായിക്കുക. ശബ്ബത്തിൽ സൗഖ്യമാക്കിക്കൊണ്ട് യേശു താഴ്മ പഠിപ്പിക്കുന്നു, അതിഥികളോട് ഏറ്റവും താഴ്ന്ന സ്ഥലം എടുക്കാനും ആതിഥേയരോട് പ്രതിഫലം നൽകാൻ കഴിയാത്തവരെ ക്ഷണിക്കാനും പ്രേരിപ്പിക്കുന്നു. വലിയ വിരുന്നിന്റെ ഉപമ കാണിക്കുന്നത് സംതൃപ്തർ നിരസിക്കുമ്പോൾ ദൈവം ദരിദ്രരെയും പുറത്താക്കപ്പെട്ടവരെയും ക്ഷണിക്കുന്നു എന്നാണ്. ശിഷ്യത്വം എല്ലാം ആവശ്യപ്പെടുന്നുവെന്ന് യേശു മുന്നറിയിപ്പു നൽകുന്നു; ഒരുവൻ വില കണക്കാക്കി അവനെ അനുഗമിക്കാൻ സകലവും സമർപ്പിക്കണം. കൃപ സൗജന്യമായി നൽകപ്പെടുന്നു, എങ്കിലും അത് ക്രിസ്തുവിനോടുള്ള ആനന്ദകരമായ വിധേയത്വത്തിൽ ജീവിതം മുഴുവൻ അവകാശപ്പെടുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440018', 'hi', 'लूका 15: अनुग्रह के दृष्टान्त', 'लूका 15 पढ़ें। पापियों का स्वागत करने के कारण उसकी निन्दा करनेवाले आलोचकों को उत्तर देते हुए, यीशु तीन दृष्टान्त सुनाता है: खोई हुई भेड़, खोया हुआ सिक्का, और उड़ाऊ पुत्र। एक पापी के पश्चाताप करने पर स्वर्ग आनन्द मनाता है। पिता अपने लौटते हुए पुत्र को गले लगाने दौड़ता है, उसे विशुद्ध अनुग्रह से पुनः स्थापित करता है, जबकि बड़ा भाई आत्म-धर्मी रोष को उजागर करता है। ये दृष्टान्त पश्चातापी के प्रति परमेश्वर के खोजते, क्षमा करते हृदय को प्रकट करते हैं, अनुग्रह के उस सुसमाचार को दर्शाते हुए जो अयोग्य को उद्धार देता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440018', 'ml', 'ലൂക്കൊസ് 15: കൃപയുടെ ഉപമകൾ', 'ലൂക്കൊസ് 15 വായിക്കുക. പാപികളെ സ്വീകരിക്കുന്നതിനെ പുച്ഛിക്കുന്ന വിമർശകർക്ക് ഉത്തരം നൽകിക്കൊണ്ട് യേശു മൂന്ന് ഉപമകൾ പറയുന്നു: കാണാതെപോയ ആട്, കാണാതെപോയ നാണയം, ധൂർത്തപുത്രൻ. മാനസാന്തരപ്പെടുന്ന ഒരു പാപിയെച്ചൊല്ലി സ്വർഗം ആനന്ദിക്കുന്നു. പിതാവ് മടങ്ങിവരുന്ന മകനെ ആലിംഗനം ചെയ്യാൻ ഓടുന്നു, കേവലം കൃപയാൽ അവനെ പുനഃസ്ഥാപിക്കുന്നു, അതേസമയം മൂത്ത സഹോദരൻ ആത്മനീതിയുള്ള നീരസം വെളിപ്പെടുത്തുന്നു. ഈ ഉപമകൾ മാനസാന്തരപ്പെടുന്നവനോടുള്ള ദൈവത്തിന്റെ അന്വേഷിക്കുന്നതും ക്ഷമിക്കുന്നതുമായ ഹൃദയം വെളിപ്പെടുത്തുന്നു, അയോഗ്യനെ രക്ഷിക്കുന്ന കൃപയുടെ സുവിശേഷം പ്രദർശിപ്പിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440019', 'hi', 'लूका 16: धन, अनन्तता, और वचन', 'लूका 16 पढ़ें। चतुर भण्डारी सांसारिक धन के बुद्धिमान, अनन्त उपयोग को सिखाता है, क्योंकि कोई परमेश्वर और धन दोनों की सेवा नहीं कर सकता। यीशु धन-प्रेमी फरीसियों को डाँटता है, परमेश्वर की व्यवस्था के स्थायी अधिकार को पुष्ट करते हुए। धनवान और लाजर मृत्यु के बाद अनन्तता की निश्चित, अपरिवर्तनीय वास्तविकता और पश्चाताप की ओर ले जाने में पवित्रशास्त्र की पर्याप्तता को प्रकट करते हैं। हम धन को कैसे सम्भालते हैं यह हृदय को प्रकट करता है, और पवित्रशास्त्र, न कि चिह्न, सच्चा विश्वास जगाता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440019', 'ml', 'ലൂക്കൊസ് 16: ധനം, നിത്യത, വചനം', 'ലൂക്കൊസ് 16 വായിക്കുക. ഒരുവന് ദൈവത്തെയും ധനത്തെയും ഒരുമിച്ച് സേവിക്കാനാവില്ലെന്നതിനാൽ, ഭൗമികസമ്പത്തിന്റെ ജ്ഞാനപൂർവവും നിത്യവുമായ ഉപയോഗം വിവേകിയായ കാര്യസ്ഥൻ പഠിപ്പിക്കുന്നു. ധനസ്നേഹികളായ പരീശന്മാരെ യേശു ശാസിക്കുന്നു, ദൈവത്തിന്റെ ന്യായപ്രമാണത്തിന്റെ നിലനിൽക്കുന്ന അധികാരം സ്ഥിരീകരിക്കുന്നു. ധനവാനും ലാസറും മരണാനന്തരം നിത്യതയുടെ സ്ഥിരവും മാറ്റാനാവാത്തതുമായ യാഥാർഥ്യവും മാനസാന്തരത്തിലേക്കു നയിക്കാൻ തിരുവെഴുത്തിന്റെ പര്യാപ്തതയും വെളിപ്പെടുത്തുന്നു. നാം ധനം എങ്ങനെ കൈകാര്യം ചെയ്യുന്നു എന്നത് ഹൃദയം വെളിപ്പെടുത്തുന്നു, അടയാളങ്ങളല്ല, തിരുവെഴുത്താണ് യഥാർഥ വിശ്വാസം ഉണർത്തുന്നത്.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440020', 'hi', 'लूका 17: विश्वास, कृतज्ञता, और आनेवाला राज्य', 'लूका 17 पढ़ें। यीशु ठोकर के कारणों से बचने, बार-बार क्षमा करने, और निकम्मे सेवकों के रूप में सेवा करने के बारे में सिखाता है जो कोई योग्यता का दावा नहीं करते। दस कोढ़ी शुद्ध किए जाते हैं, पर केवल एक सामरी धन्यवाद देने लौटता है, और उसका विश्वास उसे पूर्ण चंगा करता है। यीशु घोषित करता है कि परमेश्वर का राज्य पहले से ही उनके बीच में है और चेतावनी देता है कि उसका लौटना अचानक और प्रत्यक्ष होगा। उद्धार देनेवाला विश्वास दीनता, कृतज्ञता, और प्रभु के प्रकट होने के लिए तैयारी में स्वयं को व्यक्त करता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440020', 'ml', 'ലൂക്കൊസ് 17: വിശ്വാസം, നന്ദി, വരുവാനുള്ള രാജ്യം', 'ലൂക്കൊസ് 17 വായിക്കുക. ഇടർച്ചയ്ക്കു കാരണമാകുന്നവ ഒഴിവാക്കുന്നതിനെക്കുറിച്ചും ആവർത്തിച്ച് ക്ഷമിക്കുന്നതിനെക്കുറിച്ചും ഒരു യോഗ്യതയും അവകാശപ്പെടാത്ത പ്രയോജനമില്ലാത്ത ദാസന്മാരായി സേവിക്കുന്നതിനെക്കുറിച്ചും യേശു പഠിപ്പിക്കുന്നു. പത്തു കുഷ്ഠരോഗികൾ ശുദ്ധരാക്കപ്പെടുന്നു, എന്നാൽ ഒരു ശമര്യൻ മാത്രം നന്ദി പറയാൻ മടങ്ങിവരുന്നു, അവന്റെ വിശ്വാസം അവനെ സൗഖ്യമാക്കുന്നു. ദൈവരാജ്യം ഇപ്പോൾ തന്നെ അവരുടെ മധ്യേ ഉണ്ടെന്ന് യേശു പ്രഖ്യാപിക്കുന്നു, തന്റെ മടങ്ങിവരവ് പെട്ടെന്നും ദൃശ്യവുമായിരിക്കുമെന്ന് മുന്നറിയിപ്പു നൽകുന്നു. രക്ഷിക്കുന്ന വിശ്വാസം താഴ്മയിലും നന്ദിയിലും കർത്താവിന്റെ പ്രത്യക്ഷതയ്ക്കായുള്ള ഒരുക്കത്തിലും സ്വയം പ്രകടമാക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440021', 'hi', 'लूका 18: प्रार्थना, दीनता, और राज्य को ग्रहण करना', 'लूका 18 पढ़ें। यीशु हठीली विधवा के द्वारा निरन्तर प्रार्थना का आग्रह करता है और आत्म-धर्मी फरीसी की तुलना उस धर्मी ठहराए गए चुंगी लेनेवाले से करता है जो दया की भीख माँगता है। वह बालकों का स्वागत करता है, यह सिखाते हुए कि राज्य बालक-समान निर्भरता में ग्रहण किया जाता है। धनवान सरदार लौट जाता है, धन को छोड़ने को तैयार नहीं, जबकि यीशु अपनी मृत्यु की भविष्यवाणी करता है और एक अंधे भिखारी को चंगा करता है जो उसे दाऊद की सन्तान पुकारता है। धर्मी ठहराया जाना दीन विश्वास से आता है, कभी आत्म-विश्वासी योग्यता से नहीं।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440021', 'ml', 'ലൂക്കൊസ് 18: പ്രാർഥന, താഴ്മ, രാജ്യം സ്വീകരിക്കൽ', 'ലൂക്കൊസ് 18 വായിക്കുക. നിരന്തരം ശല്യപ്പെടുത്തുന്ന വിധവയിലൂടെ യേശു സ്ഥിരമായ പ്രാർഥനയ്ക്കു പ്രേരിപ്പിക്കുന്നു, ആത്മനീതിയുള്ള പരീശനെ കരുണയ്ക്കായി യാചിക്കുന്ന നീതീകരിക്കപ്പെട്ട ചുങ്കക്കാരനുമായി താരതമ്യപ്പെടുത്തുന്നു. അവൻ കുട്ടികളെ സ്വാഗതം ചെയ്യുന്നു, ശിശുസമാനമായ ആശ്രയത്വത്തിലാണ് രാജ്യം സ്വീകരിക്കപ്പെടുന്നതെന്ന് പഠിപ്പിക്കുന്നു. ധനവാനായ പ്രമാണി ധനം ഉപേക്ഷിക്കാൻ മനസ്സില്ലാതെ മടങ്ങിപ്പോകുന്നു, അതേസമയം യേശു തന്റെ മരണം മുൻകൂട്ടി പറയുകയും തന്നെ ദാവീദുപുത്രാ എന്നു വിളിക്കുന്ന ഒരു അന്ധനായ ഭിക്ഷക്കാരനെ സൗഖ്യമാക്കുകയും ചെയ്യുന്നു. നീതീകരണം വിനീത വിശ്വാസത്താൽ വരുന്നു, ഒരിക്കലും ആത്മവിശ്വാസമുള്ള യോഗ്യതയാലല്ല.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440022', 'hi', 'लूका 19: जक्कई, मुहरें, और विजयी प्रवेश', 'लूका 19 पढ़ें। यीशु जक्कई का उद्धार करता है, यह घोषित करते हुए कि वह खोए हुओं को ढूँढ़ने और उद्धार करने आया है, और रूपान्तरित जीवन अनुग्रह से बहता है। दस मुहरों का दृष्टान्त सेवकों को राजा के लौटने से पहले विश्वासयोग्य भण्डारीपन के लिए बुलाता है। यीशु दीन राजा के रूप में स्तुति के नारों के बीच यरूशलेम में प्रवेश करता है, नगर के अंधेपन पर रोता है, और मन्दिर को शुद्ध करता है। उद्धारकर्ता पापियों का पीछा करता है, विश्वासयोग्यता को प्रतिफल देता है, और इस्राएल के प्रतिज्ञात राजा के रूप में उचित रूप से आराधना का दावा करता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440022', 'ml', 'ലൂക്കൊസ് 19: സക്കായി, റാത്തലുകൾ, വിജയപ്രവേശനം', 'ലൂക്കൊസ് 19 വായിക്കുക. യേശു സക്കായിയെ രക്ഷിക്കുന്നു, നഷ്ടപ്പെട്ടവരെ അന്വേഷിച്ച് രക്ഷിക്കാൻ താൻ വന്നുവെന്ന് പ്രഖ്യാപിക്കുന്നു, രൂപാന്തരപ്പെട്ട ജീവിതം കൃപയിൽനിന്ന് ഒഴുകുന്നു. പത്തു റാത്തലുകളുടെ ഉപമ രാജാവ് മടങ്ങിവരുന്നതിനു മുമ്പ് വിശ്വസ്തമായ കാര്യസ്ഥതയ്ക്കു ദാസന്മാരെ വിളിക്കുന്നു. യേശു സ്തുതിയുടെ ആർപ്പുവിളികൾക്കിടയിൽ വിനീത രാജാവായി യെരൂശലേമിൽ പ്രവേശിക്കുന്നു, നഗരത്തിന്റെ അന്ധതയെച്ചൊല്ലി കരയുന്നു, ദൈവാലയം ശുദ്ധീകരിക്കുന്നു. രക്ഷകൻ പാപികളെ പിന്തുടരുന്നു, വിശ്വസ്തതയ്ക്കു പ്രതിഫലം നൽകുന്നു, യിസ്രായേലിന്റെ വാഗ്ദത്ത രാജാവായി ന്യായമായും ആരാധന അവകാശപ്പെടുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440023', 'hi', 'लूका 20: मसीह के अधिकार की परीक्षा', 'लूका 20 पढ़ें। मन्दिर में यीशु के अधिकार को चुनौती दी जाती है, और वह दुष्ट किसानों के दृष्टान्त से उत्तर देता है, परमेश्वर के प्रिय पुत्र की अस्वीकृति को उजागर करते हुए, वही ठुकराया हुआ पत्थर अब कोने का सिरा बना दिया गया है। वह कैसर को कर देने और पुनरुत्थान के बारे में जालों को चुप कराता है, परमेश्वर को जीवितों का परमेश्वर पुष्ट करते हुए। वह पूछता है कि मसीह कैसे दाऊद की सन्तान और साथ ही उसका प्रभु हो सकता है, और घमण्डी शास्त्रियों के विरुद्ध चेतावनी देता है। मसीह का दिव्य अधिकार अटल खड़ा रहता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440023', 'ml', 'ലൂക്കൊസ് 20: ക്രിസ്തുവിന്റെ അധികാരം പരീക്ഷിക്കപ്പെടുന്നു', 'ലൂക്കൊസ് 20 വായിക്കുക. ദൈവാലയത്തിൽ യേശുവിന്റെ അധികാരം വെല്ലുവിളിക്കപ്പെടുന്നു, ദുഷ്ടരായ കുടിയാന്മാരുടെ ഉപമയിലൂടെ അവൻ ഉത്തരം നൽകുന്നു, ദൈവത്തിന്റെ പ്രിയപുത്രന്റെ തിരസ്കരണം വെളിപ്പെടുത്തുന്നു, തള്ളിക്കളഞ്ഞ കല്ല് ഇപ്പോൾ മൂലക്കല്ലായിത്തീർന്നിരിക്കുന്നു. കൈസർക്കു കരം കൊടുക്കുന്നതിനെക്കുറിച്ചും പുനരുത്ഥാനത്തെക്കുറിച്ചുമുള്ള കെണികളെ അവൻ നിശ്ശബ്ദമാക്കുന്നു, ദൈവം ജീവിച്ചിരിക്കുന്നവരുടെ ദൈവമെന്ന് സ്ഥിരീകരിക്കുന്നു. ക്രിസ്തു എങ്ങനെ ദാവീദിന്റെ പുത്രനും കർത്താവും ആകുമെന്ന് അവൻ ചോദിക്കുന്നു, അഹങ്കാരികളായ ശാസ്ത്രിമാർക്കെതിരെ മുന്നറിയിപ്പു നൽകുന്നു. ക്രിസ്തുവിന്റെ ദിവ്യാധികാരം ഇളക്കമില്ലാതെ നിലനിൽക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440024', 'hi', 'लूका 21: विधवा का दान और अन्त के चिह्न', 'लूका 21 पढ़ें। यीशु उस गरीब विधवा की सराहना करता है जिसका छोटा सा दान धनवानों से बढ़कर है, क्योंकि उसने अपना सब कुछ दे दिया। वह मन्दिर के विनाश, आनेवाले क्लेशों, यरूशलेम के पतन, और मनुष्य के पुत्र के रूप में अपने महिमामय लौटने की भविष्यवाणी करता है। चेले भय के बजाय धीरज, जागरूकता, और प्रार्थना के लिए बुलाए जाते हैं। इतिहास मसीह के निश्चित लौटने की ओर बढ़ता है; उसके अचूक वचन उसके लोगों को परीक्षा के बीच विश्वासयोग्य, सजग तैयारी के लिए बुलाते हैं।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440024', 'ml', 'ലൂക്കൊസ് 21: വിധവയുടെ ദാനവും അന്ത്യത്തിന്റെ അടയാളങ്ങളും', 'ലൂക്കൊസ് 21 വായിക്കുക. ദരിദ്രയായ വിധവയുടെ ചെറിയ വഴിപാട് ധനവാന്മാരുടേതിനെ കവിയുന്നുവെന്ന് യേശു പ്രശംസിക്കുന്നു, കാരണം അവൾ തനിക്കുള്ളതെല്ലാം നൽകി. അവൻ ദൈവാലയത്തിന്റെ നാശവും വരുവാനുള്ള കഷ്ടങ്ങളും യെരൂശലേമിന്റെ പതനവും മനുഷ്യപുത്രനായി തന്റെ മഹത്വമുള്ള മടങ്ങിവരവും മുൻകൂട്ടി പറയുന്നു. ശിഷ്യന്മാർ ഭയത്തിനു പകരം സഹനത്തിലേക്കും ജാഗ്രതയിലേക്കും പ്രാർഥനയിലേക്കും വിളിക്കപ്പെടുന്നു. ചരിത്രം ക്രിസ്തുവിന്റെ നിശ്ചയമായ മടങ്ങിവരവിലേക്കു നീങ്ങുന്നു; അവന്റെ പിഴയ്ക്കാത്ത വാക്കുകൾ ക്ലേശത്തിനിടയിൽ വിശ്വസ്തവും സുബോധമുള്ളതുമായ ഒരുക്കത്തിലേക്ക് അവന്റെ ജനത്തെ വിളിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440025', 'hi', 'लूका 22: अन्तिम भोज और गतसमनी', 'लूका 22 पढ़ें। यहूदा यीशु को पकड़वाने को राज़ी होता है। फसह के समय, यीशु प्रभु-भोज की स्थापना करता है, अपनी देह और लहू को पापों की क्षमा के लिए नई वाचा के रूप में देते हुए। वह पतरस के इनकार की भविष्यवाणी करता है और सेवकाई के द्वारा बड़प्पन सिखाता है। गतसमनी में वह व्यथित प्रार्थना में पिता की इच्छा के अधीन हो जाता है, पकड़वाया और बन्दी बनाया जाता है, और पतरस उसका इनकार करता है। निष्पाप उद्धारकर्ता स्वेच्छा से क्रूस की ओर बढ़ता है ताकि अपने लोगों के लिए उद्धार सुनिश्चित करे।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440025', 'ml', 'ലൂക്കൊസ് 22: അന്ത്യഅത്താഴവും ഗെത്ത്ശമനയും', 'ലൂക്കൊസ് 22 വായിക്കുക. യൂദാ യേശുവിനെ ഒറ്റിക്കൊടുക്കാൻ സമ്മതിക്കുന്നു. പെസഹായിൽ, പാപമോചനത്തിനായുള്ള പുതിയ ഉടമ്പടിയായി തന്റെ ശരീരവും രക്തവും നൽകിക്കൊണ്ട് യേശു കർത്തൃമേശ സ്ഥാപിക്കുന്നു. അവൻ പത്രൊസിന്റെ തള്ളിപ്പറയൽ മുൻകൂട്ടി പറയുകയും ശുശ്രൂഷയിലൂടെ മഹത്വം പഠിപ്പിക്കുകയും ചെയ്യുന്നു. ഗെത്ത്ശമനയിൽ അവൻ വ്യാകുലമായ പ്രാർഥനയിൽ പിതാവിന്റെ ഇഷ്ടത്തിനു കീഴ്പെടുന്നു, ഒറ്റിക്കൊടുക്കപ്പെട്ട് അറസ്റ്റിലാകുന്നു, പത്രൊസ് അവനെ തള്ളിപ്പറയുന്നു. പാപമില്ലാത്ത രക്ഷകൻ തന്റെ ജനത്തിനായി വീണ്ടെടുപ്പ് ഉറപ്പാക്കാൻ സ്വമേധയാ ക്രൂശിലേക്കു നീങ്ങുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440026', 'hi', 'लूका 23: उद्धारकर्ता का क्रूसीकरण', 'लूका 23 पढ़ें। यद्यपि पिलातुस और हेरोदेस उसमें कोई दोष नहीं पाते, यीशु दोषी ठहराया जाता है और दो अपराधियों के बीच क्रूस पर चढ़ाया जाता है। वह अपने हत्यारों के लिए प्रार्थना करता है और पश्चातापी चोर से स्वर्गलोक की प्रतिज्ञा करता है, जो केवल विश्वास से उद्धार पाता है। अंधकार छा जाता है, मन्दिर का परदा फट जाता है, और यीशु अपना आत्मा पिता को सौंप देता है। निर्दोष पुत्र पापियों के स्थान पर मरता है, परमेश्वर के न्याय को सन्तुष्ट करता है और अपनी प्रायश्चित्त-मृत्यु के द्वारा परमेश्वर तक का मार्ग खोलता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440026', 'ml', 'ലൂക്കൊസ് 23: രക്ഷകന്റെ ക്രൂശീകരണം', 'ലൂക്കൊസ് 23 വായിക്കുക. പീലാത്തോസും ഹെരോദാവും അവനിൽ കുറ്റമൊന്നും കണ്ടെത്തുന്നില്ലെങ്കിലും, യേശു ശിക്ഷിക്കപ്പെട്ട് രണ്ടു കുറ്റവാളികളുടെ മധ്യേ ക്രൂശിക്കപ്പെടുന്നു. അവൻ തന്റെ ഘാതകർക്കായി പ്രാർഥിക്കുകയും വിശ്വാസത്താൽ മാത്രം രക്ഷിക്കപ്പെടുന്ന അനുതാപമുള്ള കള്ളന് പറുദീസ വാഗ്ദാനം ചെയ്യുകയും ചെയ്യുന്നു. അന്ധകാരം വ്യാപിക്കുന്നു, ദൈവാലയത്തിന്റെ തിരശ്ശീല കീറുന്നു, യേശു തന്റെ ആത്മാവിനെ പിതാവിന്റെ കയ്യിൽ ഏല്പിക്കുന്നു. നിർദോഷിയായ പുത്രൻ പാപികൾക്കു പകരക്കാരനായി മരിക്കുന്നു, ദൈവനീതിയെ തൃപ്തിപ്പെടുത്തുകയും തന്റെ പ്രായശ്ചിത്ത മരണത്തിലൂടെ ദൈവത്തിങ്കലേക്കുള്ള വഴി തുറക്കുകയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0300000-e29b-41d4-a716-446655440027', 'hi', 'लूका 24: पुनरुत्थान और इम्माऊस की राह', 'लूका 24 पढ़ें। पहले दिन, स्त्रियाँ कब्र को खाली पाती हैं और स्वर्गदूत घोषणा करते हैं कि यीशु जी उठा है, ठीक जैसा उसने कहा था। इम्माऊस की ओर चलते हुए, जी उठा हुआ मसीह पवित्रशास्त्र को खोलता है, यह दिखाते हुए कि वे सब किस प्रकार उसके दुःख और महिमा की ओर संकेत करते हैं। वह चेलों को शारीरिक रूप से प्रकट होता है, उनके सामने भोजन करता है, सब जातियों के लिए पश्चाताप और क्षमा का आदेश देता है, और ऊपर उठा लिया जाता है। शारीरिक पुनरुत्थान मसीह को सत्य ठहराता है और उद्धार के सुसमाचार पर मुहर लगाता है।', 'मसीह का जीवन'),
  ('d0300000-e29b-41d4-a716-446655440027', 'ml', 'ലൂക്കൊസ് 24: പുനരുത്ഥാനവും എമ്മവുസിലേക്കുള്ള വഴിയും', 'ലൂക്കൊസ് 24 വായിക്കുക. ഒന്നാം ദിവസം, സ്ത്രീകൾ കല്ലറ ശൂന്യമായി കാണുന്നു, യേശു താൻ മുൻകൂട്ടി പറഞ്ഞതുപോലെ ഉയിർത്തെഴുന്നേറ്റിരിക്കുന്നുവെന്ന് ദൂതന്മാർ അറിയിക്കുന്നു. എമ്മവുസിലേക്കു നടക്കുമ്പോൾ, ഉയിർത്തെഴുന്നേറ്റ ക്രിസ്തു തിരുവെഴുത്തുകൾ തുറന്ന്, അവയെല്ലാം എങ്ങനെ തന്റെ കഷ്ടത്തിലേക്കും മഹത്വത്തിലേക്കും ചൂണ്ടുന്നുവെന്ന് കാണിക്കുന്നു. അവൻ ശിഷ്യന്മാർക്കു ശരീരത്തോടെ പ്രത്യക്ഷനാകുന്നു, അവരുടെ മുമ്പിൽ ഭക്ഷിക്കുന്നു, സകല ജാതികളോടും മാനസാന്തരവും പാപമോചനവും കല്പിക്കുന്നു, സ്വർഗത്തിലേക്ക് എടുക്കപ്പെടുന്നു. ശാരീരിക പുനരുത്ഥാനം ക്രിസ്തുവിനെ സത്യമെന്നു സ്ഥാപിക്കുകയും രക്ഷയുടെ സുവിശേഷത്തിന് മുദ്രയിടുകയും ചെയ്യുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440001', 'hi', 'यूहन्ना 1: वचन देहधारी हुआ', 'यूहन्ना 1 पढ़ें। यूहन्ना बेतलेहेम से नहीं, परन्तु अनन्तकाल से आरम्भ करता है: वचन परमेश्वर के साथ था और स्वयं परमेश्वर था, वह सृष्टिकर्ता जिसके द्वारा सब वस्तुएँ बनीं। यह अनन्त वचन देहधारी हुआ और अनुग्रह और सच्चाई से परिपूर्ण होकर हमारे बीच डेरा किया। यूहन्ना बपतिस्मा देनेवाला गवाही देता है, और यीशु अपने पहले चेलों को बुलाते हैं। यहाँ यूहन्ना अपना सम्पूर्ण विषय प्रस्तुत करता है — वह ईश्वरीय, पूर्व-विद्यमान पुत्र जो पिता को प्रकट करता है और उसके नाम पर विश्वास करने के द्वारा परमेश्वर की सन्तान बनने का अधिकार देता है।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440001', 'ml', 'യോഹന്നാന്‍ 1: വചനം ജഡമായിത്തീര്‍ന്നു', 'യോഹന്നാന്‍ 1 വായിക്കുക. യോഹന്നാന്‍ ബേത്ത്‌ലഹേമില്‍ നിന്നല്ല, നിത്യതയില്‍ നിന്നാണ് ആരംഭിക്കുന്നത്: വചനം ദൈവത്തോടുകൂടെ ആയിരുന്നു, വചനം ദൈവം ആയിരുന്നു, സകലവും അവന്‍ മുഖാന്തരം ഉണ്ടായ സ്രഷ്ടാവ്. ഈ നിത്യവചനം ജഡമായിത്തീര്‍ന്നു, കൃപയും സത്യവും നിറഞ്ഞവനായി നമ്മുടെ ഇടയില്‍ വസിച്ചു. യോഹന്നാന്‍ സ്നാപകന്‍ സാക്ഷ്യം പറയുന്നു, യേശു തന്‍റെ ആദ്യ ശിഷ്യന്മാരെ വിളിക്കുന്നു. ഇവിടെ യോഹന്നാന്‍ തന്‍റെ മുഴുവന്‍ പ്രമേയം അവതരിപ്പിക്കുന്നു — പിതാവിനെ വെളിപ്പെടുത്തുകയും തന്‍റെ നാമത്തില്‍ വിശ്വസിക്കുന്നതിലൂടെ ദൈവമക്കളായിത്തീരുവാന്‍ അധികാരം നല്‍കുകയും ചെയ്യുന്ന ദൈവികനും മുന്‍നിലനില്‍ക്കുന്നവനുമായ പുത്രന്‍.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440002', 'hi', 'यूहन्ना 2: पहला चिह्न और मन्दिर की शुद्धि', 'यूहन्ना 2 पढ़ें। काना में यीशु पानी को दाखरस में बदल देते हैं — अपने चिह्नों में पहला — अपनी महिमा प्रकट करते हुए, जिससे उनके चेलों ने विश्वास किया। फिर वे मन्दिर को शुद्ध करते हैं, अपने पिता के घर पर अधिकार का दावा करते हुए, और अपनी देह के मन्दिर को उठाने में अपनी मृत्यु और पुनरुत्थान की भविष्यवाणी करते हैं। यूहन्ना दिखाता है कि यीशु पुरानी व्यवस्था से बड़े हैं: वे नई वाचा के आनन्द का आरम्भ करते हैं और परमेश्वर के सच्चे निवास को मूर्त रूप देते हैं, यद्यपि बहुतों ने उनके चमत्कारों पर केवल सतही रूप से विश्वास किया।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440002', 'ml', 'യോഹന്നാന്‍ 2: ആദ്യ അടയാളവും ദേവാലയശുദ്ധീകരണവും', 'യോഹന്നാന്‍ 2 വായിക്കുക. കാനായില്‍ യേശു വെള്ളം വീഞ്ഞാക്കി മാറ്റുന്നു — അവന്‍റെ അടയാളങ്ങളില്‍ ആദ്യത്തേത് — തന്‍റെ മഹത്വം വെളിപ്പെടുത്തി, അങ്ങനെ ശിഷ്യന്മാര്‍ വിശ്വസിച്ചു. പിന്നെ അവന്‍ ദേവാലയം ശുദ്ധീകരിക്കുന്നു, തന്‍റെ പിതാവിന്‍റെ ഭവനത്തിന്മേലുള്ള അധികാരം അവകാശപ്പെടുകയും തന്‍റെ ശരീരമാകുന്ന മന്ദിരം ഉയിര്‍പ്പിക്കുന്നതിലൂടെ തന്‍റെ മരണവും പുനരുത്ഥാനവും മുന്നറിയിക്കുകയും ചെയ്യുന്നു. യേശു പഴയ വ്യവസ്ഥയെക്കാള്‍ വലിയവന്‍ ആണെന്ന് യോഹന്നാന്‍ കാണിക്കുന്നു: അവന്‍ പുതിയ നിയമത്തിന്‍റെ സന്തോഷം ഉദ്ഘാടനം ചെയ്യുകയും ദൈവത്തിന്‍റെ യഥാര്‍ഥ വാസസ്ഥലത്തെ മൂര്‍ത്തീകരിക്കുകയും ചെയ്യുന്നു, അനേകര്‍ അവന്‍റെ അത്ഭുതങ്ങളില്‍ ഉപരിപ്ലവമായി മാത്രം വിശ്വസിച്ചെങ്കിലും.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440003', 'hi', 'यूहन्ना 3: तुम्हें नया जन्म लेना अवश्य है', 'यूहन्ना 3 पढ़ें। नीकुदेमुस रात को आता है, और यीशु घोषणा करते हैं कि जब तक कोई आत्मा से नया जन्म न ले, वह परमेश्वर के राज्य को नहीं देख सकता। नया जन्म परमेश्वर का सर्वसामर्थी कार्य है, मनुष्य का प्रयास नहीं। फिर आता है सुसमाचार का हृदय: परमेश्वर ने जगत से ऐसा प्रेम रखा कि उसने अपना एकलौता पुत्र दे दिया, ताकि जो कोई उस पर विश्वास करे वह नाश न हो परन्तु अनन्त जीवन पाए। उद्धार ऊँचे पर चढ़ाए गए मसीह पर टिका है, जो केवल विश्वास के द्वारा ग्रहण किया जाता है — ज्योति आ गई है, और विश्वास या अविश्वास न्याय का निर्णय करता है।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440003', 'ml', 'യോഹന്നാന്‍ 3: നിങ്ങള്‍ പുനര്‍ജനിക്കണം', 'യോഹന്നാന്‍ 3 വായിക്കുക. നിക്കൊദേമൊസ് രാത്രിയില്‍ വരുന്നു, ആത്മാവിനാല്‍ പുനര്‍ജനിച്ചല്ലാതെ ആര്‍ക്കും ദൈവരാജ്യം കാണ്മാന്‍ കഴികയില്ലെന്ന് യേശു പ്രഖ്യാപിക്കുന്നു. പുനര്‍ജന്മം ദൈവത്തിന്‍റെ പരമാധികാരപ്രവൃത്തിയാണ്, മനുഷ്യന്‍റെ ശ്രമമല്ല. പിന്നെ സുവിശേഷത്തിന്‍റെ ഹൃദയം വരുന്നു: തന്‍റെ ഏകജാതനായ പുത്രനില്‍ വിശ്വസിക്കുന്ന ഏവനും നശിച്ചുപോകാതെ നിത്യജീവന്‍ പ്രാപിക്കേണ്ടതിന് ദൈവം അവനെ നല്‍കുവാന്‍ തക്കവണ്ണം ലോകത്തെ സ്നേഹിച്ചു. രക്ഷ ഉയര്‍ത്തപ്പെട്ട ക്രിസ്തുവില്‍ ആശ്രയിച്ചിരിക്കുന്നു, വിശ്വാസത്താല്‍ മാത്രം പ്രാപിക്കുന്നു — വെളിച്ചം വന്നിരിക്കുന്നു, വിശ്വാസമോ അവിശ്വാസമോ ന്യായവിധിയെ നിര്‍ണയിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440004', 'hi', 'यूहन्ना 4: सामरी स्त्री के लिए जीवन का जल', 'यूहन्ना 4 पढ़ें। यीशु सामाजिक और जातीय बाधाओं को पार करके एक सामरी स्त्री को जीवन का जल देते हैं जो अनन्त जीवन का सोता बन जाता है। वे आत्मा और सच्चाई से सच्ची आराधना को प्रकट करते हैं और खुलकर स्वयं को मसीह घोषित करते हैं। उसकी गवाही से बहुत से सामरी विश्वास करते हैं। गलील लौटकर, यीशु केवल अपने वचन से एक अधिकारी के पुत्र को चंगा करते हैं। यूहन्ना दिखाता है कि जगत का उद्धारकर्ता इस्राएल से परे पहुँचता है, और पृष्ठभूमि या दूरी की चिन्ता किए बिना उन सबको अनुग्रह से जीवन देता है जो विश्वास करते हैं।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440004', 'ml', 'യോഹന്നാന്‍ 4: ശമര്യസ്ത്രീക്കു ജീവജലം', 'യോഹന്നാന്‍ 4 വായിക്കുക. യേശു സാമൂഹികവും വംശീയവുമായ തടസ്സങ്ങള്‍ കടന്ന് ഒരു ശമര്യസ്ത്രീക്ക് നിത്യജീവനിലേക്കു പൊങ്ങിവരുന്ന ഉറവായിത്തീരുന്ന ജീവജലം നല്‍കുന്നു. അവന്‍ ആത്മാവിലും സത്യത്തിലുമുള്ള യഥാര്‍ഥ ആരാധന വെളിപ്പെടുത്തുകയും താന്‍ ക്രിസ്തു ആകുന്നു എന്ന് തുറന്നു പ്രഖ്യാപിക്കുകയും ചെയ്യുന്നു. അവളുടെ സാക്ഷ്യം അനേകം ശമര്യര്‍ വിശ്വസിക്കുവാന്‍ ഇടയാക്കുന്നു. ഗലീലയിലേക്കു മടങ്ങി, യേശു തന്‍റെ വചനത്താല്‍ മാത്രം ഒരു ഉദ്യോഗസ്ഥന്‍റെ മകനെ സൗഖ്യമാക്കുന്നു. ലോകരക്ഷിതാവ് യിസ്രായേലിന് അപ്പുറം എത്തുന്നുവെന്നും പശ്ചാത്തലമോ ദൂരമോ നോക്കാതെ വിശ്വസിക്കുന്ന എല്ലാവര്‍ക്കും കൃപയാല്‍ ജീവന്‍ നല്‍കുന്നുവെന്നും യോഹന്നാന്‍ കാണിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440005', 'hi', 'यूहन्ना 5: पुत्र का अधिकार और पिता की गवाही', 'यूहन्ना 5 पढ़ें। यीशु बैतहसदा में अड़तीस वर्ष से लकवे के मारे हुए एक व्यक्ति को चंगा करते हैं, जिससे सब्त के विषय में विवाद उत्पन्न होता है। वे उत्तर देते हुए परमेश्वर के साथ समानता का दावा करते हैं — पुत्र के रूप में पिता के समान कार्य करते हुए, जीवन देते और न्याय करते हुए। वे अपनी पहचान के लिए गवाहों को बुलाते हैं: बपतिस्मा देनेवाला, उनके कार्य, पिता, और पवित्रशास्त्र, जो उनकी गवाही देते हैं। यूहन्ना पाठक पर दबाव डालता है कि वह पुत्र का वैसा ही आदर करे जैसा पिता का करता है, क्योंकि अनन्त जीवन उनके वचन को सुनने और विश्वास करने से मिलता है।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440005', 'ml', 'യോഹന്നാന്‍ 5: പുത്രന്‍റെ അധികാരവും പിതാവിന്‍റെ സാക്ഷ്യവും', 'യോഹന്നാന്‍ 5 വായിക്കുക. ബേത്ത്‌ഹെസ്ദയില്‍ മുപ്പത്തെട്ടു വര്‍ഷം തളര്‍വാതരോഗിയായിരുന്ന ഒരാളെ യേശു സൗഖ്യമാക്കുന്നു, ഇത് ശബ്ബത്തിനെച്ചൊല്ലി തര്‍ക്കത്തിന് ഇടയാക്കുന്നു. അവന്‍ പ്രതികരിച്ച് ദൈവത്തോടു സമത്വം അവകാശപ്പെടുന്നു — പിതാവ് പ്രവര്‍ത്തിക്കുന്നതുപോലെ പ്രവര്‍ത്തിച്ച്, പുത്രനായി ജീവന്‍ നല്‍കുകയും ന്യായവിധി നടത്തുകയും ചെയ്യുന്നു. തന്‍റെ വ്യക്തിത്വത്തിന് അവന്‍ സാക്ഷികളെ വിളിക്കുന്നു: സ്നാപകന്‍, തന്‍റെ പ്രവൃത്തികള്‍, പിതാവ്, തന്നെക്കുറിച്ച് സാക്ഷ്യം പറയുന്ന തിരുവെഴുത്തുകള്‍. പിതാവിനെ ബഹുമാനിക്കുന്നതുപോലെ പുത്രനെയും ബഹുമാനിക്കണമെന്ന് യോഹന്നാന്‍ വായനക്കാരനെ നിര്‍ബന്ധിക്കുന്നു, എന്തെന്നാല്‍ അവന്‍റെ വചനം കേട്ടു വിശ്വസിക്കുന്നതിലൂടെ നിത്യജീവന്‍ വരുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440006', 'hi', 'यूहन्ना 6:1-21: पाँच हजार को भोजन और जल पर चलना', 'यूहन्ना 6:1-21 पढ़ें। यीशु पाँच रोटियों और दो मछलियों से पाँच हजार को भोजन कराते हैं, जो उनके प्रचुर प्रबन्ध का चिह्न और आनेवाली रोटी का पूर्वाभास है। भीड़ चमत्कार देखकर उन्हें बलपूर्वक राजा बनाना चाहती है, परन्तु वे अलग हो जाते हैं। उसी रात वे जल पर चलते हैं और "मैं हूँ; मत डरो" कहकर अपने चेलों के भय को शान्त करते हैं। यूहन्ना प्रकृति पर मसीह की सृजनात्मक सामर्थ्य और उनकी सर्वसामर्थी उपस्थिति को प्रदर्शित करता है, जो जीवन की रोटी पर महान प्रवचन की तैयारी करता है।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440006', 'ml', 'യോഹന്നാന്‍ 6:1-21: അയ്യായിരം പേരെ പോഷിപ്പിക്കലും വെള്ളത്തിന്മേല്‍ നടക്കലും', 'യോഹന്നാന്‍ 6:1-21 വായിക്കുക. അഞ്ച് അപ്പവും രണ്ടു മീനും കൊണ്ട് യേശു അയ്യായിരം പേരെ പോഷിപ്പിക്കുന്നു, ഇത് അവന്‍റെ സമൃദ്ധമായ ദാനത്തിന്‍റെ അടയാളവും വരുവാനുള്ള അപ്പത്തിന്‍റെ മുന്‍നിഴലുമാണ്. അത്ഭുതം കണ്ട ജനക്കൂട്ടം അവനെ ബലത്താല്‍ രാജാവാക്കാന്‍ ശ്രമിക്കുന്നു, എന്നാല്‍ അവന്‍ വാങ്ങിപ്പോകുന്നു. ആ രാത്രി അവന്‍ കടലിന്മേല്‍ നടന്ന് "ഞാന്‍ ആകുന്നു; ഭയപ്പെടേണ്ട" എന്നു പറഞ്ഞ് ശിഷ്യന്മാരുടെ ഭയം ശമിപ്പിക്കുന്നു. പ്രകൃതിയുടെമേലുള്ള ക്രിസ്തുവിന്‍റെ സൃഷ്ടിശക്തിയും അവന്‍റെ പരമാധികാര സാന്നിധ്യവും യോഹന്നാന്‍ പ്രദര്‍ശിപ്പിക്കുന്നു, ജീവന്‍റെ അപ്പത്തെക്കുറിച്ചുള്ള മഹത്തായ പ്രഭാഷണത്തിന് ഒരുക്കമൊരുക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440007', 'hi', 'यूहन्ना 6:22-71: मैं जीवन की रोटी हूँ', 'यूहन्ना 6:22-71 पढ़ें। यीशु स्वयं को जीवन की रोटी घोषित करते हैं: जो उनके पास आता है वह कभी भूखा न होगा, और जो विश्वास करता है वह कभी प्यासा न होगा। वे सिखाते हैं कि जब तक पिता किसी को न खींचे कोई नहीं आता, और वे अपने लोगों को अन्तिम दिन में जिला उठाएँगे। उनके मांस को खाने और लहू को पीने के विषय में उनका कठोर वचन — उन पर विश्वास के द्वारा भोजन करने का आह्वान — भीड़ को छाँट देता है। बहुत से लौट जाते हैं, परन्तु पतरस अंगीकार करता है, "अनन्त जीवन की बातें तो आपके ही पास हैं।"', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440007', 'ml', 'യോഹന്നാന്‍ 6:22-71: ഞാന്‍ ജീവന്‍റെ അപ്പം ആകുന്നു', 'യോഹന്നാന്‍ 6:22-71 വായിക്കുക. യേശു തന്നെത്തന്നെ ജീവന്‍റെ അപ്പമായി പ്രഖ്യാപിക്കുന്നു: തന്‍റെ അടുക്കല്‍ വരുന്നവന് ഒരുനാളും വിശക്കയില്ല, വിശ്വസിക്കുന്നവന് ഒരുനാളും ദാഹിക്കയില്ല. പിതാവ് ആകര്‍ഷിച്ചല്ലാതെ ആരും വരികയില്ലെന്നും താന്‍ തന്‍റേവരെ ഒടുക്കത്തെ നാളില്‍ ഉയിര്‍പ്പിക്കുമെന്നും അവന്‍ പഠിപ്പിക്കുന്നു. തന്‍റെ മാംസം തിന്നുകയും രക്തം കുടിക്കുകയും ചെയ്യുന്നതിനെക്കുറിച്ചുള്ള അവന്‍റെ കഠിനവചനം — വിശ്വാസത്താല്‍ അവനെ ഭക്ഷിക്കുവാനുള്ള ആഹ്വാനം — ജനക്കൂട്ടത്തെ വേര്‍തിരിക്കുന്നു. അനേകര്‍ പിന്മാറുന്നു, എന്നാല്‍ പത്രൊസ് ഏറ്റുപറയുന്നു, "നിത്യജീവന്‍റെ വചനങ്ങള്‍ നിന്‍റെ പക്കല്‍ ഉണ്ട്."', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440008', 'hi', 'यूहन्ना 7: पर्व में जीवन के जल की नदियाँ', 'यूहन्ना 7 पढ़ें। झोपड़ियों के पर्व में, यीशु अपनी पहचान को लेकर मतभेद के बीच खुलकर शिक्षा देते हैं। वे अपनी शिक्षा के स्रोत के रूप में पिता की ओर संकेत करते हैं और प्यासों को आकर पीने का निमन्त्रण देते हैं, जीवन के जल की नदियों का वादा करते हुए — वह आत्मा जो उनकी महिमा के बाद दिया जाएगा। उन्हें पकड़ने भेजे गए सिपाही चकित होकर लौटते हैं: "किसी मनुष्य ने कभी ऐसी बातें नहीं कीं।" यूहन्ना बढ़ते तनाव, आश्चर्य और अविश्वास को दर्शाता है, जैसे भीड़ इस प्रश्न से जूझती है कि क्या यीशु ही मसीह हैं।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440008', 'ml', 'യോഹന്നാന്‍ 7: പെരുന്നാളില്‍ ജീവജലനദികള്‍', 'യോഹന്നാന്‍ 7 വായിക്കുക. കൂടാരപ്പെരുന്നാളില്‍, തന്‍റെ വ്യക്തിത്വത്തെച്ചൊല്ലിയുള്ള ഭിന്നതയ്ക്കിടയില്‍ യേശു പരസ്യമായി ഉപദേശിക്കുന്നു. തന്‍റെ ഉപദേശത്തിന്‍റെ ഉറവിടമായി പിതാവിലേക്കു ചൂണ്ടിക്കാണിക്കുകയും ദാഹിക്കുന്നവരെ വന്നു കുടിക്കാന്‍ ക്ഷണിക്കുകയും ജീവജലനദികള്‍ വാഗ്ദാനം ചെയ്യുകയും ചെയ്യുന്നു — അവന്‍റെ മഹത്വീകരണത്തിനുശേഷം നല്‍കപ്പെടുവാനുള്ള ആത്മാവ്. അവനെ പിടിക്കാന്‍ അയച്ച ചേവകര്‍ വിസ്മയിച്ച് മടങ്ങുന്നു: "ഈ മനുഷ്യന്‍ സംസാരിച്ചതുപോലെ ആരും ഒരുനാളും സംസാരിച്ചിട്ടില്ല." യേശു ക്രിസ്തുവാണോ എന്ന ചോദ്യവുമായി ജനക്കൂട്ടം മല്ലിടുമ്പോള്‍ ഉയരുന്ന പിരിമുറുക്കവും ആശ്ചര്യവും അവിശ്വാസവും യോഹന്നാന്‍ പകര്‍ത്തുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440009', 'hi', 'यूहन्ना 8: जगत की ज्योति और महान "मैं हूँ"', 'यूहन्ना 8 पढ़ें। यीशु घोषणा करते हैं, "जगत की ज्योति मैं हूँ," और जो उनके पीछे हो लेते हैं उन सबको जीवन की ज्योति देते हैं। वे अविश्वास का सामना करते हैं, पाप की दासता को उजागर करते हैं और यह वादा करते हैं कि सच्चाई उनके चेलों को स्वतन्त्र कर देगी। यह विवाद उनके चौंका देनेवाले दावे पर पहुँचता है, "इससे पहले कि इब्राहीम उत्पन्न हुआ, मैं हूँ," जो ईश्वरीय नाम का आह्वान करता है और उनकी अनन्त ईश्वरत्व की पुष्टि करता है। विरोधी भीड़ पत्थर उठाती है, परन्तु यूहन्ना पाठक को इस प्रश्न के समक्ष छोड़ देता है कि यीशु वास्तव में कौन हैं।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440009', 'ml', 'യോഹന്നാന്‍ 8: ലോകത്തിന്‍റെ വെളിച്ചവും മഹത്തായ "ഞാന്‍ ആകുന്നു"', 'യോഹന്നാന്‍ 8 വായിക്കുക. "ഞാന്‍ ലോകത്തിന്‍റെ വെളിച്ചം ആകുന്നു" എന്ന് യേശു പ്രഖ്യാപിച്ച്, തന്നെ അനുഗമിക്കുന്ന എല്ലാവര്‍ക്കും ജീവന്‍റെ വെളിച്ചം നല്‍കുന്നു. അവന്‍ അവിശ്വാസത്തെ നേരിടുന്നു, പാപത്തിന്‍റെ അടിമത്തം വെളിപ്പെടുത്തുന്നു, സത്യം തന്‍റെ ശിഷ്യന്മാരെ സ്വതന്ത്രരാക്കുമെന്ന് വാഗ്ദാനം ചെയ്യുന്നു. "അബ്രാഹാം ഉണ്ടാകുംമുമ്പെ ഞാന്‍ ഉണ്ട്" എന്ന അവന്‍റെ അമ്പരപ്പിക്കുന്ന അവകാശവാദത്തില്‍ ഈ തര്‍ക്കം പാരമ്യത്തിലെത്തുന്നു, ഇത് ദൈവനാമത്തെ വിളിച്ചപേക്ഷിക്കുകയും അവന്‍റെ നിത്യദൈവത്വം ഉറപ്പിക്കുകയും ചെയ്യുന്നു. ശത്രുതയുള്ള ജനക്കൂട്ടം കല്ലെടുക്കുന്നു, എന്നാല്‍ യേശു ആരാണ് എന്ന ചോദ്യത്തിന് മുമ്പില്‍ യോഹന്നാന്‍ വായനക്കാരനെ വിട്ടേക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440010', 'hi', 'यूहन्ना 9: जन्म के अन्धे को चंगा करना', 'यूहन्ना 9 पढ़ें। यीशु जन्म से अन्धे एक व्यक्ति को चंगा करते हैं, यह घोषणा करते हुए कि उसमें परमेश्वर के कार्य प्रकट हों और कि वे स्वयं जगत की ज्योति हैं। जैसे-जैसे फरीसी पूछताछ करते और अन्ततः चंगे किए गए व्यक्ति को निकाल देते हैं, उसकी आत्मिक दृष्टि बढ़ती जाती है जबकि उनकी कठोर होती जाती है। वह यीशु की प्रभु के रूप में आराधना करता है। यूहन्ना इस चिह्न को अनुग्रह के दृष्टान्त के रूप में प्रस्तुत करता है: जो अपना अन्धापन स्वीकार करते हैं उन्हें दृष्टि मिलती है, जबकि जो देखने का दावा करते हैं वे दोष और न्याय में बने रहते हैं।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440010', 'ml', 'യോഹന്നാന്‍ 9: ജന്മനാ കുരുടനായവനെ സൗഖ്യമാക്കല്‍', 'യോഹന്നാന്‍ 9 വായിക്കുക. ജന്മനാ കുരുടനായ ഒരാളെ യേശു സൗഖ്യമാക്കുന്നു, അവനില്‍ ദൈവത്തിന്‍റെ പ്രവൃത്തികള്‍ വെളിപ്പെടണമെന്നും താന്‍ ലോകത്തിന്‍റെ വെളിച്ചമാണെന്നും പ്രഖ്യാപിച്ചുകൊണ്ട്. പരീശന്മാര്‍ ചോദ്യം ചെയ്ത് ഒടുവില്‍ സൗഖ്യം പ്രാപിച്ചവനെ പുറത്താക്കുമ്പോള്‍, അവന്‍റെ ആത്മീയ കാഴ്ച വളരുകയും അവരുടേത് കഠിനമാകുകയും ചെയ്യുന്നു. അവന്‍ യേശുവിനെ കര്‍ത്താവായി ആരാധിക്കുന്നു. യോഹന്നാന്‍ ഈ അടയാളത്തെ കൃപയുടെ ഉപമയായി ചിത്രീകരിക്കുന്നു: തങ്ങളുടെ അന്ധത സമ്മതിക്കുന്നവര്‍ക്കു കാഴ്ച ലഭിക്കുന്നു, എന്നാല്‍ കാണുന്നു എന്ന് അവകാശപ്പെടുന്നവര്‍ കുറ്റത്തിലും ന്യായവിധിയിലും തുടരുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440011', 'hi', 'यूहन्ना 10: अच्छा चरवाहा अपने प्राण देता है', 'यूहन्ना 10 पढ़ें। यीशु वह अच्छा चरवाहा हैं जो भेड़ों के लिए अपने प्राण देते हैं और वह द्वार हैं जिसके द्वारा वे बचाई जाती हैं। उनकी भेड़ें उनका शब्द सुनती हैं, उनके पीछे चलती हैं, और उनके हाथ से कभी छीनी नहीं जा सकतीं — पिता और पुत्र में विश्वासी की सुरक्षा का एक निश्चित वादा। वे दावा करते हैं, "मैं और पिता एक हैं," जिससे ईश्वर-निन्दा के आरोप उठते हैं। यूहन्ना मसीह की प्रतिनिधिक, स्वैच्छिक मृत्यु और चरवाहे तथा उसकी अपनी भेड़ों के बीच अटूट बन्धन को प्रस्तुत करता है।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440011', 'ml', 'യോഹന്നാന്‍ 10: നല്ല ഇടയന്‍ തന്‍റെ ജീവനെ വെച്ചുകൊടുക്കുന്നു', 'യോഹന്നാന്‍ 10 വായിക്കുക. യേശു ആടുകള്‍ക്കുവേണ്ടി തന്‍റെ ജീവനെ വെച്ചുകൊടുക്കുന്ന നല്ല ഇടയനും അവ രക്ഷിക്കപ്പെടുന്ന വാതിലുമാണ്. അവന്‍റെ ആടുകള്‍ അവന്‍റെ ശബ്ദം കേള്‍ക്കുകയും അവനെ അനുഗമിക്കുകയും ചെയ്യുന്നു, അവന്‍റെ കയ്യില്‍നിന്ന് അവയെ ആര്‍ക്കും തട്ടിയെടുക്കാന്‍ കഴികയില്ല — പിതാവിലും പുത്രനിലുമുള്ള വിശ്വാസിയുടെ സുരക്ഷിതത്വത്തിന്‍റെ ഉറപ്പുള്ള വാഗ്ദാനം. "ഞാനും പിതാവും ഒന്നാകുന്നു" എന്ന് അവന്‍ അവകാശപ്പെടുന്നു, ഇത് ദൈവദൂഷണ ആരോപണത്തിന് ഇടയാക്കുന്നു. ക്രിസ്തുവിന്‍റെ പകരമായുള്ള സ്വമേധയാലുള്ള മരണവും ഇടയനും അവന്‍റേവരും തമ്മിലുള്ള അഭേദ്യബന്ധവും യോഹന്നാന്‍ അവതരിപ്പിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440012', 'hi', 'यूहन्ना 11: पुनरुत्थान और जीवन', 'यूहन्ना 11 पढ़ें। लाजर की कब्र पर, यीशु घोषणा करते हैं, "पुनरुत्थान और जीवन मैं हूँ; जो कोई मुझ पर विश्वास करता है, यदि वह मर भी जाए, तौभी जीएगा।" गहरी भावना से भरकर वे रोते हैं, फिर लाजर को मृत्यु से बाहर बुलाते हैं — वह पराकाष्ठा का चिह्न जो कब्र पर उनकी आनेवाली विजय की ओर संकेत करता है। बहुत से विश्वास करते हैं, फिर भी महासभा उन्हें मार डालने का निश्चय करती है, और कैफा अनजाने में भविष्यवाणी करता है कि एक मनुष्य लोगों के लिए मरेगा। जीवन देनेवाली सामर्थ्य और क्रूस का मार्ग एक साथ मिलते हैं।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440012', 'ml', 'യോഹന്നാന്‍ 11: പുനരുത്ഥാനവും ജീവനും', 'യോഹന്നാന്‍ 11 വായിക്കുക. ലാസറിന്‍റെ കല്ലറയ്ക്കരികെ, യേശു പ്രഖ്യാപിക്കുന്നു, "ഞാന്‍ പുനരുത്ഥാനവും ജീവനും ആകുന്നു; എന്നില്‍ വിശ്വസിക്കുന്നവന്‍ മരിച്ചാലും ജീവിക്കും." ആഴമായ വികാരത്താല്‍ അവന്‍ കരയുന്നു, പിന്നെ ലാസറിനെ മരണത്തില്‍നിന്നു വിളിച്ചുവരുത്തുന്നു — കല്ലറയ്ക്കുമേലുള്ള തന്‍റെ വരുവാനുള്ള വിജയത്തിലേക്കു ചൂണ്ടുന്ന പാരമ്യമായ അടയാളം. അനേകര്‍ വിശ്വസിക്കുന്നു, എന്നിട്ടും അവനെ കൊല്ലുവാന്‍ ന്യായാധിപസംഘം തീരുമാനിക്കുന്നു, ഒരു മനുഷ്യന്‍ ജനത്തിനുവേണ്ടി മരിക്കും എന്ന് കയ്യഫാവ് അറിയാതെ പ്രവചിക്കുന്നു. ജീവന്‍ നല്‍കുന്ന ശക്തിയും ക്രൂശിലേക്കുള്ള പാതയും ഒത്തുചേരുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440013', 'hi', 'यूहन्ना 12: समय आ पहुँचा है', 'यूहन्ना 12 पढ़ें। मरियम यीशु के गाड़े जाने के लिए उनका अभिषेक करती है, और वे प्रतिज्ञात राजा के रूप में होशन्ना के नारों के बीच यरूशलेम में प्रवेश करते हैं। यह घोषणा करते हुए कि उनका समय आ पहुँचा है, वे अपनी मृत्यु की तुलना उस बीज से करते हैं जिसे गिरकर मरना अवश्य है ताकि बहुत फल लाए, और ऊँचे पर उठाए जाने की भविष्यवाणी करते हैं ताकि सब मनुष्यों को अपनी ओर खींच लें। अनेक चिह्नों के बावजूद, राष्ट्र का बड़ा भाग अविश्वास में बना रहता है, भविष्यवाणी को पूरा करते हुए। यूहन्ना यीशु की सार्वजनिक सेवा का समापन ज्योति में चलने के अन्तिम आह्वान के साथ करता है।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440013', 'ml', 'യോഹന്നാന്‍ 12: നാഴിക വന്നിരിക്കുന്നു', 'യോഹന്നാന്‍ 12 വായിക്കുക. മറിയ യേശുവിനെ അവന്‍റെ അടക്കത്തിനായി അഭിഷേകം ചെയ്യുന്നു, അവന്‍ വാഗ്ദത്തരാജാവായി ഹോശന്നാ ആര്‍പ്പിനിടയില്‍ യെരൂശലേമില്‍ പ്രവേശിക്കുന്നു. തന്‍റെ നാഴിക വന്നിരിക്കുന്നു എന്നു പ്രഖ്യാപിച്ച്, ഏറെ ഫലം കായ്ക്കേണ്ടതിന് നിലത്തുവീണു മരിക്കേണ്ട ഒരു വിത്തിനോട് അവന്‍ തന്‍റെ മരണത്തെ ഉപമിക്കുകയും സകല മനുഷ്യരെയും തന്നിലേക്കു ആകര്‍ഷിക്കേണ്ടതിന് താന്‍ ഉയര്‍ത്തപ്പെടുമെന്ന് മുന്നറിയിക്കുകയും ചെയ്യുന്നു. അനേക അടയാളങ്ങള്‍ ഉണ്ടായിട്ടും, ജനതയുടെ വലിയ ഭാഗം അവിശ്വാസത്തില്‍ തുടരുന്നു, പ്രവചനം നിറവേറ്റിക്കൊണ്ട്. വെളിച്ചത്തില്‍ നടക്കാനുള്ള ഒരു അന്തിമ ആഹ്വാനത്തോടെ യോഹന്നാന്‍ യേശുവിന്‍റെ പരസ്യശുശ്രൂഷ അവസാനിപ്പിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440014', 'hi', 'यूहन्ना 13: सेवक राजा और नई आज्ञा', 'यूहन्ना 13 पढ़ें। अपनी मृत्यु की पूर्व-सन्ध्या पर, यीशु अपने चेलों के पाँव धोते हैं, अपने प्रेम की पूर्णता को प्रदर्शित करते और विनम्र, शुद्ध करनेवाली सेवा का आदर्श प्रस्तुत करते हुए। वे यहूदा द्वारा अपने पकड़वाए जाने और पतरस के इन्कार की भविष्यवाणी करते हैं। फिर वे एक नई आज्ञा देते हैं — कि वे एक दूसरे से वैसा ही प्रेम रखें जैसा उन्होंने उनसे रखा — ऐसे प्रेम को सच्चे चेलेपन का चिह्न बनाते हुए। यूहन्ना मसीह के बलिदानी प्रेम को उस प्रेम के साथ जोड़कर ऊपरी कोठरी की शिक्षा का आरम्भ करता है जो उनके लोगों को परिभाषित करे।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440014', 'ml', 'യോഹന്നാന്‍ 13: ദാസനായ രാജാവും പുതിയ കല്പനയും', 'യോഹന്നാന്‍ 13 വായിക്കുക. തന്‍റെ മരണത്തിന്‍റെ തലേന്ന്, യേശു ശിഷ്യന്മാരുടെ കാല്‍ കഴുകുന്നു, തന്‍റെ സ്നേഹത്തിന്‍റെ പൂര്‍ണത പ്രദര്‍ശിപ്പിക്കുകയും താഴ്മയുള്ളതും ശുദ്ധീകരിക്കുന്നതുമായ ശുശ്രൂഷയ്ക്കു മാതൃകയാകുകയും ചെയ്യുന്നു. യൂദാ തന്നെ ഒറ്റിക്കൊടുക്കുമെന്നും പത്രൊസ് തന്നെ തള്ളിപ്പറയുമെന്നും അവന്‍ മുന്നറിയിക്കുന്നു. പിന്നെ അവന്‍ ഒരു പുതിയ കല്പന നല്‍കുന്നു — താന്‍ അവരെ സ്നേഹിച്ചതുപോലെ അവര്‍ തമ്മില്‍ സ്നേഹിക്കണം — ഇത്തരം സ്നേഹത്തെ യഥാര്‍ഥ ശിഷ്യത്വത്തിന്‍റെ അടയാളമാക്കിക്കൊണ്ട്. ക്രിസ്തുവിന്‍റെ ത്യാഗപൂര്‍ണമായ സ്നേഹത്തെ തന്‍റെ ജനത്തെ നിര്‍വചിക്കേണ്ട സ്നേഹവുമായി കൂട്ടിയിണക്കിക്കൊണ്ട് യോഹന്നാന്‍ മാളികമുറിയിലെ ഉപദേശം ആരംഭിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440015', 'hi', 'यूहन्ना 14: मार्ग, सत्य और जीवन', 'यूहन्ना 14 पढ़ें। यीशु अपने व्याकुल चेलों को शान्ति देते हैं: वे एक स्थान तैयार करने जाते हैं और उनके लिए लौट आएँगे। वे घोषणा करते हैं, "मार्ग और सत्य और जीवन मैं हूँ; बिना मेरे द्वारा कोई पिता के पास नहीं पहुँच सकता," उद्धार में अपनी अनन्य भूमिका और पिता के साथ अपनी एकता की पुष्टि करते हुए। वे पवित्र आत्मा, एक और सहायक, का वादा करते हैं जो उनमें वास करे और उन्हें सिखाए, और अपनी शान्ति छोड़ जाते हैं। यूहन्ना दिखाता है कि मसीह को जानना स्वयं परमेश्वर को जानना है।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440015', 'ml', 'യോഹന്നാന്‍ 14: വഴിയും സത്യവും ജീവനും', 'യോഹന്നാന്‍ 14 വായിക്കുക. യേശു തന്‍റെ വ്യാകുലപ്പെട്ട ശിഷ്യന്മാരെ ആശ്വസിപ്പിക്കുന്നു: അവന്‍ ഒരു സ്ഥലം ഒരുക്കാന്‍ പോകുന്നു, അവര്‍ക്കായി മടങ്ങിവരും. "ഞാന്‍ വഴിയും സത്യവും ജീവനും ആകുന്നു; ഞാന്‍ മുഖാന്തരമല്ലാതെ ആരും പിതാവിന്‍റെ അടുക്കല്‍ എത്തുന്നില്ല" എന്ന് അവന്‍ പ്രഖ്യാപിക്കുന്നു, രക്ഷയില്‍ തന്‍റെ അനന്യപങ്കും പിതാവിനോടുള്ള തന്‍റെ ഏകത്വവും ഉറപ്പിച്ചുകൊണ്ട്. അവരില്‍ വസിക്കുകയും അവരെ പഠിപ്പിക്കുകയും ചെയ്യുവാന്‍ മറ്റൊരു സഹായകനായ പരിശുദ്ധാത്മാവിനെ അവന്‍ വാഗ്ദാനം ചെയ്യുകയും തന്‍റെ സമാധാനം നല്‍കുകയും ചെയ്യുന്നു. ക്രിസ്തുവിനെ അറിയുന്നത് ദൈവത്തെത്തന്നെ അറിയുന്നതാണെന്ന് യോഹന്നാന്‍ കാണിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440016', 'hi', 'यूहन्ना 15: सच्ची दाखलता', 'यूहन्ना 15 पढ़ें। यीशु घोषणा करते हैं, "सच्ची दाखलता मैं हूँ," और अपने चेलों को बुलाते हैं कि वे उनमें बने रहें, क्योंकि उनके बिना वे कुछ नहीं कर सकते। मसीह के साथ सच्चा संयोग स्थायी फल लाता है और सच्चे चेलेपन को प्रमाणित करता है, जबकि निष्फलता प्रकट करती है कि भीतर कोई वास्तविक जीवन नहीं। वे उन्हें एक दूसरे से प्रेम करने की आज्ञा देते हैं और चेतावनी देते हैं कि जगत उनसे बैर करेगा जैसा उसने उनसे किया। यूहन्ना बने रहनेवाले विश्वास, आज्ञाकारी प्रेम, और मसीह के होने की कीमती गवाही को एक साथ बाँधता है।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440016', 'ml', 'യോഹന്നാന്‍ 15: യഥാര്‍ഥ മുന്തിരിവള്ളി', 'യോഹന്നാന്‍ 15 വായിക്കുക. "ഞാന്‍ യഥാര്‍ഥ മുന്തിരിവള്ളി ആകുന്നു" എന്ന് യേശു പ്രഖ്യാപിച്ച്, തന്നില്‍ വസിക്കാന്‍ ശിഷ്യന്മാരെ വിളിക്കുന്നു, എന്തെന്നാല്‍ തന്നെ കൂടാതെ അവര്‍ക്ക് ഒന്നും ചെയ്‌വാന്‍ കഴികയില്ല. ക്രിസ്തുവുമായുള്ള യഥാര്‍ഥ ഐക്യം നിലനില്‍ക്കുന്ന ഫലം കായ്ക്കുകയും യഥാര്‍ഥ ശിഷ്യത്വം തെളിയിക്കുകയും ചെയ്യുന്നു, എന്നാല്‍ ഫലമില്ലായ്മ ഉള്ളില്‍ യഥാര്‍ഥ ജീവനില്ലെന്നു വെളിപ്പെടുത്തുന്നു. തമ്മില്‍ സ്നേഹിക്കാന്‍ അവന്‍ അവരോടു കല്പിക്കുകയും, തന്നെ ദ്വേഷിച്ചതുപോലെ ലോകം അവരെയും ദ്വേഷിക്കുമെന്ന് മുന്നറിയിക്കുകയും ചെയ്യുന്നു. വസിക്കുന്ന വിശ്വാസത്തെയും അനുസരണമുള്ള സ്നേഹത്തെയും ക്രിസ്തുവിന്‍റേവരായിരിക്കുന്നതിന്‍റെ വിലയേറിയ സാക്ഷ്യത്തെയും യോഹന്നാന്‍ ഒന്നിച്ചുചേര്‍ക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440017', 'hi', 'यूहन्ना 16: आत्मा का कार्य और स्थायी आनन्द', 'यूहन्ना 16 पढ़ें। यीशु अपने चेलों को उत्पीड़न के लिए तैयार करते हैं और समझाते हैं कि उनका जाना उनके लाभ के लिए है, क्योंकि वे आत्मा को भेजेंगे। आत्मा जगत को पाप, धार्मिकता और न्याय के विषय में दोषी ठहराएगा, और विश्वासियों को सब सत्य में मार्ग दिखाएगा, मसीह की महिमा करते हुए। उनका शोक ऐसे आनन्द में बदल जाएगा जिसे कोई छीन नहीं सकता। वे उन्हें पिता के प्रेम का आश्वासन देते हैं और समापन करते हैं, "मैंने जगत को जीत लिया है।" यूहन्ना स्थायी आशा को मसीह की निश्चित विजय में आधारित करता है।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440017', 'ml', 'യോഹന്നാന്‍ 16: ആത്മാവിന്‍റെ പ്രവൃത്തിയും നിലനില്‍ക്കുന്ന സന്തോഷവും', 'യോഹന്നാന്‍ 16 വായിക്കുക. യേശു തന്‍റെ ശിഷ്യന്മാരെ പീഡനത്തിന് ഒരുക്കുകയും, താന്‍ ആത്മാവിനെ അയക്കുമെന്നതിനാല്‍ തന്‍റെ വേര്‍പാട് അവരുടെ പ്രയോജനത്തിന് ആണെന്ന് വിശദീകരിക്കുകയും ചെയ്യുന്നു. ആത്മാവ് പാപത്തെയും നീതിയെയും ന്യായവിധിയെയും കുറിച്ച് ലോകത്തെ ബോധ്യപ്പെടുത്തുകയും, ക്രിസ്തുവിനെ മഹത്വപ്പെടുത്തിക്കൊണ്ട് വിശ്വാസികളെ സകല സത്യത്തിലേക്കും വഴിനടത്തുകയും ചെയ്യും. അവരുടെ ദുഃഖം ആര്‍ക്കും എടുത്തുകളയാന്‍ കഴിയാത്ത സന്തോഷമായി മാറും. പിതാവിന്‍റെ സ്നേഹത്തെക്കുറിച്ച് അവന്‍ അവര്‍ക്കു ഉറപ്പുനല്‍കുകയും "ഞാന്‍ ലോകത്തെ ജയിച്ചിരിക്കുന്നു" എന്ന് അവസാനിപ്പിക്കുകയും ചെയ്യുന്നു. നിലനില്‍ക്കുന്ന പ്രത്യാശയെ ക്രിസ്തുവിന്‍റെ ഉറപ്പുള്ള വിജയത്തില്‍ യോഹന്നാന്‍ അടിയുറപ്പിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440018', 'hi', 'यूहन्ना 17: महायाजकीय प्रार्थना', 'यूहन्ना 17 पढ़ें। यीशु पिता से प्रार्थना करते हैं, यह माँगते हुए कि वे महिमित किए जाएँ ताकि वे उसकी महिमा करें, और अनन्त जीवन को इस रूप में परिभाषित करते हुए कि वह एकमात्र सच्चे परमेश्वर को और यीशु मसीह को, जिसे उसने भेजा, जानना है। वे अपने चेलों के लिए मध्यस्थता करते हैं — कि वे रखे जाएँ, सत्य में पवित्र किए जाएँ, और वैसे ही एक हों जैसे वे और पिता एक हैं। वे उनके लिए भी प्रार्थना करते हैं जो उनके वचन के द्वारा विश्वास करेंगे, कि उनके सब अपने उनकी महिमा को निहारें। यूहन्ना हमारे महान महायाजक के रूप में पुत्र का हृदय प्रकट करता है।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440018', 'ml', 'യോഹന്നാന്‍ 17: മഹാപുരോഹിത പ്രാര്‍ഥന', 'യോഹന്നാന്‍ 17 വായിക്കുക. യേശു പിതാവിനോട് പ്രാര്‍ഥിക്കുന്നു, പിതാവിനെ മഹത്വപ്പെടുത്തേണ്ടതിന് താന്‍ മഹത്വപ്പെടണമെന്ന് അപേക്ഷിക്കുകയും, ഏകസത്യദൈവത്തെയും താന്‍ അയച്ച യേശുക്രിസ്തുവിനെയും അറിയുന്നതാണ് നിത്യജീവന്‍ എന്ന് നിര്‍വചിക്കുകയും ചെയ്യുന്നു. തന്‍റെ ശിഷ്യന്മാര്‍ക്കുവേണ്ടി അവന്‍ മധ്യസ്ഥത ചെയ്യുന്നു — അവര്‍ കാക്കപ്പെടേണ്ടതിനും സത്യത്തില്‍ വിശുദ്ധീകരിക്കപ്പെടേണ്ടതിനും താനും പിതാവും ഒന്നായിരിക്കുന്നതുപോലെ ഒന്നായിരിക്കേണ്ടതിനും. അവരുടെ വചനത്താല്‍ വിശ്വസിക്കുവാനുള്ളവര്‍ക്കുവേണ്ടിയും അവന്‍ പ്രാര്‍ഥിക്കുന്നു, തന്‍റേവര്‍ എല്ലാവരും തന്‍റെ മഹത്വം ദര്‍ശിക്കേണ്ടതിന്. നമ്മുടെ മഹാപുരോഹിതനായ പുത്രന്‍റെ ഹൃദയം യോഹന്നാന്‍ വെളിപ്പെടുത്തുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440019', 'hi', 'यूहन्ना 18: पकड़वाया गया, बन्दी बनाया गया, और मुकद्दमे में', 'यूहन्ना 18 पढ़ें। यहूदा बारी में यीशु को पकड़वाता है, जहाँ यीशु "मैं ही हूँ" कहकर अपने लोगों की रक्षा के लिए स्वेच्छा से समर्पण कर देते हैं। पतरस भविष्यवाणी के अनुसार तीन बार उनका इन्कार करता है। हन्ना, कैफा और पिलातुस के सामने, यीशु सत्य की और एक ऐसे राज्य की गवाही देते हैं जो इस जगत का नहीं है। पिलातुस कोई दोष नहीं पाता फिर भी भीड़ के आगे झुक जाता है। यूहन्ना पुत्र को सर्वसामर्थ्य के साथ क्रूस की ओर बढ़ते हुए चित्रित करता है — कभी शिकार नहीं, परन्तु पिता के दिए हुए कटोरे को पीने हेतु आज्ञाकारिता में अपना प्राण देते हुए।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440019', 'ml', 'യോഹന്നാന്‍ 18: ഒറ്റിക്കൊടുക്കപ്പെട്ടു, ബന്ധിക്കപ്പെട്ടു, വിസ്താരത്തിലായി', 'യോഹന്നാന്‍ 18 വായിക്കുക. യൂദാ തോട്ടത്തില്‍ വെച്ച് യേശുവിനെ ഒറ്റിക്കൊടുക്കുന്നു, അവിടെ യേശു "ഞാന്‍ ആകുന്നു" എന്നു പറഞ്ഞ് തന്‍റേവരെ സംരക്ഷിക്കാന്‍ സ്വമേധയാ കീഴടങ്ങുന്നു. പത്രൊസ് മുന്നറിയിച്ചതുപോലെ മൂന്നു പ്രാവശ്യം അവനെ തള്ളിപ്പറയുന്നു. ഹന്നാവ്, കയ്യഫാവ്, പീലാത്തൊസ് എന്നിവരുടെ മുമ്പാകെ, യേശു സത്യത്തിനും ഈ ലോകത്തിന്‍റേതല്ലാത്ത ഒരു രാജ്യത്തിനും സാക്ഷ്യം പറയുന്നു. പീലാത്തൊസ് കുറ്റമൊന്നും കാണുന്നില്ലെങ്കിലും ജനക്കൂട്ടത്തിന് വഴങ്ങുന്നു. പുത്രന്‍ പരമാധികാരത്തോടെ ക്രൂശിലേക്കു നീങ്ങുന്നതായി യോഹന്നാന്‍ ചിത്രീകരിക്കുന്നു — ഒരിക്കലും ഇരയല്ല, പിന്നെയോ പിതാവ് നല്‍കിയ പാനപാത്രം കുടിക്കാന്‍ അനുസരണത്തില്‍ തന്‍റെ ജീവനെ വെച്ചുകൊടുക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440020', 'hi', 'यूहन्ना 19: पूरा हुआ', 'यूहन्ना 19 पढ़ें। कोड़े खाकर, ठट्ठों में उड़ाए जाकर और दोषी ठहराए जाकर, यीशु दो और लोगों के बीच क्रूस पर चढ़ाए जाते हैं, यहूदियों का राजा। क्रूस से वे अपनी माता को यूहन्ना को सौंपते हैं, फिर पुकारते हैं, "पूरा हुआ" — पाप का दण्ड उठाने का सम्पूर्ण, प्रायश्चित्तकारी कार्य सम्पन्न — और अपना प्राण त्याग देते हैं। सिपाही उनकी पसली बेधते हैं, और वे एक नई कब्र में गाड़े जाते हैं, हर बात में पवित्रशास्त्र को पूरा करते हुए। यूहन्ना क्रूस को मसीह के सोच-समझकर किए गए, प्रतिनिधिक बलिदान के रूप में प्रस्तुत करता है, जो पापियों के लिए ईश्वरीय न्याय को सन्तुष्ट करता है।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440020', 'ml', 'യോഹന്നാന്‍ 19: നിവൃത്തിയായി', 'യോഹന്നാന്‍ 19 വായിക്കുക. ചമ്മട്ടികൊണ്ടടിക്കപ്പെട്ട്, പരിഹസിക്കപ്പെട്ട്, ശിക്ഷിക്കപ്പെട്ട യേശു, യഹൂദന്മാരുടെ രാജാവായി, മറ്റു രണ്ടുപേരുടെ നടുവില്‍ ക്രൂശിക്കപ്പെടുന്നു. ക്രൂശില്‍നിന്ന് അവന്‍ തന്‍റെ അമ്മയെ യോഹന്നാനെ ഭരമേല്‍പിക്കുന്നു, പിന്നെ "നിവൃത്തിയായി" എന്നു നിലവിളിക്കുന്നു — പാപത്തിന്‍റെ ശിക്ഷ വഹിക്കുന്ന പൂര്‍ണവും പ്രായശ്ചിത്തപരവുമായ വേല പൂര്‍ത്തിയായി — തന്‍റെ ആത്മാവിനെ ഏല്‍പിക്കുന്നു. പടയാളികള്‍ അവന്‍റെ വിലാപ്പുറം കുത്തുന്നു, അവന്‍ ഒരു പുതിയ കല്ലറയില്‍ അടക്കപ്പെടുന്നു, എല്ലാറ്റിലും തിരുവെഴുത്ത് നിറവേറ്റിക്കൊണ്ട്. ക്രൂശിനെ ക്രിസ്തുവിന്‍റെ മനഃപൂര്‍വവും പകരമായുള്ളതുമായ യാഗമായി യോഹന്നാന്‍ അവതരിപ്പിക്കുന്നു, ഇത് പാപികള്‍ക്കുവേണ്ടി ദൈവനീതിയെ തൃപ്തിപ്പെടുത്തുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440021', 'hi', 'यूहन्ना 20: प्रभु जी उठा है', 'यूहन्ना 20 पढ़ें। पहले दिन कब्र खाली है; जी उठे यीशु पहले मरियम मगदलीनी को, फिर अपने चेलों को दर्शन देते हैं, अपने बेधे हुए हाथ और पसली दिखाते हुए। वे उन पर फूँकते हैं, उन्हें भेजते हैं, और सन्देह करनेवाले थोमा से मिलते हैं, जो अंगीकार करता है, "हे मेरे प्रभु, हे मेरे परमेश्वर!" यीशु उन्हें धन्य कहते हैं जो बिना देखे विश्वास करते हैं। यूहन्ना अपना उद्देश्य स्पष्ट रूप से बताता है: ये चिह्न इसलिए लिखे गए हैं कि तुम विश्वास करो कि यीशु ही मसीह हैं, परमेश्वर के पुत्र, और उनके नाम में जीवन पाओ।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440021', 'ml', 'യോഹന്നാന്‍ 20: കര്‍ത്താവ് ഉയിര്‍ത്തെഴുന്നേറ്റിരിക്കുന്നു', 'യോഹന്നാന്‍ 20 വായിക്കുക. ആഴ്ചവട്ടത്തിന്‍റെ ഒന്നാം നാളില്‍ കല്ലറ ശൂന്യമാണ്; ഉയിര്‍ത്തെഴുന്നേറ്റ യേശു ആദ്യം മഗ്ദലക്കാരി മറിയയ്ക്കും പിന്നെ ശിഷ്യന്മാര്‍ക്കും പ്രത്യക്ഷനായി, തന്‍റെ കുത്തേറ്റ കൈകളും വിലാപ്പുറവും കാണിക്കുന്നു. അവന്‍ അവരുടെമേല്‍ ഊതുകയും അവരെ അയക്കുകയും, "എന്‍റെ കര്‍ത്താവേ, എന്‍റെ ദൈവമേ!" എന്ന് ഏറ്റുപറയുന്ന സംശയാലുവായ തോമാസിനെ കണ്ടുമുട്ടുകയും ചെയ്യുന്നു. കാണാതെ വിശ്വസിക്കുന്നവരെ യേശു ഭാഗ്യവാന്മാര്‍ എന്നു വിളിക്കുന്നു. യോഹന്നാന്‍ തന്‍റെ ഉദ്ദേശ്യം വ്യക്തമായി പ്രസ്താവിക്കുന്നു: യേശു ദൈവപുത്രനായ ക്രിസ്തു ആകുന്നു എന്നു നിങ്ങള്‍ വിശ്വസിക്കേണ്ടതിനും അവന്‍റെ നാമത്തില്‍ ജീവന്‍ പ്രാപിക്കേണ്ടതിനും ഈ അടയാളങ്ങള്‍ എഴുതിയിരിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം'),
  ('d0400000-e29b-41d4-a716-446655440022', 'hi', 'यूहन्ना 21: क्या तू मुझ से प्रेम रखता है? — पतरस की बहाली', 'यूहन्ना 21 पढ़ें। जी उठे यीशु गलील की झील के किनारे दर्शन देते हैं, अपने थके हुए चेलों के लिए मछलियों का चमत्कारी जाल और कलेवा प्रदान करते हुए। कोमलता से और तीन बार, पतरस के तीन बार के इन्कार को प्रतिबिम्बित करते हुए, वे पतरस को बहाल करते हैं, उसे बुलाते हुए कि वह उनसे प्रेम रखे और उनकी भेड़ों को चराए। वे पतरस की मृत्यु के प्रकार की भविष्यवाणी करते हैं और "मेरे पीछे हो ले" का आह्वान नया करते हैं। यूहन्ना अपनी गवाही की विश्वसनीयता की साक्षी देकर समापन करता है, यह पुष्टि करते हुए कि यीशु ने जो किया वह सब जगत में भी समा न सकता।', 'मसीह का जीवन'),
  ('d0400000-e29b-41d4-a716-446655440022', 'ml', 'യോഹന്നാന്‍ 21: നീ എന്നെ സ്നേഹിക്കുന്നുവോ? — പത്രൊസിന്‍റെ പുനഃസ്ഥാപനം', 'യോഹന്നാന്‍ 21 വായിക്കുക. ഉയിര്‍ത്തെഴുന്നേറ്റ യേശു ഗലീലക്കടലിന്‍റെ തീരത്ത് പ്രത്യക്ഷനായി, ക്ഷീണിച്ച തന്‍റെ ശിഷ്യന്മാര്‍ക്ക് അത്ഭുതകരമായ മീന്‍പിടുത്തവും പ്രാതലും ഒരുക്കുന്നു. പത്രൊസിന്‍റെ മൂന്നു പ്രാവശ്യത്തെ തള്ളിപ്പറയലിനെ പ്രതിഫലിപ്പിച്ച്, ആര്‍ദ്രതയോടെയും മൂന്നു പ്രാവശ്യവും, അവന്‍ പത്രൊസിനെ പുനഃസ്ഥാപിക്കുന്നു, തന്നെ സ്നേഹിക്കാനും തന്‍റെ ആടുകളെ മേയ്ക്കാനും അവനെ വിളിക്കുന്നു. പത്രൊസിന്‍റെ മരണത്തിന്‍റെ വിധം മുന്നറിയിക്കുകയും "എന്നെ അനുഗമിക്ക" എന്ന വിളി പുതുക്കുകയും ചെയ്യുന്നു. തന്‍റെ സാക്ഷ്യത്തിന്‍റെ വിശ്വാസ്യതയ്ക്കു സാക്ഷ്യം പറഞ്ഞ്, യേശു ചെയ്തതെല്ലാം ലോകത്തിന് തന്നെ ഉള്‍ക്കൊള്ളാന്‍ കഴികയില്ലെന്ന് ഉറപ്പിച്ചുകൊണ്ട് യോഹന്നാന്‍ അവസാനിപ്പിക്കുന്നു.', 'ക്രിസ്തുവിന്റെ ജീവിതം')
